# ════════════════════════════════════════════════════════════
# OPENAI CLIENT
# ════════════════════════════════════════════════════════════
def _get_client():
    try:
        from openai import OpenAI
        api_key = os.environ.get("OPENAI_API_KEY", "")
        if api_key:
            return OpenAI(api_key=api_key)
        env_path = os.path.join(os.path.dirname(os.path.dirname(__file__)), ".env")
        if os.path.exists(env_path):
            with open(env_path, encoding="utf-8") as f:
                for line in f:
                    if line.strip().startswith("OPENAI_API_KEY="):
                        api_key = line.strip().split("=", 1)[1].strip()
                        if api_key:
                            return OpenAI(api_key=api_key)
    except Exception as e:
        _logger.error(f"OpenAI client: {e}")
    return None

# ════════════════════════════════════════════════════════════
# STRUCTURED AI LESSON (TUM DERSLER)
# ════════════════════════════════════════════════════════════
def ai_explain_structured(konu: str, ders: str, seviye: str,
                          difficulty: str = "normal", ek_talimat: str = "",
                          socratic: bool = False, student_interests: str = "") -> dict | None:
    client = _get_client()
    if not client:
        return None

    # ═══ ADAPTIF ZORLUK ═══
    # Auto-adjust difficulty based on last quiz performance
    if difficulty == "auto":
        prog = load_progress()
        gd = prog.get(ders, {})
        topics = gd.get("topics", {})
        if topics:
            last_scores = sorted(topics.values(), key=lambda x: x.get("date", ""), reverse=True)[:3]
            avg = sum(t.get("quiz_score", 50) for t in last_scores) / len(last_scores)
            if avg >= 85:
                difficulty = "hard"
            elif avg < 50:
                difficulty = "easy"
            else:
                difficulty = "normal"
        else:
            difficulty = "normal"

    diff_inst = {
        "easy": "Basit ve anlasilir anlat. Kisa cumleler. Somut ornekler. EN AZ 14-18 bolum olustur. 4 kelime. TON: Sicak, samimi, tesvik edici. 'Cok guzel!', 'Harika!', 'Gordugunuz gibi cok net!' gibi ifadeler kullan. Ogrenciye guven veren bir anlatim. DERSE ve KONUYA OZGU gercekci ornekler ver — gunluk hayattan ornek vereceksen KONUYLA DOGRUDAN ILGILI olsun. Her text section EN AZ 4-5 cumle olsun. Hikaye ve ornekleri DETAYLI anlat.",
        "normal": "Dengeli zorluk. Acik anlatim. EN AZ 18-24 bolum olustur. 6 kelime. TON: Samimi ve sicak ama ciddi. DERSE ve KONUYA OZGU gercekci ornekler kullan. Merak uyandirici ama abartisiz. 'Peki sence?', 'Ilginc degil mi?' gibi dogal sorular. Her text section EN AZ 5-6 cumle olsun. Konuyu DERINLEMESINE ve KAPSAMLI anlat. Acele etme, her alt konuyu ayri ayri isle.",
        "hard": "Detayli ve akademik. Derinlemesine. EN AZ 22-28 bolum olustur. 8+ kelime. TON: Akademik ama canli. Universite hocasi gibi derinlemesine analiz. Tarihsel baglamlar, bilimsel kanitlar, ileri duzey baglantilar. 'Bu konuyu biraz daha derinlestirelim...', 'Altta yatan mekanizma su...' gibi ifadeler. Elestirel dusunmeye tesvik et. Her text section EN AZ 6-8 cumle olsun. Konuyu cok KAPSAMLI ve DETAYLI isle. Birden fazla ornek ve analoji kullan.",
    }

    # ═══ SOKRATİK MOD ═══
    socratic_block = ""
    if socratic:
        socratic_block = """
═══ SOKRATİK OGRETIM MODU (AKTİF) ═══
KESINLIKLE CEVABI DOGRUDAN VERME. Ogrenciyi dusundurerek cevaba ulastir.
YONTEM:
1. Konuyu bir SORU ile ac: "Peki sence X ne anlama gelir?"
2. Her bilgiyi SORU-CEVAP formatinda sun: "Eger A olursa, B ne olur?"
3. Challenge section'larda cevabi gizle, ipucu ver, dusundur.
4. text section'larda bile sorular sor: "Buraya kadar ne anladik?"
5. Formula verirken once "Bu formulu nasil bulurduk?" diye sor.
6. Hatalari gostermeden once "Sence burada ne yanlis?" diye sor.
7. Recap'te "Soyle ozetleyelim... peki sen nasil ozetlerdin?" yaz.
ASLA monoton bilgi aktarma YAPMA. Her paragrafta en az 1 soru olsun.
"""

