# ═══ GÖRSEL-KONU UYUMLULUK DOĞRULAMASI ═══
# Genel/soyut görsel tipleri — bunlar sadece konu gerçekten grafik/istatistik gerektiriyorsa uygundur
_GENERIC_VISUAL_TYPES = {
    "bar_chart", "pie_chart", "line_chart", "area_chart", "scatter_plot",
    "radar_chart", "donut_chart", "bubble_chart", "gauge_chart", "histogram",
    "box_plot", "stacked_bar", "step_chart", "funnel_chart", "waterfall_chart",
    "polar_chart", "treemap", "sankey_diagram", "heatmap",
    "geometric_shape", "mind_map", "timeline", "flowchart", "comparison",
    "hierarchy", "cycle_diagram", "venn_diagram", "cause_effect", "diagram",
}
# Bu genel görsellerin uygun olduğu anahtar kelimeler
_STATS_KEYWORDS = {
    "istatistik", "grafik", "veri", "tablo", "oran", "yüzde", "dağılım",
    "karşılaştırma", "analiz", "sayısal", "frekans", "nüfus", "bütçe",
    "anket", "araştırma", "ortalama", "medyan", "standart sapma",
}


def _validate_visual_relevance(sections: list, konu: str, ders: str) -> list:
    """AI'nın seçtiği görsellerin konuyla uyumluluğunu kontrol eder.
    Alakasız genel görselleri çıkarır."""
    # Türkçe İ/I dönüşüm sorunu — normalize et
    _tr_lower_map = str.maketrans("İIÇŞĞÜÖ", "iicşğüö")
    konu_lower = konu.lower().translate(_tr_lower_map).replace("i̇", "i")
    ders_lower = ders.lower().translate(_tr_lower_map).replace("i̇", "i")

    # Ders bazlı anahtar kelime -> uygun görsel tipleri (merkezi fonksiyondan al)
    _DERS_VISUAL_KEYWORDS = _get_ders_visual_keywords()

    # ═══ KAZANIM BAZLI ÖN FİLTRE: Sadece konuyla eşleşen görselleri kabul et ═══
    import re as _re_val
    _sinif_match_val = _re_val.search(r'(\d)\.\s*[Ss][ıi]n[ıi]f', konu)
    _sinif_no_val = int(_sinif_match_val.group(1)) if _sinif_match_val else 0
    _suggested = set(_suggest_visuals_for_kazanim(konu, ders, _sinif_no_val))

    validated = []
    for sec in sections:
        if sec.get("type") != "visual":
            validated.append(sec)
            continue

        vtype = sec.get("visual_type", "").strip().lower()
        if not vtype:
            continue  # Boş visual_type — atla

        # ═══ AŞAMA 1: Kazanım bazlı öneri setinde mi? ═══
        # _suggest_visuals_for_kazanim tarafından önerildiyse direkt kabul et
        if _suggested and vtype in _suggested:
            validated.append(sec)
            continue

        # ═══ AŞAMA 2: Genel/soyut görsel mü kontrol et ═══
        if vtype in _GENERIC_VISUAL_TYPES:
            _GENERIC_MATCH = {
                "bar_chart": _STATS_KEYWORDS, "pie_chart": _STATS_KEYWORDS,
                "line_chart": _STATS_KEYWORDS, "area_chart": _STATS_KEYWORDS,
                "scatter_plot": _STATS_KEYWORDS, "histogram": _STATS_KEYWORDS,
                "box_plot": _STATS_KEYWORDS, "stacked_bar": _STATS_KEYWORDS,
                "step_chart": _STATS_KEYWORDS, "radar_chart": _STATS_KEYWORDS,
                "donut_chart": _STATS_KEYWORDS, "bubble_chart": _STATS_KEYWORDS,
                "gauge_chart": _STATS_KEYWORDS, "funnel_chart": _STATS_KEYWORDS,
                "waterfall_chart": _STATS_KEYWORDS, "polar_chart": _STATS_KEYWORDS,
                "treemap": _STATS_KEYWORDS, "sankey_diagram": _STATS_KEYWORDS,
                "heatmap": _STATS_KEYWORDS,
                "geometric_shape": {"geometri", "şekil", "çokgen", "açı", "üçgen", "dörtgen", "daire", "kare", "dikdörtgen", "çember", "simetri"},
                "mind_map": {"kavram", "harita", "ilişki", "bağlantı", "sınıflandırma", "özetleme", "planlama"},
                "timeline": {"tarih", "kronoloji", "dönem", "süreç", "gelişim", "zaman çizelgesi", "sıralama", "evrim"},
                "flowchart": {"süreç", "aşama", "adım", "akış", "algoritma", "yöntem", "prosedür"},
                "comparison": {"karşılaştırma", "karşılaştır", "fark", "benzerlik", "ayrım"},
                "hierarchy": {"sınıflandırma", "hiyerarşi", "sıralama", "düzey", "kategori", "taksonomi"},
                "cycle_diagram": {"döngü", "çevrim", "tekrar", "su döngüsü", "karbon döngüsü"},
                "venn_diagram": {"küme", "ortak", "kesişim", "birleşim", "fark"},
                "cause_effect": {"neden", "sonuç", "sebep", "etki"},
                "diagram": {"diyagram", "şema", "yapı", "sistem"},
            }
            allowed_kws = _GENERIC_MATCH.get(vtype, _STATS_KEYWORDS)
            if any(kw in konu_lower for kw in allowed_kws):
                validated.append(sec)
            else:
                _logger.info(f"Görsel filtrelendi (genel görsel, konu uyumsuz): {vtype} — konu: {konu[:50]}")
            continue

        # ═══ AŞAMA 3: Ders prefix kontrolü ═══
        ders_prefix_map = {
            "matematik": "m_", "türkçe": "t_", "fen": "f_",
            "hayat": "h_", "din": "d_", "ingilizce": "i_",
            "sosyal": "s_",
        }
        has_grade_prefix = any(vtype.startswith(f"s{i}") for i in range(1, 13))
        if has_grade_prefix:
            # Ders prefix uyumu kontrol et
            ders_suffix = None
            for dk, suffix in ders_prefix_map.items():
                if dk in ders_lower:
                    ders_suffix = suffix
                    break
            if ders_suffix and ders_suffix not in vtype[2:4]:
                _logger.info(f"Görsel filtrelendi (ders prefix uyumsuz): {vtype} — ders: {ders}")
                continue

        # ═══ AŞAMA 4: Konu-görsel keyword eşleştirmesi ═══
        ders_keywords = None
        for dk, kw_map in _DERS_VISUAL_KEYWORDS.items():
            if dk in ders_lower:
                ders_keywords = kw_map
                break

        if ders_keywords:
            konu_match = False
            for konu_kw, visual_kws in ders_keywords.items():
                if konu_kw in konu_lower:
                    if any(vkw in vtype for vkw in visual_kws):
                        konu_match = True
                        break
            if konu_match:
                validated.append(sec)
            else:
                # Son şans: görsel tipi adı konu kelimeleriyle örtüşüyor mu?
                vtype_words = set(vtype.replace("_", " ").split())
                konu_words = set(konu_lower.replace(",", "").replace(".", "").split())
                if vtype_words & konu_words:
                    validated.append(sec)
                else:
                    _logger.info(f"Görsel filtrelendi (kazanım uyumsuz): {vtype} — konu: {konu[:50]}")
        else:
            # Ders eşleşmesi bulunamadı — kabul et
            validated.append(sec)

    return validated


def _build_tts_from_sections(sections: list, konu: str) -> str:
    """Section içeriklerinden TTS metni üretir (AI yetersiz ürettiğinde fallback)."""
    parts = [f"Merhaba çocuklar! Bugün çok güzel bir konu işleyeceğiz. Konumuz: {konu}."]

    for sec in sections:
        stype = sec.get("type", "")
        if stype == "header":
            title = sec.get("title", "")
            if title:
                parts.append(f"Dersimizin başlığı: {title}.")
        elif stype == "text":
            content = sec.get("content", "")
            if content:
                parts.append(content)
        elif stype == "visual":
            desc = sec.get("visual_description", "")
            title = sec.get("visual_title", "")
            if desc:
                parts.append(f"Şimdi ekrana bakın. Burada {title or 'bir görsel'} görüyorsunuz. {desc}")
            elif title:
                parts.append(f"Şimdi ekrana bakın, burada {title} ile ilgili bir görsel var.")
        elif stype == "story" or stype == "analogy":
            title = sec.get("title", "")
            content = sec.get("content", "")
            if content:
                parts.append(f"Şimdi size bir hikaye anlatacağım. {title + '. ' if title else ''}{content}")
        elif stype == "example":
            content = sec.get("content", "")
            if content:
                parts.append(f"Bir örneğe bakalım. {content}")
        elif stype == "curiosity":
            content = sec.get("content", "")
            if content:
                parts.append(f"Biliyor musunuz? {content}")
        elif stype == "challenge":
            content = sec.get("content", sec.get("question", ""))
            if content:
                parts.append(f"Şimdi size bir meydan okuma! {content}")
        elif stype == "recap":
            points = sec.get("points", [])
            if points:
                parts.append("Buraya kadar neler öğrendik? Hadi gözden geçirelim.")
                for i, pt in enumerate(points, 1):
                    parts.append(f"{i}. {pt}")
                parts.append("Harika! Tüm bunları öğrendiniz.")
        elif stype == "tip":
            content = sec.get("content", "")
            if content:
                parts.append(f"Size bir ipucu vereyim. {content}")
        elif stype == "mistake":
            content = sec.get("content", "")
            if content:
                parts.append(f"Dikkat! Sık yapılan bir hata var. {content}")
        elif stype == "dialogue":
            content = sec.get("content", "")
            if content:
                parts.append(content)
        elif stype == "practice":
            content = sec.get("content", "")
            if content:
                parts.append(f"Şimdi pratik zamanı! {content}")
        elif stype == "mnemonic":
            content = sec.get("content", "")
            if content:
                parts.append(f"Bunu kolayca hatırlamak için: {content}")
        elif stype == "inline_quiz":
            q = sec.get("question", "")
            if q:
                parts.append(f"Şimdi bir soru soracağım. {q}")

    parts.append("Dersimiz burada sona eriyor. Harika bir ders oldu, tebrikler!")
    return " ".join(parts)


def _repair_truncated_json(raw: str) -> dict | None:
    """Kesik JSON'ı kurtarmaya çalış."""
    if not raw or not raw.strip():
        return None
    # Sondaki eksik kapanışları tamamla
    text = raw.strip()
    # sections dizisinin sonunu bul
    bracket_count = 0
    brace_count = 0
    for ch in text:
        if ch == '[': bracket_count += 1
        elif ch == ']': bracket_count -= 1
        elif ch == '{': brace_count += 1
        elif ch == '}': brace_count -= 1

    # Eksik kapanışları ekle
    repair = text
    if repair.rstrip().endswith(','):
        repair = repair.rstrip().rstrip(',')
    repair += ']' * max(0, bracket_count) + '}' * max(0, brace_count)

    try:
        return json.loads(repair)
    except json.JSONDecodeError:
        pass

    # Son çare: sections dizisine kadar olan kısmı al
    idx = text.find('"sections"')
    if idx == -1:
        return None
    # En son tamamlanmış section'ı bul
    last_complete = text.rfind('}')
    if last_complete > idx:
        attempt = text[:last_complete + 1]
        # Kapanışları tamamla
        bc, brc = 0, 0
        for ch in attempt:
            if ch == '[': bc += 1
            elif ch == ']': bc -= 1
            elif ch == '{': brc += 1
            elif ch == '}': brc -= 1
        attempt += ']' * max(0, bc) + '}' * max(0, brc)
        try:
            return json.loads(attempt)
        except json.JSONDecodeError:
            pass
    return None

# ════════════════════════════════════════════════════════════
# OPENAI TTS
# ════════════════════════════════════════════════════════════
def ai_generate_tts(text: str, voice: str = "onyx") -> str | None:
    client = _get_client()
    if not client:
        return None
    try:
        max_len = 4000
        if len(text) <= max_len:
            chunks = [text]
        else:
            chunks, cur = [], ""
            for sent in text.replace(". ", ".|").split("|"):
                if len(cur) + len(sent) > max_len:
                    if cur:
                        chunks.append(cur.strip())
                    cur = sent
                else:
                    cur += sent
            if cur.strip():
                chunks.append(cur.strip())
        chunks = [c for c in chunks if c.strip()]
        if not chunks:
            return None

        # Paralel TTS — her chunk'ı aynı anda gönder (max 6 thread)
        def _tts_chunk(idx_chunk):
            idx, chunk = idx_chunk
            resp = client.audio.speech.create(
                model="tts-1", voice=voice,
                input=chunk.strip(), response_format="mp3",
            )
            return idx, resp.content

        if len(chunks) == 1:
            _, audio = _tts_chunk((0, chunks[0]))
            return base64.b64encode(audio).decode()

        audio_parts = [None] * len(chunks)
        with ThreadPoolExecutor(max_workers=min(6, len(chunks))) as pool:
            futures = pool.map(_tts_chunk, enumerate(chunks))
            for idx, content in futures:
                audio_parts[idx] = content

        audio_parts = [p for p in audio_parts if p]
        if not audio_parts:
            return None
        return base64.b64encode(b"".join(audio_parts)).decode()
    except Exception as e:
        _logger.error(f"TTS: {e}")
        return None

# ════════════════════════════════════════════════════════════
# STORAGE & PROGRESS
# ════════════════════════════════════════════════════════════
def _data_dir():
    from utils.tenant import get_tenant_dir
    d = os.path.join(get_tenant_dir(), "ai_premium")
    os.makedirs(d, exist_ok=True)
    return d

def save_lesson(data: dict, ders: str, topic: str, tts_b64: str | None = None):
    rec = {
        "ders": ders, "topic": topic, "lesson": data,
        "tts_b64": tts_b64, "timestamp": time.time(),
        "date": datetime.now().strftime("%Y-%m-%d %H:%M"),
    }
    fname = f"lesson_{int(time.time())}.json"
    with open(os.path.join(_data_dir(), fname), "w", encoding="utf-8") as f:
        json.dump(rec, f, ensure_ascii=False)

def load_saved_lessons(ders: str = "") -> list:
    d = _data_dir()
    lessons = []
    for fname in sorted(os.listdir(d), reverse=True):
        if fname.startswith("lesson_") and fname.endswith(".json"):
            try:
                with open(os.path.join(d, fname), "r", encoding="utf-8") as f:
                    rec = json.load(f)
                if not ders or rec.get("ders", "") == ders:
                    lessons.append(rec)
            except Exception:
                pass
    return lessons[:20]

def _progress_path():
    return os.path.join(_data_dir(), "progress.json")

def load_progress() -> dict:
    p = _progress_path()
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            pass
    return {}

def update_progress(ders: str, topic: str, quiz_score: float = 0):
    prog = load_progress()
    if ders not in prog:
        prog[ders] = {"topics": {}, "total_lessons": 0, "total_xp": 0,
                      "streak": 0, "last_date": "", "streak_freezes": 0,
                      "best_streak": 0, "daily_goal_done": False,
                      "daily_lessons_today": 0, "daily_goal_target": 2}
    gd = prog[ders]
    gd["topics"][topic[:80]] = {
        "completed": True, "quiz_score": quiz_score,
        "date": datetime.now().strftime("%Y-%m-%d"),
    }
    gd["total_lessons"] += 1

    # ═══ DOUBLE XP (Cuma gunleri) ═══
    is_friday = datetime.now().weekday() == 4
    xp_multiplier = 2 if is_friday else 1
    xp_earned = int((50 + quiz_score * 0.5) * xp_multiplier)
    gd["total_xp"] = gd.get("total_xp", 0) + xp_earned

    # ═══ STREAK with Freeze ═══
    today = datetime.now().strftime("%Y-%m-%d")
    yesterday = (datetime.now() - timedelta(days=1)).strftime("%Y-%m-%d")
    two_days_ago = (datetime.now() - timedelta(days=2)).strftime("%Y-%m-%d")

    if gd.get("last_date") in (yesterday, today):
        if gd.get("last_date") != today:
            gd["streak"] = gd.get("streak", 0) + 1
    elif gd.get("last_date") == two_days_ago and gd.get("streak_freezes", 0) > 0:
        # Streak freeze used
        gd["streak_freezes"] = gd.get("streak_freezes", 0) - 1
        gd["streak"] = gd.get("streak", 0) + 1
    else:
        gd["streak"] = 1
    gd["last_date"] = today

    # ═══ BEST STREAK tracking ═══
    gd["best_streak"] = max(gd.get("best_streak", 0), gd.get("streak", 0))

    # ═══ STREAK FREEZE earning ═══
    streak = gd.get("streak", 0)
    if streak >= 7 and gd.get("streak_freezes", 0) < 3:
        gd["streak_freezes"] = min(3, gd.get("streak_freezes", 0) + 1)

    # ═══ DAILY GOAL tracking ═══
    if gd.get("_daily_date") != today:
        gd["_daily_date"] = today
        gd["daily_lessons_today"] = 0
        gd["daily_goal_done"] = False
    gd["daily_lessons_today"] = gd.get("daily_lessons_today", 0) + 1
    goal_target = gd.get("daily_goal_target", 2)
    if gd["daily_lessons_today"] >= goal_target and not gd.get("daily_goal_done"):
        gd["daily_goal_done"] = True
        xp_earned += 25  # Daily goal bonus
        gd["total_xp"] = gd.get("total_xp", 0) + 25

    with open(_progress_path(), "w", encoding="utf-8") as f:
        json.dump(prog, f, ensure_ascii=False, indent=2)
    return xp_earned

def get_earned_badges(ders: str) -> list:
    prog = load_progress()
    gd = prog.get(ders, {})
    total = gd.get("total_lessons", 0)
    streak = gd.get("streak", 0)
    total_xp = gd.get("total_xp", 0)
    best_score = max((t.get("quiz_score", 0) for t in gd.get("topics", {}).values()), default=0)
    badges = []
    for b in BADGE_DEFS:
        earned = False
        if "req" in b and total >= b["req"]:
            earned = True
        elif "req_streak" in b and streak >= b["req_streak"]:
            earned = True
        elif "req_xp" in b and total_xp >= b["req_xp"]:
            earned = True
        elif "req_score" in b and best_score >= b["req_score"]:
            earned = True
        if earned:
            badges.append(b)
    return badges

def get_current_league(ders: str) -> dict:
    prog = load_progress()
    total_xp = prog.get(ders, {}).get("total_xp", 0)
    current = LEAGUE_DEFS[0]
    for lg in LEAGUE_DEFS:
        if total_xp >= lg["min_xp"]:
            current = lg
    return current

def get_next_league(ders: str) -> dict | None:
    prog = load_progress()
    total_xp = prog.get(ders, {}).get("total_xp", 0)
    for lg in LEAGUE_DEFS:
        if total_xp < lg["min_xp"]:
            return lg
    return None


