def _render_visual_js(visual: dict) -> str:
    """Visual section icin Canvas/SVG JS kodu uret — ders bazli ozel renderer."""
    vtype = visual.get("visual_type", "diagram")
    title = visual.get("title", "")
    desc = visual.get("description", "")
    data = visual.get("data", {})
    labels = data.get("labels", [])
    values = data.get("values", [])
    connections = data.get("connections", [])
    points = data.get("points", [])
    highlight = data.get("highlight", [])
    angles = data.get("angles", [])
    sides = data.get("sides", [])
    numerator = data.get("numerator", 3)
    denominator = data.get("denominator", 8)
    range_min = data.get("range_min", -5)
    range_max = data.get("range_max", 5)

    cv_h = 320 if vtype in ("cell_diagram", "atom_model", "dna_helix",
                             "earth_layers", "heart_circulation", "photosynthesis",
                             "periodic_table") else 280

    wrapper_start = (
        f'<div class="sec" style="opacity:1;transform:none">'
        f'<div class="s-hdr" style="background:linear-gradient(135deg,#7c3aed,#a855f7)">'
        f'\U0001F4CA {title}</div>'
        f'<div style="background:#0B0F19;border:1px solid rgba(124,58,237,0.3);'
        f'border-radius:0 0 10px 10px;padding:12px;margin-top:-4px">'
        f'<canvas id="vis_cv" width="560" height="{cv_h}" style="width:100%;border-radius:8px"></canvas>'
        f'<div style="color:#94a3b8;font-size:11px;margin-top:6px;text-align:center">{desc}</div>'
        f'</div></div>'
    )

    labels_js = json.dumps(labels, ensure_ascii=False)
    values_js = json.dumps(values, ensure_ascii=False)

    conn_js = json.dumps(connections, ensure_ascii=False)
    pts_js = json.dumps(points, ensure_ascii=False)
    hl_js = json.dumps(highlight, ensure_ascii=False)
    ang_js = json.dumps(angles, ensure_ascii=False)
    sid_js = json.dumps(sides, ensure_ascii=False)
    CLR = "['#3b82f6','#22c55e','#f59e0b','#ef4444','#a855f7','#06b6d4','#f97316','#ec4899']"
    I = f"var vc=document.getElementById('vis_cv');if(vc){{var c=vc.getContext('2d');var W=vc.width,H=vc.height;c.fillStyle='#0B0F19';c.fillRect(0,0,W,H);"

    draw_js = _build_visual_js(vtype, I, labels_js, values_js, conn_js, pts_js,
                                hl_js, ang_js, sid_js, CLR,
                                numerator, denominator, range_min, range_max)
    if not draw_js:
        # Fallback: bilinmeyen visual_type icin default renderer
        draw_js = f"""{I}var lbs={labels_js},vals={values_js};
c.fillStyle='#38bdf8';c.font='bold 14px system-ui';c.textAlign='center';
c.fillText(lbs[0]||'{title}',W/2,30);
c.fillStyle='#94a3b8';c.font='12px system-ui';
for(var i=1;i<lbs.length;i++)c.fillText(lbs[i]||'',W/2,55+i*22);
if(vals.length>0){{var bw=40,gap=10,sx=(W-(vals.length*(bw+gap)))/2,maxV=Math.max(...vals)||1;
for(var i=0;i<vals.length;i++){{var h2=vals[i]/maxV*120,x=sx+i*(bw+gap),y2=H-30-h2;
c.fillStyle=['#3b82f6','#22c55e','#f59e0b','#ef4444','#a855f7'][i%5];
c.beginPath();c.roundRect(x,y2,bw,h2,4);c.fill();
c.fillStyle='#e2e8f0';c.font='10px system-ui';c.fillText(lbs[i+1]||'',x+bw/2,H-15);}}}}
}}"""
    return wrapper_start, draw_js


