c.strokeStyle='#dfe6e9'; c.lineWidth=3;
c.beginPath(); c.moveTo(sx,sy); c.lineTo(sx,sy+eh); c.stroke();
c.beginPath(); c.moveTo(sx+ew,sy); c.lineTo(sx+ew,sy+eh); c.stroke();
