# S2 — SESLİ SORU-CEVAP (Web Speech API)
# ════════════════════════════════════════════════════════════
def render_voice_qa(lesson_data: dict, ders: str, kp: str):
    """Sesli soru-cevap: Web Speech API ile ses girdisi, AI cevap, TTS ile okuma."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F3A4 Sesli Soru-Cevap</span>'
        '<span style="color:#475569;font-size:.8rem;margin-left:8px">'
        'Mikrofona konuş, AI cevaplasın</span></div>',
        unsafe_allow_html=True,
    )
    import streamlit.components.v1 as components

    # Web Speech API HTML widget
    voice_html = """
    <div id="voiceBox" style="background:#f0f9ff;border:1px solid #93c5fd;
    border-radius:12px;padding:16px;text-align:center;font-family:system-ui">
      <button id="micBtn" onclick="startListening()" style="
        background:linear-gradient(135deg,#ef4444,#dc2626);color:#fff;border:none;
        border-radius:50%;width:64px;height:64px;font-size:24px;cursor:pointer;
        box-shadow:0 0 20px rgba(239,68,68,0.3);transition:all 0.3s">🎤</button>
      <div id="voiceStatus" style="color:#475569;font-size:.85rem;margin-top:8px">
        Mikrofona tıklayın ve sorunuzu söyleyin</div>
      <div id="voiceResult" style="color:#1e293b;font-size:.95rem;margin-top:12px;
        min-height:30px;background:#e2e8f0;border-radius:8px;padding:10px;display:none"></div>
      <button id="sendBtn" onclick="sendQuestion()" style="
        display:none;background:linear-gradient(135deg,#22c55e,#16a34a);color:#fff;
        border:none;border-radius:8px;padding:8px 24px;margin-top:8px;cursor:pointer;
        font-weight:700;font-size:.9rem">📨 Gönder</button>
    </div>
    <script>
    let recognition=null,transcript='';
    function startListening(){
      const SR=window.SpeechRecognition||window.webkitSpeechRecognition;
      if(!SR){document.getElementById('voiceStatus').textContent='Tarayıcınız ses tanımayı desteklemiyor';return;}
      recognition=new SR();recognition.lang='tr-TR';recognition.continuous=false;recognition.interimResults=true;
      const btn=document.getElementById('micBtn');
      btn.style.background='linear-gradient(135deg,#22c55e,#16a34a)';
      btn.style.boxShadow='0 0 30px rgba(34,197,94,0.5)';
      document.getElementById('voiceStatus').textContent='Dinleniyor...';
      recognition.onresult=function(e){
        transcript='';for(let i=0;i<e.results.length;i++)transcript+=e.results[i][0].transcript;
        document.getElementById('voiceResult').style.display='block';
        document.getElementById('voiceResult').textContent=transcript;
      };
      recognition.onend=function(){
        btn.style.background='linear-gradient(135deg,#ef4444,#dc2626)';
        btn.style.boxShadow='0 0 20px rgba(239,68,68,0.3)';
        document.getElementById('voiceStatus').textContent='Tamamlandı. Göndermek için butona tıklayın.';
        if(transcript)document.getElementById('sendBtn').style.display='inline-block';
      };
      recognition.onerror=function(e){
        document.getElementById('voiceStatus').textContent='Hata: '+e.error;
        btn.style.background='linear-gradient(135deg,#ef4444,#dc2626)';
      };
      recognition.start();
    }
    function sendQuestion(){
      if(transcript){
        window.parent.postMessage({type:'voice_question',text:transcript},'*');
        document.getElementById('voiceStatus').textContent='Soru gönderildi: '+transcript;
        document.getElementById('sendBtn').style.display='none';
      }
    }
    </script>
    """
    components.html(voice_html, height=220)

    # Metin tabanlı fallback
    st.markdown(
        '<div style="color:#64748b;font-size:.8rem;text-align:center;margin:-4px 0 8px">'
        'veya yazarak sorun:</div>', unsafe_allow_html=True)

    hist_key = f"{kp}_voice_hist"
    if hist_key not in st.session_state:
        st.session_state[hist_key] = []

    user_q = st.text_input("Sorunuz:", key=f"{kp}_voice_input",
                            placeholder="Sorunuzu yazın veya yukarıdan sesle söyleyin...")

    if user_q and st.button("\U0001F4E8 Sor", key=f"{kp}_voice_send", type="primary"):
        st.session_state[hist_key].append({"role": "user", "text": user_q})
        client = _get_client()
        if client:
            try:
                ctx = json.dumps(lesson_data.get("sections", [])[:5], ensure_ascii=False)[:1500]
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content":
                         f"Sen {ders} ogretmenisin. Ogrenci sesli soru sordu. "
                         f"Ders baglami: {ctx}\n"
                         "Kisa, net ve konusmaya uygun cevap ver. Turkce. Max 120 kelime."},
                        {"role": "user", "content": user_q},
                    ],
                    max_tokens=250, temperature=0.7,
                )
                answer = resp.choices[0].message.content
            except Exception as e:
                answer = f"Hata: {e}"
        else:
            answer = "AI bağlantısı kurulamadı."
        st.session_state[hist_key].append({"role": "assistant", "text": answer})
        st.rerun()

    # Geçmiş konuşmalar
    for msg in st.session_state.get(hist_key, []):
        icon = "\U0001F3A4" if msg["role"] == "user" else "\U0001F468\u200D\U0001F3EB"
        bg = "#dbeafe" if msg["role"] == "user" else "#dcfce7"
        bdr = "#3b82f6" if msg["role"] == "user" else "#22c55e"
        st.markdown(
            f'<div style="border-left:3px solid {bdr};background:{bg};border-radius:0 8px 8px 0;'
            f'padding:8px 12px;margin:4px 0">'
            f'{icon} <span style="color:#1e293b;font-size:.9rem">{msg["text"]}</span></div>',
            unsafe_allow_html=True,
        )
        # AI cevabını sesli oku (TTS fallback)
        if msg["role"] == "assistant":
            tts_js = msg["text"].replace("'", "\\'").replace("\n", " ")
            st.markdown(
                f'<div style="text-align:right;margin:-2px 0 4px">'
                f'<button onclick="try{{var u=new SpeechSynthesisUtterance(\'{tts_js}\');'
                f'u.lang=\'tr-TR\';u.rate=0.9;speechSynthesis.speak(u)}}catch(e){{}}"'
                f' style="background:#e2e8f0;color:#0c4a6e;border:1px solid #93c5fd;'
                f'border-radius:6px;padding:3px 10px;cursor:pointer;font-size:.75rem">'
                f'\U0001F50A Dinle</button></div>',
                unsafe_allow_html=True,
            )


# ════════════════════════════════════════════════════════════
# S3 — İNTERAKTİF SİMÜLASYON
# ════════════════════════════════════════════════════════════
def _ai_generate_simulation(ders: str, konu: str) -> str | None:
    """AI ile konuya özel Canvas tabanlı interaktif simülasyon HTML kodu üret."""
    client = _get_client()
    if not client:
        return None
    prompt = f"""Sen bir eğitim simülasyonu geliştiricisisin.
"{ders}" dersinde "{konu}" konusu için Canvas tabanlı interaktif bir simülasyon yaz.

KURALLAR:
1. Tam bir HTML dosyası döndür (<!DOCTYPE html> ile başla)
2. Canvas boyutu: width="560" height="400"
3. Koyu arka plan (#0B0F19), modern renkler kullan
4. EN AZ 2 adet range slider (input type=range) ile parametreleri değiştirilebilir yap
5. requestAnimationFrame ile sürekli animasyon olsun
6. Slider değişince simülasyon anında güncellensin
7. Sol üstte bilgi metinleri göster (formüller, değerler)
8. Mouse etkileşimi ekle (mümkünse sürükle-bırak)
9. Konuyla DOĞRUDAN ilgili olsun — genel parçacık sistemi YAPMA
10. Türkçe etiketler kullan
11. body margin:0, font-family:system-ui
12. Sadece HTML/CSS/JS — harici kütüphane KULLANMA

Örnek konular ve beklenen simülasyonlar:
- "Fotosentez" → Güneş ışığı, CO2, H2O girişi → O2, glikoz çıkışı animasyonu, ışık şiddeti slider'ı
- "Pythagor teoremi" → Üçgen çiz, kenar uzunluklarını slider ile değiştir, a²+b²=c² göster
- "Ohm yasası" → Devre, voltaj/direnç slider, akım/parlaklık değişimi
- "Hücre bölünmesi" → Mitoz aşamaları animasyonu, hız slider'ı

Sadece HTML kodu döndür, açıklama yazma."""

    try:
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": prompt},
                {"role": "user", "content": f"Ders: {ders}, Konu: {konu}"},
            ],
            max_tokens=4000,
            temperature=0.7,
        )
        html = resp.choices[0].message.content
        # Markdown code block temizle
        if "```html" in html:
            html = html.split("```html", 1)[1].rsplit("```", 1)[0]
        elif "```" in html:
            html = html.split("```", 1)[1].rsplit("```", 1)[0]
        return html.strip()
    except Exception as e:
        _logger.error(f"Simulation AI: {e}")
        return None


def render_interactive_simulation(ders: str, konu: str, kp: str):
    """Konuya özel interaktif simülasyon — hazır veya AI üretimli."""
    import streamlit.components.v1 as components

    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F3AE \u0130nteraktif Sim\u00FClasyon</span>'
        '<span style="color:#475569;font-size:.8rem;margin-left:8px">'
        f'{konu or ders}</span></div>',
        unsafe_allow_html=True,
    )

    # Hazır simülasyonlarla konu eşleştirmesi
    _KONU_SIM_MAP = {
        "sarkaç": "Sarkaç Hareketi", "sarkac": "Sarkaç Hareketi",
        "salınım": "Sarkaç Hareketi", "periyot": "Sarkaç Hareketi",
        "kuvvet": "Kuvvet ve İvme (F=ma)", "newton": "Kuvvet ve İvme (F=ma)",
        "ivme": "Kuvvet ve İvme (F=ma)", "f=ma": "Kuvvet ve İvme (F=ma)",
        "fonksiyon": "Fonksiyon Grafiği Çizer", "grafik": "Fonksiyon Grafiği Çizer",
        "doğrusal": "Fonksiyon Grafiği Çizer", "parabol": "Fonksiyon Grafiği Çizer",
        "atom": "Atom Modeli (Elektron Yörüngesi)", "elektron": "Atom Modeli (Elektron Yörüngesi)",
        "periyodik": "Atom Modeli (Elektron Yörüngesi)", "element": "Atom Modeli (Elektron Yörüngesi)",
    }

    # Konudan hazır simülasyon bul
    konu_lower = (konu or "").lower()
    matched_sim = None
    for keyword, sim_name in _KONU_SIM_MAP.items():
        if keyword in konu_lower:
            matched_sim = sim_name
            break

    sim_key = f"{kp}_sim_html"
    gen_key = f"{kp}_sim_gen"

    if matched_sim:
        # Hazır simülasyon var
        sim_html = _build_simulation_html(matched_sim, ders)
        components.html(sim_html, height=480, scrolling=False)
    elif sim_key in st.session_state:
        # AI üretilmiş simülasyon var
        components.html(st.session_state[sim_key], height=480, scrolling=False)
        def _reset_sim():
            st.session_state.pop(sim_key, None)
        st.button("\U0001F504 Yeni Sim\u00FClasyon \u00DCret", key=f"{kp}_sim_reset",
                  use_container_width=True, on_click=_reset_sim)
    elif st.session_state.get(gen_key):
        # AI üretiyor
        with st.spinner(f"\U0001F3AE '{konu}' i\u00E7in sim\u00FClasyon \u00FCretiliyor..."):
            html = _ai_generate_simulation(_strip_emoji(ders), konu)
            if html:
                st.session_state[sim_key] = html
            else:
                st.error("Sim\u00FClasyon \u00Fcretilemedi. L\u00FCtfen tekrar deneyin.")
            st.session_state[gen_key] = False
            st.rerun()
    else:
        # Üret butonu
        st.info(f"\U0001F4A1 **{konu}** konusu i\u00E7in AI ile \u00F6zel sim\u00FClasyon \u00FCretilecek.")
        def _start_gen():
            st.session_state[gen_key] = True
        st.button(f"\U0001F680 '{konu}' Sim\u00FClasyonu \u00DCret",
                  key=f"{kp}_sim_gen_btn", use_container_width=True,
                  type="primary", on_click=_start_gen)


def _build_simulation_html(sim_name: str, ders: str) -> str:
    """Seçilen simülasyon için Canvas tabanlı interaktif HTML üret."""
    common_style = """
    <style>
    body{margin:0;background:#f0f9ff;font-family:system-ui;overflow:hidden}
    canvas{display:block;margin:0 auto;border-radius:12px;cursor:crosshair}
    .ctrl{display:flex;gap:8px;justify-content:center;padding:8px;flex-wrap:wrap}
    .ctrl label{color:#475569;font-size:.8rem}
    .ctrl input[type=range]{width:120px;accent-color:#0c4a6e}
    .ctrl span{color:#0c4a6e;font-size:.85rem;font-weight:700;min-width:40px}
    .info{color:#64748b;font-size:.75rem;text-align:center;padding:4px}
    </style>
    """

    if sim_name == "Sarkaç Hareketi":
        return f"""<!DOCTYPE html><html><head><meta charset="utf-8">{common_style}</head><body>
        <canvas id="c" width="560" height="360"></canvas>
        <div class="ctrl">
          <label>Uzunluk: <input type="range" id="sLen" min="50" max="250" value="150"
            oninput="L=+this.value;document.getElementById('vLen').textContent=this.value+'px'">
            <span id="vLen">150px</span></label>
          <label>Yerçekimi: <input type="range" id="sG" min="1" max="30" value="10"
            oninput="g=+this.value;document.getElementById('vG').textContent=this.value">
            <span id="vG">10</span></label>
          <label>Sönüm: <input type="range" id="sD" min="0" max="100" value="5"
            oninput="damp=this.value/1000;document.getElementById('vD').textContent=(this.value/10).toFixed(1)+'%'">
            <span id="vD">0.5%</span></label>
        </div>
        <div class="info">Sarkacı mouse ile sürükleyip bırakın</div>
        <script>
        var cv=document.getElementById('c'),c=cv.getContext('2d');
        var W=cv.width,H=cv.height,ox=W/2,oy=60;
        var L=150,g=10,damp=0.005,angle=Math.PI/4,aVel=0;
        var dragging=false,trail=[];
        function draw(){{
          c.fillStyle='#0B0F19';c.fillRect(0,0,W,H);
          // Grid
          c.strokeStyle='rgba(148,163,184,0.05)';c.lineWidth=1;
          for(var i=0;i<W;i+=30){{c.beginPath();c.moveTo(i,0);c.lineTo(i,H);c.stroke();}}
          for(var i=0;i<H;i+=30){{c.beginPath();c.moveTo(0,i);c.lineTo(W,i);c.stroke();}}
          var bx=ox+L*Math.sin(angle),by=oy+L*Math.cos(angle);
          // Trail
          trail.push({{x:bx,y:by}});if(trail.length>80)trail.shift();
          c.strokeStyle='rgba(212,175,55,0.15)';c.lineWidth=2;c.beginPath();
          for(var i=0;i<trail.length;i++){{if(i===0)c.moveTo(trail[i].x,trail[i].y);else c.lineTo(trail[i].x,trail[i].y);}}
          c.stroke();
          // String
          c.strokeStyle='#64748b';c.lineWidth=2;c.beginPath();c.moveTo(ox,oy);c.lineTo(bx,by);c.stroke();
          // Pivot
          c.fillStyle='#94a3b8';c.beginPath();c.arc(ox,oy,5,0,Math.PI*2);c.fill();
          // Bob
          var grad=c.createRadialGradient(bx-4,by-4,2,bx,by,18);
          grad.addColorStop(0,'#f59e0b');grad.addColorStop(1,'#d97706');
          c.fillStyle=grad;c.beginPath();c.arc(bx,by,18,0,Math.PI*2);c.fill();
          c.strokeStyle='#fbbf24';c.lineWidth=1.5;c.stroke();
          // Info
          c.fillStyle='#6366F1';c.font='bold 12px system-ui';c.textAlign='left';
          c.fillText('Açı: '+(angle*180/Math.PI).toFixed(1)+'°',12,24);
          c.fillText('Hız: '+(aVel*100).toFixed(1),12,40);
          c.fillText('T = 2π√(L/g) = '+(2*Math.PI*Math.sqrt(L/(g*100))).toFixed(2)+'s',12,56);
          if(!dragging){{aVel+=(-g/100)*Math.sin(angle)*0.016;aVel*=(1-damp);angle+=aVel;}}
          requestAnimationFrame(draw);
        }}
        cv.addEventListener('mousedown',function(e){{
          var r=cv.getBoundingClientRect();var mx=e.clientX-r.left;var my=e.clientY-r.top;
          var bx=ox+L*Math.sin(angle),by=oy+L*Math.cos(angle);
          if(Math.hypot(mx-bx,my-by)<30){{dragging=true;aVel=0;trail=[];}}
        }});
        cv.addEventListener('mousemove',function(e){{
          if(!dragging)return;var r=cv.getBoundingClientRect();
          var mx=e.clientX-r.left-ox,my=e.clientY-r.top-oy;
          angle=Math.atan2(mx,my);
        }});
        cv.addEventListener('mouseup',function(){{dragging=false;}});
        cv.addEventListener('mouseleave',function(){{dragging=false;}});
        draw();
        </script></body></html>"""

    elif sim_name == "Kuvvet ve İvme (F=ma)":
        return f"""<!DOCTYPE html><html><head><meta charset="utf-8">{common_style}</head><body>
        <canvas id="c" width="560" height="320"></canvas>
        <div class="ctrl">
          <label>Kütle (kg): <input type="range" id="sM" min="1" max="50" value="10"
            oninput="mass=+this.value;document.getElementById('vM').textContent=this.value">
            <span id="vM">10</span></label>
          <label>Kuvvet (N): <input type="range" id="sF" min="0" max="200" value="50"
            oninput="force=+this.value;document.getElementById('vF').textContent=this.value">
            <span id="vF">50</span></label>
          <label>Sürtünme: <input type="range" id="sFr" min="0" max="100" value="10"
            oninput="friction=this.value/100;document.getElementById('vFr').textContent=(this.value/100).toFixed(2)">
            <span id="vFr">0.10</span></label>
        </div>
        <div class="info">Kuvvet ve sürtünme slider'larını ayarlayın, cismi gözlemleyin</div>
        <script>
        var cv=document.getElementById('c'),c=cv.getContext('2d');
        var W=cv.width,H=cv.height;
        var mass=10,force=50,friction=0.1,posX=80,velX=0,accel=0;
        function draw(){{
          c.fillStyle='#0B0F19';c.fillRect(0,0,W,H);
          // Ground
          c.fillStyle='#1e293b';c.fillRect(0,H-40,W,40);
          c.strokeStyle='#334155';c.lineWidth=1;
          for(var i=0;i<W;i+=15){{c.beginPath();c.moveTo(i,H-40);c.lineTo(i-8,H-30);c.stroke();}}
          // Physics
          var netF=force-friction*mass*9.8;if(netF<0&&velX<=0)netF=0;
          accel=netF/mass;velX+=accel*0.016;if(velX<0)velX=0;
          posX+=velX*0.5;if(posX>W+60)posX=-60;
          // Box
          var bw=30+mass*0.8,bh=30+mass*0.5;
          var bx=posX,by=H-40-bh;
          c.fillStyle='#3b82f6';c.fillRect(bx,by,bw,bh);
          c.strokeStyle='#60a5fa';c.lineWidth=2;c.strokeRect(bx,by,bw,bh);
          c.fillStyle='#fff';c.font='bold 11px system-ui';c.textAlign='center';
          c.fillText(mass+'kg',bx+bw/2,by+bh/2+4);
          // Force arrow
          if(force>0){{c.strokeStyle='#ef4444';c.lineWidth=3;c.beginPath();
          c.moveTo(bx+bw,by+bh/2);c.lineTo(bx+bw+force*0.6,by+bh/2);c.stroke();
          c.fillStyle='#ef4444';c.beginPath();c.moveTo(bx+bw+force*0.6+10,by+bh/2);
          c.lineTo(bx+bw+force*0.6-2,by+bh/2-6);c.lineTo(bx+bw+force*0.6-2,by+bh/2+6);c.fill();
          c.fillText('F='+force+'N',bx+bw+force*0.3,by+bh/2-10);}}
          // Friction arrow
          if(friction>0&&velX>0){{var fF=friction*mass*9.8;c.strokeStyle='#f59e0b';c.lineWidth=2;
          c.beginPath();c.moveTo(bx,by+bh/2);c.lineTo(bx-Math.min(fF*0.6,80),by+bh/2);c.stroke();
          c.fillStyle='#f59e0b';c.fillText('f='+fF.toFixed(1)+'N',bx-40,by+bh/2-10);}}
          // Info
          c.fillStyle='#6366F1';c.font='bold 12px system-ui';c.textAlign='left';
          c.fillText('a = F/m = '+accel.toFixed(2)+' m/s²',12,24);
          c.fillText('v = '+velX.toFixed(2)+' m/s',12,42);
          c.fillText('F_net = '+(force-friction*mass*9.8).toFixed(1)+' N',12,60);
          requestAnimationFrame(draw);
        }}
        draw();
        </script></body></html>"""

    elif sim_name == "Fonksiyon Grafiği Çizer":
        return f"""<!DOCTYPE html><html><head><meta charset="utf-8">{common_style}</head><body>
        <canvas id="c" width="560" height="340"></canvas>
        <div class="ctrl">
          <label>a: <input type="range" id="sA" min="-5" max="5" value="1" step="0.5"
            oninput="a=+this.value;document.getElementById('vA').textContent=this.value">
            <span id="vA">1</span></label>
          <label>b: <input type="range" id="sB" min="-5" max="5" value="0" step="0.5"
            oninput="b=+this.value;document.getElementById('vB').textContent=this.value">
            <span id="vB">0</span></label>
          <label>c: <input type="range" id="sC" min="-5" max="5" value="0" step="0.5"
            oninput="cc=+this.value;document.getElementById('vC').textContent=this.value">
            <span id="vC">0</span></label>
          <label style="color:#0c4a6e">Fonksiyon: <select id="fType" onchange="ftype=this.value"
            style="background:#e2e8f0;color:#0c4a6e;border:1px solid #0284c7;border-radius:4px;padding:2px">
            <option value="linear">y = ax + b</option>
            <option value="quadratic">y = ax² + bx + c</option>
            <option value="sin">y = a·sin(bx) + c</option>
          </select></label>
        </div>
        <script>
        var cv=document.getElementById('c'),c=cv.getContext('2d');
        var W=cv.width,H=cv.height,ox=W/2,oy=H/2,sc=30;
        var a=1,b=0,cc=0,ftype='linear';
        function f(x){{
          if(ftype==='linear')return a*x+b;
          if(ftype==='quadratic')return a*x*x+b*x+cc;
          if(ftype==='sin')return a*Math.sin(b*x)+cc;
          return x;
        }}
        function draw(){{
          c.fillStyle='#0B0F19';c.fillRect(0,0,W,H);
          // Grid
          c.strokeStyle='rgba(148,163,184,0.08)';c.lineWidth=1;
          for(var i=-10;i<=10;i++){{c.beginPath();c.moveTo(ox+i*sc,0);c.lineTo(ox+i*sc,H);c.stroke();
          c.beginPath();c.moveTo(0,oy+i*sc);c.lineTo(W,oy+i*sc);c.stroke();}}
          // Axes
          c.strokeStyle='#64748b';c.lineWidth=2;
          c.beginPath();c.moveTo(0,oy);c.lineTo(W,oy);c.stroke();
          c.beginPath();c.moveTo(ox,0);c.lineTo(ox,H);c.stroke();
          c.fillStyle='#64748b';c.font='10px system-ui';c.textAlign='center';
          for(var i=-8;i<=8;i++)if(i!==0)c.fillText(i,ox+i*sc,oy+14);
          // Function
          c.strokeStyle='#3b82f6';c.lineWidth=2.5;c.beginPath();
          var started=false;
          for(var px=0;px<W;px++){{var x=(px-ox)/sc;var y=f(x);var py=oy-y*sc;
          if(py>-50&&py<H+50){{if(!started){{c.moveTo(px,py);started=true;}}else c.lineTo(px,py);}}}}
          c.stroke();
          // Label
          c.fillStyle='#6366F1';c.font='bold 13px system-ui';c.textAlign='left';
          var lbl=ftype==='linear'?'y = '+a+'x + '+b:ftype==='quadratic'?'y = '+a+'x² + '+b+'x + '+cc:'y = '+a+'·sin('+b+'x) + '+cc;
          c.fillText(lbl,12,24);
          requestAnimationFrame(draw);
        }}
        draw();
        </script></body></html>"""

    elif sim_name == "Atom Modeli (Elektron Yörüngesi)":
        return f"""<!DOCTYPE html><html><head><meta charset="utf-8">{common_style}</head><body>
        <canvas id="c" width="560" height="380"></canvas>
        <div class="ctrl">
          <label>Proton: <input type="range" id="sP" min="1" max="20" value="6"
            oninput="protons=+this.value;setupAtom();document.getElementById('vP').textContent=this.value">
            <span id="vP">6</span></label>
          <label>Hız: <input type="range" id="sSpd" min="1" max="10" value="3"
            oninput="speed=+this.value;document.getElementById('vSpd').textContent=this.value">
            <span id="vSpd">3</span></label>
        </div>
        <div class="info">Proton sayısını değiştirip atom modelini gözlemleyin</div>
        <script>
        var cv=document.getElementById('c'),c=cv.getContext('2d');
        var W=cv.width,H=cv.height,cx=W/2,cy=H/2;
        var protons=6,speed=3,electrons=[],shells=[],t=0;
        var elements=['','H','He','Li','Be','B','C','N','O','F','Ne','Na','Mg','Al','Si','P','S','Cl','Ar','K','Ca'];
        function setupAtom(){{
          electrons=[];shells=[];
          var config=[2,8,8,2];var rem=protons;
          for(var s=0;s<config.length&&rem>0;s++){{
            var n=Math.min(rem,config[s]);shells.push(n);rem-=n;
            for(var i=0;i<n;i++)electrons.push({{shell:s,angle:Math.PI*2*i/n+Math.random()*0.5}});
          }}
        }}
        setupAtom();
        function draw(){{
          t+=0.016*speed;
          c.fillStyle='#0B0F19';c.fillRect(0,0,W,H);
          // Orbits
          for(var s=0;s<shells.length;s++){{
            var r=50+s*40;c.strokeStyle='rgba(148,163,184,0.15)';c.lineWidth=1;
            c.beginPath();c.arc(cx,cy,r,0,Math.PI*2);c.stroke();
          }}
          // Nucleus
          var nr=12+protons*0.8;
          var grd=c.createRadialGradient(cx-3,cy-3,2,cx,cy,nr);
          grd.addColorStop(0,'#ef4444');grd.addColorStop(1,'#991b1b');
          c.fillStyle=grd;c.beginPath();c.arc(cx,cy,nr,0,Math.PI*2);c.fill();
          c.fillStyle='#fff';c.font='bold '+(10+Math.min(protons,6))+'px system-ui';
          c.textAlign='center';c.textBaseline='middle';
          c.fillText(protons+'p',cx,cy);
          // Electrons
          for(var i=0;i<electrons.length;i++){{
            var e=electrons[i],r=50+e.shell*40;
            e.angle+=0.02*speed*(1/(e.shell+1));
            var ex=cx+r*Math.cos(e.angle),ey=cy+r*Math.sin(e.angle);
            c.fillStyle='#3b82f6';c.beginPath();c.arc(ex,ey,5,0,Math.PI*2);c.fill();
            c.fillStyle='rgba(59,130,246,0.2)';c.beginPath();c.arc(ex,ey,8,0,Math.PI*2);c.fill();
          }}
          // Info
          c.fillStyle='#6366F1';c.font='bold 13px system-ui';c.textAlign='left';c.textBaseline='top';
          c.fillText('Element: '+(elements[protons]||'?')+' (Z='+protons+')',12,12);
          c.fillText('Elektron: '+electrons.length,12,30);
          var sh='Katmanlar: ';for(var s=0;s<shells.length;s++)sh+=(s>0?'-':'')+shells[s];
          c.fillText(sh,12,48);
          requestAnimationFrame(draw);
        }}
        draw();
        </script></body></html>"""

    else:
        # Genel simülasyon — basit parçacık sistemi
        return f"""<!DOCTYPE html><html><head><meta charset="utf-8">{common_style}</head><body>
        <canvas id="c" width="560" height="380"></canvas>
        <div class="ctrl">
          <label>Parçacık: <input type="range" id="sN" min="5" max="100" value="30"
            oninput="resetParticles(+this.value);document.getElementById('vN').textContent=this.value">
            <span id="vN">30</span></label>
          <label>Sıcaklık: <input type="range" id="sT" min="1" max="20" value="5"
            oninput="temp=+this.value;document.getElementById('vT').textContent=this.value">
            <span id="vT">5</span></label>
        </div>
        <div class="info">Sıcaklığı artırarak parçacık hareketini gözlemleyin</div>
        <script>
        var cv=document.getElementById('c'),c=cv.getContext('2d');
        var W=cv.width,H=cv.height,particles=[],temp=5;
        function resetParticles(n){{
          particles=[];for(var i=0;i<n;i++)
          particles.push({{x:Math.random()*W,y:Math.random()*H,
            vx:(Math.random()-0.5)*4,vy:(Math.random()-0.5)*4,
            r:3+Math.random()*3,color:['#3b82f6','#22c55e','#f59e0b','#ef4444','#a855f7'][i%5]}});
        }}
        resetParticles(30);
        function draw(){{
          c.fillStyle='rgba(15,23,42,0.3)';c.fillRect(0,0,W,H);
          for(var i=0;i<particles.length;i++){{
            var p=particles[i];p.x+=p.vx*temp*0.3;p.y+=p.vy*temp*0.3;
            if(p.x<p.r||p.x>W-p.r)p.vx*=-1;if(p.y<p.r||p.y>H-p.r)p.vy*=-1;
            p.x=Math.max(p.r,Math.min(W-p.r,p.x));p.y=Math.max(p.r,Math.min(H-p.r,p.y));
            c.fillStyle=p.color;c.beginPath();c.arc(p.x,p.y,p.r,0,Math.PI*2);c.fill();
          }}
          c.fillStyle='#6366F1';c.font='bold 12px system-ui';c.textAlign='left';
          c.fillText('Parçacık: '+particles.length+'  Sıcaklık: '+temp,12,20);
          requestAnimationFrame(draw);
        }}
        draw();
        </script></body></html>"""


# ════════════════════════════════════════════════════════════
# S4 — AKILLI TEKRAR (Spaced Repetition / Anki benzeri)
# ════════════════════════════════════════════════════════════
def _sr_path():
    return os.path.join(_data_dir(), "spaced_repetition.json")

def _load_sr() -> dict:
    p = _sr_path()
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            pass
    return {"cards": []}

def _save_sr(data: dict):
    with open(_sr_path(), "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def add_to_spaced_repetition(vocab_data: list, ders: str, topic: str):
    """Ders kavramlarını Spaced Repetition havuzuna ekle."""
    sr = _load_sr()
    existing = {(c["term"], c["ders"]) for c in sr["cards"]}
    added = 0
    for v in vocab_data:
        term = v.get("term", v.get("en", ""))
        if not term or (term, ders) in existing:
            continue
        sr["cards"].append({
            "term": term,
            "definition": v.get("definition", v.get("tr", "")),
            "example": v.get("example", ""),
            "ders": ders,
            "topic": topic,
            "ease": 2.5,
            "interval": 1,
            "repetitions": 0,
            "next_review": datetime.now().strftime("%Y-%m-%d"),
            "added": datetime.now().strftime("%Y-%m-%d"),
        })
        added += 1
    _save_sr(sr)
    return added

def render_spaced_repetition(ders: str, kp: str):
    """Spaced Repetition UI — bugün tekrar edilecek kartları göster."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F501 Akıllı Tekrar (Spaced Repetition)</span>'
        '<span style="color:#475569;font-size:.8rem;margin-left:8px">'
        'Anki tarzı akıllı kart tekrarı</span></div>',
        unsafe_allow_html=True,
    )

    sr = _load_sr()
    today = datetime.now().strftime("%Y-%m-%d")
    due_cards = [c for c in sr["cards"]
                 if c.get("ders", "") == ders and c.get("next_review", "") <= today]
    all_cards = [c for c in sr["cards"] if c.get("ders", "") == ders]

    # İstatistikler
    sc1, sc2, sc3 = st.columns(3)
    with sc1:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(59,130,246,0.3);border-radius:10px;'
            f'padding:10px;text-align:center">'
            f'<div style="color:#3b82f6;font-size:1.5rem;font-weight:800">{len(all_cards)}</div>'
            f'<div style="color:#64748b;font-size:.75rem">Toplam Kart</div></div>',
            unsafe_allow_html=True)
    with sc2:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(34,197,94,0.3);border-radius:10px;'
            f'padding:10px;text-align:center">'
            f'<div style="color:#22c55e;font-size:1.5rem;font-weight:800">{len(due_cards)}</div>'
            f'<div style="color:#64748b;font-size:.75rem">Bugün Tekrar</div></div>',
            unsafe_allow_html=True)
    with sc3:
        mastered = len([c for c in all_cards if c.get("interval", 1) >= 21])
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid #93c5fd;border-radius:10px;'
            f'padding:10px;text-align:center">'
            f'<div style="color:#0c4a6e;font-size:1.5rem;font-weight:800">{mastered}</div>'
            f'<div style="color:#64748b;font-size:.75rem">Uzmanlaşılan</div></div>',
            unsafe_allow_html=True)

    if not due_cards:
        st.success("Bugün tekrar edilecek kart yok! Tebrikler.")
        return

    # Kart göster
    idx_key = f"{kp}_sr_idx"
    flipped_key = f"{kp}_sr_flipped"
    if idx_key not in st.session_state:
        st.session_state[idx_key] = 0
    if flipped_key not in st.session_state:
        st.session_state[flipped_key] = False

    ci = st.session_state[idx_key]
    if ci >= len(due_cards):
        st.success(f"Tüm {len(due_cards)} kart tamamlandı! Harika!")
        st.session_state.pop(idx_key, None)
        st.session_state.pop(flipped_key, None)
        return

    card = due_cards[ci]
    flipped = st.session_state[flipped_key]

    st.markdown(
        f'<div style="color:#64748b;font-size:.8rem;text-align:center;margin-bottom:4px">'
        f'Kart {ci+1}/{len(due_cards)} | Konu: {card.get("topic","")}</div>',
        unsafe_allow_html=True)

    if not flipped:
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
            f'border:2px solid #3b82f6;border-radius:14px;padding:30px;'
            f'text-align:center;min-height:120px;display:flex;align-items:center;justify-content:center">'
            f'<div style="color:#1e293b;font-size:1.3rem;font-weight:700">'
            f'{card.get("term","")}</div></div>',
            unsafe_allow_html=True)
        def _flip():
            st.session_state[flipped_key] = True
        st.button("\U0001F504 Cevabı Göster", key=f"{kp}_sr_flip",
                  use_container_width=True, type="primary", on_click=_flip)
    else:
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);'
            f'border:2px solid #22c55e;border-radius:14px;padding:24px;'
            f'text-align:center;min-height:120px">'
            f'<div style="color:#0c4a6e;font-size:1.1rem;font-weight:700;margin-bottom:8px">'
            f'{card.get("term","")}</div>'
            f'<div style="color:#22c55e;font-size:1.1rem;font-weight:600">'
            f'{card.get("definition","")}</div>'
            + (f'<div style="color:#475569;font-size:.85rem;margin-top:8px;font-style:italic">'
               f'{card.get("example","")}</div>' if card.get("example") else '')
            + '</div>',
            unsafe_allow_html=True)

        st.markdown(
            '<div style="color:#475569;font-size:.85rem;text-align:center;margin:8px 0">'
            'Ne kadar kolaydı?</div>', unsafe_allow_html=True)

        bc1, bc2, bc3, bc4 = st.columns(4)
        ratings = [
            (bc1, "\u274C Tekrar", 0, "#ef4444"),
            (bc2, "\U0001F914 Zor", 1, "#f59e0b"),
            (bc3, "\U0001F44D İyi", 2, "#3b82f6"),
            (bc4, "\U0001F31F Kolay", 3, "#22c55e"),
        ]
        for col, label, quality, color in ratings:
            with col:
                def _rate(q=quality):
                    _update_sr_card(card, q)
                    st.session_state[idx_key] = st.session_state.get(idx_key, 0) + 1
                    st.session_state[flipped_key] = False
                st.button(label, key=f"{kp}_sr_rate_{quality}",
                          use_container_width=True, on_click=_rate)


def _update_sr_card(card: dict, quality: int):
    """SM-2 algoritması ile kartı güncelle."""
    sr = _load_sr()
    for c in sr["cards"]:
        if c["term"] == card["term"] and c["ders"] == card["ders"]:
            ease = c.get("ease", 2.5)
            interval = c.get("interval", 1)
            reps = c.get("repetitions", 0)

            if quality < 1:  # Tekrar
                reps = 0
                interval = 1
            elif quality == 1:  # Zor
                reps += 1
                interval = max(1, int(interval * 1.2))
                ease = max(1.3, ease - 0.3)
            elif quality == 2:  # İyi
                reps += 1
                if reps == 1:
                    interval = 1
                elif reps == 2:
                    interval = 3
                else:
                    interval = int(interval * ease)
                ease = max(1.3, ease - 0.05)
            else:  # Kolay
                reps += 1
                if reps == 1:
                    interval = 2
                elif reps == 2:
                    interval = 6
                else:
                    interval = int(interval * ease * 1.3)
                ease = max(1.3, ease + 0.15)

            c["ease"] = round(ease, 2)
            c["interval"] = interval
            c["repetitions"] = reps
            c["next_review"] = (datetime.now() + timedelta(days=interval)).strftime("%Y-%m-%d")
            break
    _save_sr(sr)


