# S5 — DERS SONU SERTİFİKA (PDF)
# ════════════════════════════════════════════════════════════
def generate_certificate_pdf(student_name: str, ders: str, topic: str,
                              score: float, date_str: str = "") -> bytes | None:
    """Ders sonu sertifika PDF üret."""
    try:
        from reportlab.lib.pagesizes import landscape, A4
        from reportlab.lib.colors import HexColor
        from reportlab.pdfgen import canvas as pdf_canvas
        from reportlab.lib.units import cm
        import io

        buf = io.BytesIO()
        w, h = landscape(A4)
        c = pdf_canvas.Canvas(buf, pagesize=landscape(A4))

        # Arka plan
        c.setFillColor(HexColor("#0B0F19"))
        c.rect(0, 0, w, h, fill=True)

        # Kenarlık
        c.setStrokeColor(HexColor("#6366F1"))
        c.setLineWidth(3)
        c.rect(20, 20, w - 40, h - 40)
        c.setLineWidth(1)
        c.rect(30, 30, w - 60, h - 60)

        # Köşe süslemeleri
        for cx, cy in [(50, h - 50), (w - 50, h - 50), (50, 50), (w - 50, 50)]:
            c.setFillColor(HexColor("#6366F1"))
            c.circle(cx, cy, 8, fill=True)

        # Başlık
        c.setFillColor(HexColor("#6366F1"))
        c.setFont("Helvetica-Bold", 36)
        c.drawCentredString(w / 2, h - 100, "BASARI SERTIFIKASI")

        # Alt başlık
        c.setFont("Helvetica", 14)
        c.setFillColor(HexColor("#94a3b8"))
        c.drawCentredString(w / 2, h - 130, "SmartCampusAI - Premium AI Ders Asistani")

        # Çizgi
        c.setStrokeColor(HexColor("#6366F1"))
        c.setLineWidth(2)
        c.line(100, h - 145, w - 100, h - 145)

        # İsim
        c.setFillColor(HexColor("#e2e8f0"))
        c.setFont("Helvetica", 14)
        c.drawCentredString(w / 2, h - 180, "Bu sertifika")

        c.setFillColor(HexColor("#6366F1"))
        c.setFont("Helvetica-Bold", 28)
        c.drawCentredString(w / 2, h - 215, student_name.upper())

        c.setFillColor(HexColor("#e2e8f0"))
        c.setFont("Helvetica", 14)
        c.drawCentredString(w / 2, h - 245,
                            f"adli ogrenciye {ders} dersinde")

        # Konu
        c.setFillColor(HexColor("#3b82f6"))
        c.setFont("Helvetica-Bold", 18)
        c.drawCentredString(w / 2, h - 280, f'"{topic}"')

        c.setFillColor(HexColor("#e2e8f0"))
        c.setFont("Helvetica", 14)
        c.drawCentredString(w / 2, h - 310,
                            "konusunu basariyla tamamladigi icin verilmistir.")

        # Puan
        score_color = "#22c55e" if score >= 80 else "#f59e0b" if score >= 60 else "#ef4444"
        c.setFillColor(HexColor(score_color))
        c.setFont("Helvetica-Bold", 24)
        c.drawCentredString(w / 2, h - 360, f"Puan: {int(score)}/100")

        # Tarih
        if not date_str:
            date_str = datetime.now().strftime("%d.%m.%Y")
        c.setFillColor(HexColor("#94a3b8"))
        c.setFont("Helvetica", 12)
        c.drawCentredString(w / 2, 70, f"Tarih: {date_str}")

        # Alt çizgi
        c.setStrokeColor(HexColor("#6366F1"))
        c.setLineWidth(1)
        c.line(100, 55, w - 100, 55)
        c.setFillColor(HexColor("#64748b"))
        c.setFont("Helvetica", 9)
        c.drawCentredString(w / 2, 40, "SmartCampusAI | smartcampus.ai")

        c.save()
        return buf.getvalue()
    except ImportError:
        _logger.error("ReportLab yuklu degil — sertifika uretilemedi")
        return None
    except Exception as e:
        _logger.error(f"Sertifika PDF: {e}")
        return None


def render_certificate(ders: str, topic: str, score: float, kp: str):
    """Sertifika UI — isim gir, PDF indir."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F3C5 Ders Sonu Sertifika</span></div>',
        unsafe_allow_html=True,
    )

    if score < 60:
        st.warning("Sertifika almak için en az 60 puan gerekiyor.")
        return

    student_name = st.text_input("Adınız Soyadınız:", key=f"{kp}_cert_name",
                                  placeholder="Sertifika üzerinde görünecek isim")

    if student_name and st.button("\U0001F4C4 Sertifika Oluştur", key=f"{kp}_cert_gen",
                                   type="primary"):
        pdf_bytes = generate_certificate_pdf(student_name, ders, topic, score)
        if pdf_bytes:
            st.download_button(
                "\u2B07\uFE0F PDF İndir",
                data=pdf_bytes,
                file_name=f"sertifika_{ders}_{datetime.now().strftime('%Y%m%d')}.pdf",
                mime="application/pdf",
                key=f"{kp}_cert_dl",
            )
            st.success("Sertifika oluşturuldu! PDF'i indirin.")
        else:
            st.error("Sertifika oluşturulamadı.")


# ════════════════════════════════════════════════════════════
# A6 — HATA DEFTERİ (Mistake Journal)
# ════════════════════════════════════════════════════════════
def _mistakes_path():
    return os.path.join(_data_dir(), "mistakes.json")

def _load_mistakes() -> list:
    p = _mistakes_path()
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            pass
    return []

def _save_mistakes(data: list):
    with open(_mistakes_path(), "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def record_mistakes(quiz_data: list, answers: dict, ders: str, topic: str):
    """Quiz sonuçlarından yanlış cevapları Hata Defteri'ne kaydet."""
    mistakes = _load_mistakes()
    existing = {(m["question"], m["ders"]) for m in mistakes}
    added = 0
    for i, q in enumerate(quiz_data[:5]):
        user_ans = answers.get(i, -1)
        correct = q.get("correct", 0)
        if user_ans != correct and user_ans >= 0:
            qtext = q.get("question", "")
            if (qtext, ders) not in existing:
                mistakes.append({
                    "question": qtext,
                    "options": q.get("options", []),
                    "correct": correct,
                    "user_answer": user_ans,
                    "explanation": q.get("explanation", ""),
                    "ders": ders,
                    "topic": topic,
                    "date": datetime.now().strftime("%Y-%m-%d %H:%M"),
                    "reviewed": False,
                    "review_count": 0,
                })
                added += 1
    if added:
        _save_mistakes(mistakes)
    return added

def render_mistake_journal(ders: str, kp: str):
    """Hata Defteri UI — yanlış yapılan soruları göster ve tekrar çöz."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4D3 Hata Defteri</span>'
        '<span style="color:#475569;font-size:.8rem;margin-left:8px">'
        'Yanlış yaptığın soruları tekrar çöz</span></div>',
        unsafe_allow_html=True,
    )

    mistakes = _load_mistakes()
    ders_mistakes = [m for m in mistakes if m.get("ders") == ders]

    if not ders_mistakes:
        st.info("Henüz hata kaydı yok. Quiz çözdükçe yanlışların burada birikecek.")
        return

    # İstatistikler
    total = len(ders_mistakes)
    reviewed = len([m for m in ders_mistakes if m.get("reviewed")])
    topics_set = set(m.get("topic", "") for m in ders_mistakes)
    weak_topic = max(topics_set, key=lambda t: len([m for m in ders_mistakes if m.get("topic") == t]))

    sc1, sc2, sc3 = st.columns(3)
    with sc1:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(239,68,68,0.3);border-radius:10px;'
            f'padding:10px;text-align:center">'
            f'<div style="color:#ef4444;font-size:1.5rem;font-weight:800">{total}</div>'
            f'<div style="color:#64748b;font-size:.75rem">Toplam Hata</div></div>',
            unsafe_allow_html=True)
    with sc2:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(34,197,94,0.3);border-radius:10px;'
            f'padding:10px;text-align:center">'
            f'<div style="color:#22c55e;font-size:1.5rem;font-weight:800">{reviewed}</div>'
            f'<div style="color:#64748b;font-size:.75rem">Gözden Geçirilen</div></div>',
            unsafe_allow_html=True)
    with sc3:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(245,158,11,0.3);border-radius:10px;'
            f'padding:10px;text-align:center">'
            f'<div style="color:#f59e0b;font-size:.85rem;font-weight:700">{weak_topic[:20]}</div>'
            f'<div style="color:#64748b;font-size:.75rem">En Zayıf Konu</div></div>',
            unsafe_allow_html=True)

    # Hataları listele
    for i, m in enumerate(ders_mistakes[:15]):
        icon = "\u2705" if m.get("reviewed") else "\u274C"
        opts = m.get("options", [])
        correct_text = opts[m["correct"]] if m["correct"] < len(opts) else "?"
        user_text = opts[m["user_answer"]] if m["user_answer"] < len(opts) else "?"
        st.markdown(
            f'<div style="border-left:3px solid {"#22c55e" if m.get("reviewed") else "#ef4444"};'
            f'background:#f0f9ff;border-radius:0 8px 8px 0;padding:10px 12px;margin:4px 0">'
            f'<div style="color:#1e293b;font-weight:600;font-size:.9rem">'
            f'{icon} {m.get("question","")}</div>'
            f'<div style="font-size:.8rem;margin-top:4px">'
            f'<span style="color:#ef4444">Senin: {user_text}</span> | '
            f'<span style="color:#22c55e">Doğru: {correct_text}</span></div>'
            f'<div style="color:#475569;font-size:.75rem;margin-top:2px">'
            f'{m.get("explanation","")}</div>'
            f'<div style="color:#64748b;font-size:.7rem">'
            f'{m.get("topic","")} | {m.get("date","")}</div></div>',
            unsafe_allow_html=True,
        )

    # Gözden geçir butonu
    unreviewed = [m for m in ders_mistakes if not m.get("reviewed")]
    if unreviewed:
        def _mark_reviewed():
            all_m = _load_mistakes()
            for m in all_m:
                if m.get("ders") == ders:
                    m["reviewed"] = True
                    m["review_count"] = m.get("review_count", 0) + 1
            _save_mistakes(all_m)
        st.button(f"\u2705 Tümünü Gözden Geçirildi İşaretle ({len(unreviewed)})",
                  key=f"{kp}_mist_mark", use_container_width=True,
                  type="primary", on_click=_mark_reviewed)


# ════════════════════════════════════════════════════════════
# A7 — GÜNLÜK MEYDAN OKUMA (Daily Challenge)
# ════════════════════════════════════════════════════════════
def _daily_challenge_path():
    return os.path.join(_data_dir(), "daily_challenges.json")

def _load_daily() -> dict:
    p = _daily_challenge_path()
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            pass
    return {"challenges": [], "streak": 0, "last_date": ""}

def _save_daily(data: dict):
    with open(_daily_challenge_path(), "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def render_daily_challenge(ders: str, seviye: str, kp: str):
    """Günlük Meydan Okuma — her gün yeni quiz."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F525 Günlük Meydan Okuma</span>'
        '<span style="color:#475569;font-size:.8rem;margin-left:8px">'
        'Her gün 3 soru çöz, seriyi koru!</span></div>',
        unsafe_allow_html=True,
    )

    daily = _load_daily()
    today = datetime.now().strftime("%Y-%m-%d")
    yesterday = (datetime.now() - timedelta(days=1)).strftime("%Y-%m-%d")

    # Streak hesapla
    streak = daily.get("streak", 0)
    last = daily.get("last_date", "")
    if last == today:
        pass  # Bugün zaten çözülmüş
    elif last == yesterday:
        pass  # Streak devam ediyor
    elif last != "":
        streak = 0  # Streak kırıldı

    # Streak göster
    st.markdown(
        f'<div style="display:flex;gap:12px;justify-content:center;margin-bottom:12px">'
        f'<div style="background:#f0f9ff;border:1px solid #93c5fd;border-radius:10px;'
        f'padding:10px 20px;text-align:center">'
        f'<div style="color:#f59e0b;font-size:1.8rem;font-weight:800">{streak}</div>'
        f'<div style="color:#64748b;font-size:.75rem">Gün Serisi</div></div>'
        f'<div style="background:#f0f9ff;border:1px solid rgba(34,197,94,0.3);border-radius:10px;'
        f'padding:10px 20px;text-align:center">'
        f'<div style="color:#22c55e;font-size:1.8rem;font-weight:800">'
        f'{len(daily.get("challenges",[]))}</div>'
        f'<div style="color:#64748b;font-size:.75rem">Tamamlanan</div></div></div>',
        unsafe_allow_html=True,
    )

    # Bugünkü challenge zaten çözüldü mü?
    today_done = any(c.get("date") == today for c in daily.get("challenges", []))
    if today_done:
        st.success("Bugünkü meydan okumayı tamamladın! Yarın tekrar gel.")
        # Son sonucu göster
        last_ch = [c for c in daily["challenges"] if c.get("date") == today]
        if last_ch:
            ch = last_ch[-1]
            st.markdown(
                f'<div style="background:#f0f9ff;border:1px solid rgba(34,197,94,0.3);'
                f'border-radius:10px;padding:12px;text-align:center">'
                f'<div style="color:#22c55e;font-weight:700">Bugünkü Sonuç: '
                f'{ch.get("score",0)}/3 doğru</div></div>',
                unsafe_allow_html=True)
        return

    # Günlük challenge üret
    gen_key = f"{kp}_daily_gen"
    data_key = f"{kp}_daily_data"

    if st.session_state.get(gen_key):
        with st.spinner("Günlük meydan okuma hazırlanıyor..."):
            client = _get_client()
            if client:
                try:
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"Sen {ders} ogretmenisin. Seviye: {seviye}. "
                             "3 tane coktan secmeli soru uret. Zorluk: orta-zor. "
                             "JSON formatinda dondur: "
                             '{"questions":[{"question":"...","options":["A","B","C","D"],'
                             '"correct":0,"explanation":"..."}]}'},
                            {"role": "user", "content":
                             f"Gunluk meydan okuma icin {ders} dersi {seviye} seviye 3 soru uret."},
                        ],
                        max_tokens=1000, temperature=0.8,
                        response_format={"type": "json_object"},
                    )
                    result = json.loads(resp.choices[0].message.content)
                    st.session_state[data_key] = result.get("questions", [])[:3]
                except Exception as e:
                    st.error(f"Soru üretilemedi: {e}")
            st.session_state[gen_key] = False
            st.rerun()

    if data_key not in st.session_state:
        def _start_daily():
            st.session_state[gen_key] = True
        st.button("\U0001F3AF Bugünkü Meydan Okumayı Başlat!",
                  key=f"{kp}_daily_start", use_container_width=True,
                  type="primary", on_click=_start_daily)
        return

    # Soruları göster
    questions = st.session_state[data_key]
    answers = {}
    for i, q in enumerate(questions[:3]):
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid #bae6fd;'
            f'border-radius:10px;padding:10px 14px;margin-bottom:6px">'
            f'<div style="color:#0c4a6e;font-weight:700">Soru {i+1}/3</div>'
            f'<div style="color:#1e293b;font-size:.95rem">{q.get("question","")}</div></div>',
            unsafe_allow_html=True)
        opts = q.get("options", [])
        if opts:
            sel = st.radio(f"Cevap:", opts, key=f"{kp}_daily_q{i}",
                           index=None, label_visibility="collapsed")
            if sel is not None:
                answers[i] = opts.index(sel) if sel in opts else -1

    submitted = st.session_state.get(f"{kp}_daily_submitted", False)
    if not submitted:
        def _submit_daily():
            st.session_state[f"{kp}_daily_submitted"] = True
            st.session_state[f"{kp}_daily_answers"] = answers
        st.button("\u2705 Gönder!", key=f"{kp}_daily_submit",
                  use_container_width=True, type="primary", on_click=_submit_daily)
    else:
        answers = st.session_state.get(f"{kp}_daily_answers", answers)
        correct = 0
        for i, q in enumerate(questions[:3]):
            is_correct = answers.get(i, -1) == q.get("correct", 0)
            if is_correct:
                correct += 1
            icon = "\u2705" if is_correct else "\u274C"
            st.markdown(
                f'<div style="border-left:3px solid {"#22c55e" if is_correct else "#ef4444"};'
                f'padding:4px 10px;margin:2px 0;border-radius:0 6px 6px 0;'
                f'background:{"rgba(34,197,94,0.05)" if is_correct else "rgba(239,68,68,0.05)"}">'
                f'{icon} <span style="color:#475569;font-size:.85rem">'
                f'{q.get("explanation","")}</span></div>',
                unsafe_allow_html=True)

        # Sonucu kaydet
        if not any(c.get("date") == today for c in daily.get("challenges", [])):
            if last == yesterday or last == "":
                daily["streak"] = daily.get("streak", 0) + 1
            elif last != today:
                daily["streak"] = 1
            daily["last_date"] = today
            daily["challenges"].append({
                "date": today, "ders": ders, "score": correct,
            })
            _save_daily(daily)

        st.markdown(
            f'<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
            f'border:2px solid {"#22c55e" if correct>=2 else "#f59e0b"};'
            f'border-radius:12px;padding:14px;text-align:center;margin:8px 0">'
            f'<div style="font-size:1.5rem;font-weight:900;'
            f'color:{"#22c55e" if correct>=2 else "#f59e0b"}">{correct}/3</div>'
            f'<div style="color:#475569">{"Harika!" if correct==3 else "İyi!" if correct>=2 else "Tekrar dene!"}</div></div>',
            unsafe_allow_html=True)


# ════════════════════════════════════════════════════════════
# A8 — KONU HARİTASI (Knowledge Map) — Legacy (see enhanced version above)
# ════════════════════════════════════════════════════════════
def _render_knowledge_map_legacy(ders: str, kp: str):
    """Eski versiyon — artik render_knowledge_map kullanilir."""
    import streamlit.components.v1 as components

    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F5FA\uFE0F Konu Haritası</span>'
        '<span style="color:#475569;font-size:.8rem;margin-left:8px">'
        'Öğrendiğin konuların ilişki ağı</span></div>',
        unsafe_allow_html=True,
    )

    prog = load_progress()
    gd = prog.get(ders, {})
    topics = gd.get("topics", {})

    if not topics:
        st.info("Henüz tamamlanmış ders yok. Ders tamamladıkça harita dolacak.")
        return

    # Konuları node'lara dönüştür
    nodes_json = []
    for i, (topic, data) in enumerate(topics.items()):
        score = data.get("quiz_score", 0)
        color = "#22c55e" if score >= 80 else "#f59e0b" if score >= 60 else "#ef4444" if score > 0 else "#64748b"
        nodes_json.append({
            "id": i, "label": topic[:25], "score": score,
            "color": color, "date": data.get("date", ""),
        })
    nodes_js = json.dumps(nodes_json, ensure_ascii=False)

    map_html = f"""<!DOCTYPE html><html><head><meta charset="utf-8">
    <style>body{{margin:0;background:#f0f9ff;overflow:hidden}}canvas{{display:block}}</style>
    </head><body><canvas id="c"></canvas>
    <script>
    var cv=document.getElementById('c');cv.width=560;cv.height=400;
    var c=cv.getContext('2d'),W=cv.width,H=cv.height;
    var nodes={nodes_js};
    var cx=W/2,cy=H/2;
    // Pozisyon hesapla (dairesel yerleşim)
    var n=nodes.length;
    for(var i=0;i<n;i++){{
      var a=2*Math.PI*i/n-Math.PI/2;
      var r=Math.min(W,H)*0.35;
      nodes[i].x=cx+r*Math.cos(a);nodes[i].y=cy+r*Math.sin(a);
      nodes[i].vx=0;nodes[i].vy=0;
    }}
    var hovered=-1,dragging=-1;
    function draw(){{
      c.fillStyle='#0B0F19';c.fillRect(0,0,W,H);
      // Grid
      c.strokeStyle='rgba(148,163,184,0.03)';
      for(var i=0;i<W;i+=40){{c.beginPath();c.moveTo(i,0);c.lineTo(i,H);c.stroke();}}
      for(var i=0;i<H;i+=40){{c.beginPath();c.moveTo(0,i);c.lineTo(W,i);c.stroke();}}
      // Bağlantılar (sıralı konular arası)
      for(var i=0;i<n-1;i++){{
        c.strokeStyle='rgba(148,163,184,0.15)';c.lineWidth=1;
        c.beginPath();c.moveTo(nodes[i].x,nodes[i].y);
        c.lineTo(nodes[i+1].x,nodes[i+1].y);c.stroke();
      }}
      // Merkez node
      c.fillStyle='rgba(212,175,55,0.1)';c.beginPath();c.arc(cx,cy,25,0,Math.PI*2);c.fill();
      c.fillStyle='#6366F1';c.font='bold 11px system-ui';c.textAlign='center';c.textBaseline='middle';
      c.fillText('{ders}',cx,cy);
      // Merkeze bağlantılar
      for(var i=0;i<n;i++){{
        c.strokeStyle='rgba(212,175,55,0.1)';c.lineWidth=1;
        c.beginPath();c.moveTo(cx,cy);c.lineTo(nodes[i].x,nodes[i].y);c.stroke();
      }}
      // Node'lar
      for(var i=0;i<n;i++){{
        var nd=nodes[i],r=hovered===i?22:16;
        c.fillStyle=nd.color+'33';c.beginPath();c.arc(nd.x,nd.y,r+4,0,Math.PI*2);c.fill();
        c.fillStyle=nd.color;c.beginPath();c.arc(nd.x,nd.y,r,0,Math.PI*2);c.fill();
        c.strokeStyle='#fff';c.lineWidth=1.5;c.stroke();
        c.fillStyle='#fff';c.font=(hovered===i?'bold 10px':'9px')+' system-ui';
        c.fillText(nd.label,nd.x,nd.y+r+14);
        c.fillStyle='#fff';c.font='bold 10px system-ui';
        c.fillText(nd.score>0?nd.score+'%':'?',nd.x,nd.y+3);
      }}
      // Hover info
      if(hovered>=0){{
        var h=nodes[hovered];
        c.fillStyle='rgba(15,23,42,0.9)';c.fillRect(10,H-50,200,40);
        c.strokeStyle='#6366F1';c.lineWidth=1;c.strokeRect(10,H-50,200,40);
        c.fillStyle='#e2e8f0';c.font='12px system-ui';c.textAlign='left';
        c.fillText(h.label,18,H-32);
        c.fillStyle='#94a3b8';c.font='10px system-ui';
        c.fillText('Puan: '+h.score+'% | '+h.date,18,H-18);
      }}
      requestAnimationFrame(draw);
    }}
    cv.addEventListener('mousemove',function(e){{
      var r=cv.getBoundingClientRect();var mx=e.clientX-r.left,my=e.clientY-r.top;
      hovered=-1;
      for(var i=0;i<n;i++)if(Math.hypot(mx-nodes[i].x,my-nodes[i].y)<20)hovered=i;
      if(dragging>=0){{nodes[dragging].x=mx;nodes[dragging].y=my;}}
    }});
    cv.addEventListener('mousedown',function(e){{
      var r=cv.getBoundingClientRect();var mx=e.clientX-r.left,my=e.clientY-r.top;
      for(var i=0;i<n;i++)if(Math.hypot(mx-nodes[i].x,my-nodes[i].y)<20)dragging=i;
    }});
    cv.addEventListener('mouseup',function(){{dragging=-1;}});
    draw();
    </script></body></html>"""
    components.html(map_html, height=420, scrolling=False)

    # Renk açıklaması
    st.markdown(
        '<div style="display:flex;gap:12px;justify-content:center;margin-top:4px">'
        '<span style="color:#22c55e;font-size:.75rem">\u25CF 80%+</span>'
        '<span style="color:#f59e0b;font-size:.75rem">\u25CF 60-79%</span>'
        '<span style="color:#ef4444;font-size:.75rem">\u25CF <60%</span>'
        '<span style="color:#64748b;font-size:.75rem">\u25CF Quiz yok</span></div>',
        unsafe_allow_html=True)


# ════════════════════════════════════════════════════════════
# A9 — SINAV HAZIRLIK MODU (LGS/TYT/AYT)
# ════════════════════════════════════════════════════════════
def render_exam_prep(ders: str, seviye: str, kp: str):
    """LGS/TYT/AYT formatında zamanlı deneme sınavı."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4DD Sınav Hazırlık Modu</span></div>',
        unsafe_allow_html=True,
    )

    exam_types = {
        "Ortaokul": ["LGS Denemesi (10 Soru / 15 dk)"],
        "Lise": ["TYT Denemesi (10 Soru / 15 dk)", "AYT Denemesi (10 Soru / 20 dk)"],
    }
    kademe = "Lise" if seviye in ("Lise", "Üniversite") else "Ortaokul"
    options = exam_types.get(kademe, exam_types["Lise"])
    selected = st.selectbox("Sınav Türü:", options, key=f"{kp}_exam_type")

    is_ayt = "AYT" in selected
    q_count = 10
    time_min = 20 if is_ayt else 15

    gen_key = f"{kp}_exam_gen"
    data_key = f"{kp}_exam_data"
    start_key = f"{kp}_exam_start"

    if st.session_state.get(gen_key):
        with st.spinner(f"{selected} hazırlanıyor..."):
            client = _get_client()
            if client:
                try:
                    diff = "zor, analitik, yorum gerektiren" if is_ayt else "orta zorluk, MEB müfredatı"
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"Sen {ders} sinav hazirlayicisisin. {selected} icin "
                             f"{q_count} coktan secmeli soru uret. Zorluk: {diff}. "
                             f"Seviye: {seviye}. JSON formatinda dondur: "
                             '{"questions":[{"question":"...","options":["A","B","C","D"],'
                             '"correct":0,"explanation":"..."}]}'},
                            {"role": "user", "content": f"{ders} dersi {selected} formatında {q_count} soru"},
                        ],
                        max_tokens=2500, temperature=0.7,
                        response_format={"type": "json_object"},
                    )
                    result = json.loads(resp.choices[0].message.content)
                    st.session_state[data_key] = result.get("questions", [])[:q_count]
                    st.session_state[start_key] = time.time()
                except Exception as e:
                    st.error(f"Sınav üretilemedi: {e}")
            st.session_state[gen_key] = False
            st.rerun()

    if data_key not in st.session_state:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(59,130,246,0.3);'
            f'border-radius:10px;padding:14px;text-align:center">'
            f'<div style="color:#3b82f6;font-size:1rem">'
            f'{q_count} Soru | {time_min} Dakika</div>'
            f'<div style="color:#475569;font-size:.85rem;margin-top:4px">'
            f'Gerçek sınav formatında zamanlı deneme</div></div>',
            unsafe_allow_html=True)
        def _start_exam():
            st.session_state[gen_key] = True
        st.button("\U0001F680 Sınava Başla!", key=f"{kp}_exam_start_btn",
                  use_container_width=True, type="primary", on_click=_start_exam)
        return

    questions = st.session_state[data_key]
    start_time = st.session_state.get(start_key, time.time())
    elapsed = time.time() - start_time
    remaining = max(0, time_min * 60 - elapsed)

    # Zamanlayıcı
    rem_min = int(remaining // 60)
    rem_sec = int(remaining % 60)
    timer_color = "#22c55e" if remaining > 300 else "#f59e0b" if remaining > 60 else "#ef4444"
    st.markdown(
        f'<div style="background:#f0f9ff;border:2px solid {timer_color};border-radius:10px;'
        f'padding:8px;text-align:center;margin-bottom:10px">'
        f'<span style="color:{timer_color};font-size:1.3rem;font-weight:800;font-family:monospace">'
        f'\u23F1 {rem_min:02d}:{rem_sec:02d}</span>'
        f'<span style="color:#64748b;font-size:.8rem;margin-left:8px">kalan süre</span></div>',
        unsafe_allow_html=True)

    # Sorular
    answers = {}
    for i, q in enumerate(questions):
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(212,175,55,0.15);'
            f'border-radius:8px;padding:8px 12px;margin-bottom:4px">'
            f'<span style="color:#0c4a6e;font-weight:700">{i+1}.</span> '
            f'<span style="color:#1e293b;font-size:.9rem">{q.get("question","")}</span></div>',
            unsafe_allow_html=True)
        opts = q.get("options", [])
        if opts:
            sel = st.radio(f"Cevap:", opts, key=f"{kp}_exam_q{i}",
                           index=None, label_visibility="collapsed")
            if sel is not None:
                answers[i] = opts.index(sel) if sel in opts else -1

    submitted = st.session_state.get(f"{kp}_exam_submitted", False)
    if not submitted:
        def _submit_exam():
            st.session_state[f"{kp}_exam_submitted"] = True
            st.session_state[f"{kp}_exam_answers"] = answers
        st.button("\u2705 Sınavı Bitir", key=f"{kp}_exam_submit",
                  use_container_width=True, type="primary", on_click=_submit_exam)
    else:
        answers = st.session_state.get(f"{kp}_exam_answers", answers)
        correct = sum(1 for i, q in enumerate(questions) if answers.get(i, -1) == q.get("correct", 0))
        net = correct - (len(questions) - correct) * 0.25  # 4 yanlış 1 doğruyu götürür
        score = max(0, (correct / max(len(questions), 1)) * 100)

        for i, q in enumerate(questions):
            is_correct = answers.get(i, -1) == q.get("correct", 0)
            icon = "\u2705" if is_correct else "\u274C"
            st.markdown(
                f'<div style="border-left:3px solid {"#22c55e" if is_correct else "#ef4444"};'
                f'padding:3px 8px;margin:2px 0;font-size:.8rem">'
                f'{icon} S{i+1}: {q.get("explanation","")}</div>',
                unsafe_allow_html=True)

        elapsed_min = elapsed / 60
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
            f'border:2px solid #6366F1;border-radius:12px;padding:16px;text-align:center;margin:10px 0">'
            f'<div style="color:#0c4a6e;font-size:1.8rem;font-weight:900">'
            f'{correct}/{len(questions)}</div>'
            f'<div style="color:#475569">Net: {net:.1f} | Süre: {elapsed_min:.1f} dk</div></div>',
            unsafe_allow_html=True)

        def _new_exam():
            for k in [data_key, start_key, gen_key,
                      f"{kp}_exam_submitted", f"{kp}_exam_answers"]:
                st.session_state.pop(k, None)
            for i in range(20):
                st.session_state.pop(f"{kp}_exam_q{i}", None)
        st.button("\U0001F504 Yeni Sınav", key=f"{kp}_exam_new",
                  use_container_width=True, on_click=_new_exam)


# ════════════════════════════════════════════════════════════
# A10 — PDF DERS NOTU EXPORT
# ════════════════════════════════════════════════════════════
def generate_lesson_pdf(lesson_data: dict, ders: str, topic: str) -> bytes | None:
    """Ders içeriğini formatlı PDF olarak export et — Türkçe karakter destekli."""
    try:
        from reportlab.lib.pagesizes import A4
        from reportlab.lib.colors import HexColor
        from reportlab.pdfgen import canvas as pdf_canvas
        from reportlab.pdfbase import pdfmetrics
        from reportlab.pdfbase.ttfonts import TTFont
        import io, os

        # ── Türkçe destekli font kayıt ──
        _font_dir = "C:/Windows/Fonts"
        _fn = "TRFont"
        _fnb = "TRFontB"
        _fni = "TRFontI"
        if _fn not in pdfmetrics.getRegisteredFontNames():
            pdfmetrics.registerFont(TTFont(_fn, os.path.join(_font_dir, "arial.ttf")))
            pdfmetrics.registerFont(TTFont(_fnb, os.path.join(_font_dir, "arialbd.ttf")))
            pdfmetrics.registerFont(TTFont(_fni, os.path.join(_font_dir, "ariali.ttf")))

        buf = io.BytesIO()
        w, h = A4
        c = pdf_canvas.Canvas(buf, pagesize=A4)

        # ── Başlık sayfası ──
        c.setFillColor(HexColor("#0B0F19"))
        c.rect(0, h - 80, w, 80, fill=True)
        c.setFillColor(HexColor("#6366F1"))
        c.setFont(_fnb, 20)
        title = lesson_data.get("title", topic)[:60]
        c.drawCentredString(w / 2, h - 40, title)
        c.setFillColor(HexColor("#94a3b8"))
        c.setFont(_fn, 11)
        c.drawCentredString(w / 2, h - 60, f"{ders} | {datetime.now().strftime('%d.%m.%Y')}")

        # ── Yardımcı satır sarma ──
        def _wrap_draw(txt, x, _y, font, size, max_w):
            c.setFont(font, size)
            words = txt.split()
            line = ""
            for word in words:
                test = line + " " + word if line else word
                if c.stringWidth(test, font, size) < max_w:
                    line = test
                else:
                    c.drawString(x, _y, line)
                    _y -= line_height
                    if _y < 80:
                        c.showPage()
                        _y = h - 40
                        c.setFont(font, size)
                    line = word
            if line:
                c.drawString(x, _y, line)
                _y -= line_height
            return _y

        # ── İçerik ──
        y = h - 110
        line_height = 16

        for sec in lesson_data.get("sections", []):
            if y < 80:
                c.showPage()
                y = h - 40

            stype = sec.get("type", "text")
            if stype == "header":
                c.setFillColor(HexColor("#1e40af"))
                c.setFont(_fnb, 14)
                c.drawString(40, y, sec.get("text", ""))
                y -= 8
                c.setStrokeColor(HexColor("#6366F1"))
                c.setLineWidth(1)
                c.line(40, y, w - 40, y)
                y -= line_height
            elif stype == "text":
                c.setFillColor(HexColor("#1e293b"))
                y = _wrap_draw(sec.get("content", ""), 40, y, _fn, 10, w - 80)
            elif stype == "formula":
                c.setFillColor(HexColor("#7c3aed"))
                c.setFont(_fnb, 12)
                c.drawString(60, y, f"  {sec.get('formula', '')}")
                y -= line_height
                if sec.get("explanation"):
                    c.setFillColor(HexColor("#64748b"))
                    c.setFont(_fn, 9)
                    c.drawString(60, y, f"  {sec['explanation']}")
                    y -= line_height
            elif stype == "example":
                c.setFillColor(HexColor("#059669"))
                c.setFont(_fnb, 10)
                c.drawString(40, y, f"Örnek: {sec.get('label', '')}")
                y -= line_height
                c.setFillColor(HexColor("#334155"))
                y = _wrap_draw(sec.get("content", ""), 50, y, _fn, 10, w - 90)
            elif stype == "tip":
                c.setFillColor(HexColor("#f59e0b"))
                c.setFont(_fnb, 10)
                c.drawString(40, y, f"İpucu: {sec.get('content', '')[:100]}")
                y -= line_height
            elif stype == "story":
                c.setFillColor(HexColor("#7c3aed"))
                c.setFont(_fnb, 10)
                c.drawString(40, y, f"Hikâye: {sec.get('title', '')}")
                y -= line_height
                c.setFillColor(HexColor("#334155"))
                y = _wrap_draw(sec.get("content", ""), 50, y, _fni, 10, w - 100)
            elif stype == "curiosity":
                c.setFillColor(HexColor("#d97706"))
                c.setFont(_fnb, 10)
                c.drawString(40, y, f"Biliyor musun? {sec.get('content', '')[:100]}")
                y -= line_height
            elif stype == "analogy":
                c.setFillColor(HexColor("#0891b2"))
                c.setFont(_fnb, 10)
                src = sec.get("source", "")
                tgt = sec.get("target", "")
                c.drawString(40, y, f"Benzetme: {src} → {tgt}")
                y -= line_height
                c.setFillColor(HexColor("#334155"))
                y = _wrap_draw(sec.get("content", ""), 50, y, _fn, 10, w - 90)
            elif stype == "challenge":
                c.setFillColor(HexColor("#dc2626"))
                c.setFont(_fnb, 10)
                c.drawString(40, y, f"Düşün: {sec.get('question', '')[:90]}")
                y -= line_height
                if sec.get("answer"):
                    c.setFillColor(HexColor("#059669"))
                    c.setFont(_fn, 9)
                    c.drawString(50, y, f"Cevap: {sec['answer'][:90]}")
                    y -= line_height
            elif stype == "mistake":
                c.setFillColor(HexColor("#dc2626"))
                c.setFont(_fnb, 10)
                c.drawString(40, y, f"Yanlış: {sec.get('wrong', '')[:80]}")
                y -= line_height
                c.setFillColor(HexColor("#059669"))
                c.setFont(_fnb, 10)
                c.drawString(40, y, f"Doğru: {sec.get('correct', '')[:80]}")
                y -= line_height
            elif stype == "mnemonic":
                c.setFillColor(HexColor("#db2777"))
                c.setFont(_fnb, 10)
                tech = sec.get("technique", "")
                c.drawString(40, y, f"Hafıza Tekniği [{tech}]: {sec.get('content', '')[:80]}")
                y -= line_height
                if sec.get("remember"):
                    c.setFillColor(HexColor("#ec4899"))
                    c.setFont(_fnb, 11)
                    c.drawString(50, y, f"Hatırla: {sec['remember'][:80]}")
                    y -= line_height
            elif stype == "recap":
                c.setFillColor(HexColor("#0284c7"))
                c.setFont(_fnb, 11)
                c.drawString(40, y, sec.get("title", "Ara Özet"))
                y -= line_height
                c.setFillColor(HexColor("#334155"))
                c.setFont(_fn, 10)
                for pi, pt in enumerate(sec.get("points", [])[:5]):
                    c.drawString(50, y, f"  {pi+1}. {pt[:85]}")
                    y -= line_height
                    if y < 80:
                        c.showPage()
                        y = h - 40
            elif stype == "real_question":
                c.setFillColor(HexColor("#7c3aed"))
                c.setFont(_fni, 10)
                c.drawString(40, y, f"Öğrenci: {sec.get('student', '')[:80]}")
                y -= line_height
                c.setFillColor(HexColor("#334155"))
                c.setFont(_fn, 10)
                c.drawString(40, y, f"Cevap: {sec.get('answer', '')[:90]}")
                y -= line_height
            elif stype == "timeline":
                c.setFillColor(HexColor("#ea580c"))
                c.setFont(_fnb, 11)
                c.drawString(40, y, f"⏳ {sec.get('title', 'Zaman Çizelgesi')}")
                y -= line_height
                for ev in sec.get("events", [])[:8]:
                    if y < 80:
                        c.showPage()
                        y = h - 40
                    c.setFillColor(HexColor("#ea580c"))
                    c.setFont(_fnb, 10)
                    c.drawString(50, y, f"● {ev.get('date', '')} — {ev.get('title', '')}")
                    y -= line_height
                    if ev.get("description"):
                        c.setFillColor(HexColor("#64748b"))
                        c.setFont(_fn, 9)
                        y = _wrap_draw(ev["description"], 65, y, _fn, 9, w - 110)
            elif stype == "simulation":
                c.setFillColor(HexColor("#059669"))
                c.setFont(_fnb, 11)
                c.drawString(40, y, f"🧪 {sec.get('title', 'Simülasyon')}")
                y -= line_height
                if sec.get("formula"):
                    c.setFillColor(HexColor("#059669"))
                    c.setFont(_fnb, 10)
                    c.drawString(50, y, f"Formül: {sec['formula']}")
                    y -= line_height
                c.setFillColor(HexColor("#334155"))
                y = _wrap_draw(f"Değişken: {sec.get('variable', '')} ({sec.get('min', 0)}-{sec.get('max', 100)} {sec.get('unit', '')})", 50, y, _fn, 10, w - 90)
                if sec.get("effect"):
                    y = _wrap_draw(f"Etki: {sec['effect']}", 50, y, _fn, 9, w - 90)
                for step in sec.get("steps", [])[:5]:
                    c.setFillColor(HexColor("#64748b"))
                    c.setFont(_fn, 9)
                    c.drawString(55, y, f"• {step[:85]}")
                    y -= line_height
                    if y < 80:
                        c.showPage()
                        y = h - 40
            elif stype == "concept_map":
                c.setFillColor(HexColor("#7c3aed"))
                c.setFont(_fnb, 11)
                c.drawString(40, y, f"🗺️ {sec.get('title', 'Kavram Haritası')}")
                y -= line_height
                c.setFillColor(HexColor("#7c3aed"))
                c.setFont(_fnb, 12)
                c.drawCentredString(w / 2, y, f"[ {sec.get('central', 'Merkez')} ]")
                y -= line_height + 4
                for node in sec.get("nodes", [])[:8]:
                    if y < 80:
                        c.showPage()
                        y = h - 40
                    c.setFillColor(HexColor("#6d28d9"))
                    c.setFont(_fnb, 10)
                    c.drawString(60, y, f"→ {node.get('label', '')}")
                    if node.get("detail"):
                        c.setFillColor(HexColor("#64748b"))
                        c.setFont(_fn, 9)
                        c.drawString(180, y, f"— {node['detail'][:60]}")
                    y -= line_height
            elif stype == "real_world":
                c.setFillColor(HexColor("#0284c7"))
                c.setFont(_fnb, 11)
                c.drawString(40, y, f"🌍 {sec.get('title', 'Gerçek Hayat Bağlantısı')}")
                y -= line_height
                if sec.get("context"):
                    c.setFillColor(HexColor("#0369a1"))
                    c.setFont(_fni, 10)
                    y = _wrap_draw(sec["context"], 50, y, _fni, 10, w - 90)
                for ex in sec.get("examples", [])[:4]:
                    if y < 80:
                        c.showPage()
                        y = h - 40
                    c.setFillColor(HexColor("#0284c7"))
                    c.setFont(_fnb, 10)
                    c.drawString(50, y, f"▶ {ex.get('area', '')}")
                    y -= line_height
                    c.setFillColor(HexColor("#334155"))
                    y = _wrap_draw(ex.get("description", ""), 60, y, _fn, 9, w - 100)
                if sec.get("takeaway"):
                    c.setFillColor(HexColor("#0284c7"))
                    c.setFont(_fnb, 10)
                    y = _wrap_draw(f"Sonuç: {sec['takeaway']}", 50, y, _fnb, 10, w - 90)
            elif stype == "speed_round":
                c.setFillColor(HexColor("#dc2626"))
                c.setFont(_fnb, 11)
                c.drawString(40, y, f"⚡ {sec.get('title', 'Hız Turu')}")
                y -= line_height
                for qi, sq in enumerate(sec.get("questions", [])[:8]):
                    if y < 80:
                        c.showPage()
                        y = h - 40
                    c.setFillColor(HexColor("#dc2626"))
                    c.setFont(_fnb, 10)
                    c.drawString(50, y, f"{qi+1}. {sq.get('q', '')[:80]}")
                    y -= line_height
                    c.setFillColor(HexColor("#059669"))
                    c.setFont(_fn, 9)
                    c.drawString(60, y, f"Cevap: {sq.get('a', '')[:80]}")
                    y -= line_height
            elif stype == "dialogue":
                c.setFillColor(HexColor("#6366F1"))
                c.setFont(_fnb, 10)
                c.drawString(40, y, sec.get("title", "Diyalog"))
                y -= line_height
                for line in sec.get("lines", [])[:6]:
                    if y < 80:
                        c.showPage()
                        y = h - 40
                    c.setFillColor(HexColor("#334155"))
                    c.setFont(_fnb if "gretmen" in line.get("speaker", "") or "Hoca" in line.get("speaker", "") else _fn, 10)
                    c.drawString(50, y, f"{line.get('speaker', '')}: {line.get('text', '')[:80]}")
                    y -= line_height
            elif stype == "inline_quiz":
                c.setFillColor(HexColor("#2563eb"))
                c.setFont(_fnb, 10)
                c.drawString(40, y, f"Mini Test: {sec.get('question', '')[:80]}")
                y -= line_height
                for oi, opt in enumerate(sec.get("options", [])[:4]):
                    marker = "✓" if oi == sec.get("correct", 0) else " "
                    c.setFillColor(HexColor("#059669") if oi == sec.get("correct", 0) else HexColor("#334155"))
                    c.setFont(_fn, 9)
                    c.drawString(55, y, f"  {marker} {chr(65+oi)}) {opt[:70]}")
                    y -= line_height
                    if y < 80:
                        c.showPage()
                        y = h - 40

            y -= 4

        # ── Özet ──
        summary = lesson_data.get("summary", [])
        if summary:
            if y < 120:
                c.showPage()
                y = h - 40
            y -= 10
            c.setFillColor(HexColor("#1e40af"))
            c.setFont(_fnb, 13)
            c.drawString(40, y, "Ders Özeti")
            y -= line_height
            c.setFillColor(HexColor("#334155"))
            c.setFont(_fn, 10)
            for i, p in enumerate(summary[:5]):
                c.drawString(50, y, f"{i + 1}. {p[:90]}")
                y -= line_height

        # ── Footer ──
        c.setFillColor(HexColor("#94a3b8"))
        c.setFont(_fn, 8)
        c.drawCentredString(w / 2, 20, "SmartCampusAI Premium AI Ders Asistanı")

        c.save()
        return buf.getvalue()
    except ImportError:
        _logger.error("ReportLab yüklü değil")
        return None
    except Exception as e:
        _logger.error(f"Lesson PDF: {e}")
        return None


def render_lesson_pdf_export(lesson_data: dict, ders: str, topic: str, kp: str):
    """PDF Ders Notu Export UI."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4C4 PDF Ders Notu</span></div>',
        unsafe_allow_html=True,
    )

    if st.button("\U0001F4E5 PDF Oluştur", key=f"{kp}_pdf_gen", type="primary"):
        pdf_bytes = generate_lesson_pdf(lesson_data, ders, topic)
        if pdf_bytes:
            st.download_button(
                "\u2B07\uFE0F PDF İndir",
                data=pdf_bytes,
                file_name=f"ders_notu_{ders}_{datetime.now().strftime('%Y%m%d')}.pdf",
                mime="application/pdf",
                key=f"{kp}_pdf_dl",
            )
        else:
            st.error("PDF oluşturulamadı.")


# ════════════════════════════════════════════════════════════
# A11 — SESLİ ALTYAZI MODU (Karaoke Sync)
# ════════════════════════════════════════════════════════════
def render_karaoke_mode(lesson_data: dict, tts_b64: str | None, kp: str):
    """Karaoke tarzı altyazılı ders izleme."""
    import streamlit.components.v1 as components

    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F3A4 Sesli Altyazı (Karaoke)</span></div>',
        unsafe_allow_html=True,
    )

    tts_text = lesson_data.get("tts_text", "")
    if not tts_text:
        st.info("Bu ders için TTS metni bulunamadı.")
        return

    # Cümlelere böl
    sentences = [s.strip() for s in tts_text.replace(". ", ".|").split("|") if s.strip()]
    sentences_js = json.dumps(sentences, ensure_ascii=False)
    audio_src = f"data:audio/mp3;base64,{tts_b64}" if tts_b64 else ""

    karaoke_html = f"""<!DOCTYPE html><html><head><meta charset="utf-8">
    <style>
    body{{margin:0;background:#f0f9ff;font-family:system-ui;padding:16px}}
    .sub-container{{background:#e2e8f0;border:2px solid rgba(212,175,55,0.3);border-radius:16px;
      padding:24px;text-align:center;min-height:200px;display:flex;flex-direction:column;
      align-items:center;justify-content:center}}
    .prev-line{{color:#64748b;font-size:.9rem;margin:4px 0;transition:all 0.3s}}
    .current-line{{color:#0c4a6e;font-size:1.3rem;font-weight:700;margin:8px 0;
      text-shadow:0 0 20px rgba(212,175,55,0.3);transition:all 0.3s}}
    .next-line{{color:#475569;font-size:.9rem;margin:4px 0;transition:all 0.3s}}
    .controls{{margin-top:16px;display:flex;gap:8px;justify-content:center}}
    .cb{{background:#e2e8f0;color:#0c4a6e;border:1px solid #93c5fd;
      border-radius:8px;padding:6px 16px;cursor:pointer;font-size:.85rem;font-weight:600}}
    .cb:hover{{background:#334155}}
    .progress{{width:100%;height:4px;background:#334155;border-radius:2px;margin-top:12px}}
    .progress-fill{{height:100%;background:linear-gradient(90deg,#6366F1,#f59e0b);border-radius:2px;
      transition:width 0.3s}}
    </style></head><body>
    <div class="sub-container">
      <div id="prevLine" class="prev-line"></div>
      <div id="currentLine" class="current-line">Başlamak için oynat tuşuna basın</div>
      <div id="nextLine" class="next-line"></div>
    </div>
    <div class="progress"><div id="progFill" class="progress-fill" style="width:0%"></div></div>
    <div class="controls">
      <button class="cb" onclick="toggleKaraoke()" id="kBtn">▶ Başlat</button>
      <button class="cb" onclick="prevSentence()">⏮ Geri</button>
      <button class="cb" onclick="nextSentence()">⏭ İleri</button>
    </div>
    <audio id="kAud"><source src="{audio_src}" type="audio/mpeg"></audio>
    <script>
    var sentences={sentences_js};
    var idx=0,playing=false;
    var aud=document.getElementById('kAud');
    var synth=window.speechSynthesis||null;
    function showLine(i){{
      idx=Math.max(0,Math.min(i,sentences.length-1));
      document.getElementById('prevLine').textContent=idx>0?sentences[idx-1]:'';
      document.getElementById('currentLine').textContent=sentences[idx];
      document.getElementById('nextLine').textContent=idx<sentences.length-1?sentences[idx+1]:'';
      document.getElementById('progFill').style.width=((idx+1)/sentences.length*100)+'%';
    }}
    function speakLine(i){{
      if(i>=sentences.length){{playing=false;document.getElementById('kBtn').textContent='▶ Başlat';return;}}
      showLine(i);
      if(synth){{
        var u=new SpeechSynthesisUtterance(sentences[i]);u.lang='tr-TR';u.rate=0.9;
        u.onend=function(){{if(playing)speakLine(i+1);}};synth.speak(u);
      }}else{{setTimeout(function(){{if(playing)speakLine(i+1);}},3000);}}
    }}
    function toggleKaraoke(){{
      if(playing){{playing=false;if(synth)synth.cancel();
        document.getElementById('kBtn').textContent='▶ Devam';
      }}else{{playing=true;document.getElementById('kBtn').textContent='⏸ Duraklat';
        speakLine(idx);}}
    }}
    function nextSentence(){{if(idx<sentences.length-1){{if(synth)synth.cancel();showLine(idx+1);if(playing)speakLine(idx);}};}}
    function prevSentence(){{if(idx>0){{if(synth)synth.cancel();showLine(idx-1);if(playing)speakLine(idx);}};}}
    showLine(0);
    </script></body></html>"""
    components.html(karaoke_html, height=340, scrolling=False)


