# A12 — ÇOKLU DERS KARŞILAŞTIRMA
# ════════════════════════════════════════════════════════════
def render_lesson_comparison(kp: str):
    """İki ders/konuyu yan yana karşılaştır."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F504 Çoklu Ders Karşılaştırma</span></div>',
        unsafe_allow_html=True,
    )

    # Kayıtlı dersleri yükle
    all_lessons = load_saved_lessons()
    if len(all_lessons) < 2:
        st.info("Karşılaştırma için en az 2 tamamlanmış ders gerekiyor.")
        return

    options = [f"{l.get('ders','')} - {l.get('topic','')[:40]} ({l.get('date','')})"
               for l in all_lessons]

    c1, c2 = st.columns(2)
    with c1:
        sel1 = st.selectbox("1. Ders:", options, key=f"{kp}_cmp1")
    with c2:
        sel2 = st.selectbox("2. Ders:", options, key=f"{kp}_cmp2", index=min(1, len(options) - 1))

    if sel1 == sel2:
        st.warning("Farklı dersler seçin.")
        return

    idx1 = options.index(sel1)
    idx2 = options.index(sel2)
    l1 = all_lessons[idx1].get("lesson", {})
    l2 = all_lessons[idx2].get("lesson", {})

    # Yan yana karşılaştırma
    cc1, cc2 = st.columns(2)
    for col, lesson, label in [(cc1, l1, sel1), (cc2, l2, sel2)]:
        with col:
            st.markdown(
                f'<div style="background:#f0f9ff;border:1px solid #bae6fd;'
                f'border-radius:10px;padding:10px;margin-bottom:8px">'
                f'<div style="color:#0c4a6e;font-weight:700;font-size:.85rem">'
                f'{lesson.get("title","")}</div></div>',
                unsafe_allow_html=True)

            # Özet noktaları
            for p in lesson.get("summary", [])[:5]:
                st.markdown(
                    f'<div style="color:#1e293b;font-size:.8rem;border-left:2px solid #3b82f6;'
                    f'padding:2px 8px;margin:3px 0">{p}</div>',
                    unsafe_allow_html=True)

            # Kavramlar
            vocab = lesson.get("vocabulary", [])
            if vocab:
                terms = ", ".join(v.get("term", "") for v in vocab[:6])
                st.markdown(
                    f'<div style="color:#475569;font-size:.75rem;margin-top:6px">'
                    f'Kavramlar: {terms}</div>',
                    unsafe_allow_html=True)


