# B13 — CONFETTİ + SES EFEKTLERİ
# ════════════════════════════════════════════════════════════
def render_confetti(score: float = 100):
    """Başarı kutlaması — confetti + ses efekti."""
    import streamlit.components.v1 as components
    if score < 60:
        return
    color1 = "#6366F1" if score >= 80 else "#f59e0b"
    confetti_html = f"""
    <div id="confetti-container" style="position:fixed;top:0;left:0;width:100%;height:100%;
    pointer-events:none;z-index:9999;overflow:hidden"></div>
    <script>
    (function(){{
      var container=document.getElementById('confetti-container');
      var colors=['{color1}','#22c55e','#3b82f6','#ef4444','#a855f7','#ec4899','#f97316'];
      for(var i=0;i<80;i++){{
        var c=document.createElement('div');
        var size=Math.random()*10+5;
        c.style.cssText='position:absolute;width:'+size+'px;height:'+size+'px;'+
          'background:'+colors[Math.floor(Math.random()*colors.length)]+';'+
          'left:'+Math.random()*100+'%;top:-20px;'+
          'border-radius:'+(Math.random()>0.5?'50%':'2px')+';'+
          'animation:confettiFall '+(Math.random()*3+2)+'s ease-out '+(Math.random()*1)+'s forwards;'+
          'transform:rotate('+Math.random()*360+'deg)';
        container.appendChild(c);
      }}
      var style=document.createElement('style');
      style.textContent='@keyframes confettiFall{{0%{{opacity:1;top:-20px;transform:rotate(0deg) translateX(0)}}'+
        '100%{{opacity:0;top:100%;transform:rotate(720deg) translateX('+(Math.random()*200-100)+'px)}}}}';
      document.head.appendChild(style);
      // Ses efekti (kısa bip)
      try{{
        var ac=new(window.AudioContext||window.webkitAudioContext)();
        var osc=ac.createOscillator();var gain=ac.createGain();
        osc.connect(gain);gain.connect(ac.destination);
        osc.frequency.value=880;osc.type='sine';gain.gain.value=0.1;
        osc.start();osc.stop(ac.currentTime+0.15);
        setTimeout(function(){{
          var o2=ac.createOscillator();var g2=ac.createGain();
          o2.connect(g2);g2.connect(ac.destination);
          o2.frequency.value=1318;o2.type='sine';g2.gain.value=0.1;
          o2.start();o2.stop(ac.currentTime+0.2);
        }},150);
      }}catch(e){{}}
      setTimeout(function(){{container.remove();}},5000);
    }})();
    </script>"""
    components.html(confetti_html, height=0)


