# B14 — DERS YER İMİ (Bookmark)
# ════════════════════════════════════════════════════════════
def _bookmarks_path():
    return os.path.join(_data_dir(), "bookmarks.json")

def _load_bookmarks() -> list:
    p = _bookmarks_path()
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            pass
    return []

def _save_bookmarks(data: list):
    with open(_bookmarks_path(), "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def render_bookmarks(lesson_data: dict, ders: str, topic: str, kp: str):
    """Ders içeriğinden bölüm yer imi kaydet."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F516 Yer İmleri</span></div>',
        unsafe_allow_html=True,
    )

    bookmarks = _load_bookmarks()
    sections = lesson_data.get("sections", [])

    # Mevcut yer imlerini göster
    my_bm = [b for b in bookmarks if b.get("ders") == ders and b.get("topic") == topic]
    if my_bm:
        for bm in my_bm:
            st.markdown(
                f'<div style="border-left:3px solid #6366F1;background:#f0f9ff;'
                f'border-radius:0 8px 8px 0;padding:6px 10px;margin:3px 0">'
                f'<div style="color:#0c4a6e;font-weight:600;font-size:.85rem">'
                f'\U0001F516 {bm.get("section_title","")}</div>'
                f'<div style="color:#475569;font-size:.75rem">{bm.get("note","")}</div>'
                f'<div style="color:#64748b;font-size:.7rem">{bm.get("date","")}</div></div>',
                unsafe_allow_html=True)

    # Yeni yer imi ekle
    section_titles = []
    for s in sections:
        t = s.get("text", s.get("content", s.get("title", "")))[:60]
        if t:
            section_titles.append(f"[{s.get('type','')}] {t}")
    if section_titles:
        sel_sec = st.selectbox("Bölüm seçin:", section_titles, key=f"{kp}_bm_sec")
        note = st.text_input("Not (opsiyonel):", key=f"{kp}_bm_note",
                              placeholder="Bu bölüm hakkında kısa not...")

        def _add_bm():
            bms = _load_bookmarks()
            bms.append({
                "ders": ders, "topic": topic,
                "section_title": sel_sec[:80],
                "note": note[:200],
                "date": datetime.now().strftime("%Y-%m-%d %H:%M"),
            })
            _save_bookmarks(bms)
        st.button("\U0001F516 Yer İmi Ekle", key=f"{kp}_bm_add",
                  use_container_width=True, on_click=_add_bm)


