# B16 — AI MNEMONİK ÜRETİCİ
# ════════════════════════════════════════════════════════════
def render_mnemonic_generator(lesson_data: dict, ders: str, kp: str):
    """AI ile akrostiş, hikaye, çağrışım gibi hafıza teknikleri üret."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F9E0 AI Mnemonik Üretici</span>'
        '<span style="color:#475569;font-size:.8rem;margin-left:8px">'
        'Hafıza teknikleri ile kolay ezberle</span></div>',
        unsafe_allow_html=True,
    )

    vocab = lesson_data.get("vocabulary", [])
    terms = [v.get("term", "") for v in vocab if v.get("term")]
    summary = lesson_data.get("summary", [])

    # Ezberlenecek konuyu göster
    if terms:
        st.markdown(
            f'<div style="color:#475569;font-size:.85rem;margin-bottom:8px">'
            f'Kavramlar: {", ".join(terms[:8])}</div>',
            unsafe_allow_html=True)

    gen_key = f"{kp}_mnem_gen"
    result_key = f"{kp}_mnem_result"

    if st.session_state.get(gen_key):
        with st.spinner("AI hafıza teknikleri üretiyor..."):
            client = _get_client()
            if client:
                try:
                    content = f"Kavramlar: {', '.join(terms[:8])}\nÖzet: {'; '.join(summary[:3])}"
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"Sen {ders} dersi icin hafiza teknikleri ureten bir uzmansin. "
                             "Asagidaki kavram/bilgileri kolayca ezberlemek icin 3 farkli teknik uret:\n"
                             "1. AKROSTIS: Kavramlarin bas harflerinden anlamli bir cumle\n"
                             "2. HIKAYE: Kavramlari bir hikayeye yerlestir (2-3 cumle)\n"
                             "3. CAGRISIM: Her kavram icin gorsel/sesli bir cagrisim\n"
                             "Turkce yaz. Kisa ve akilda kalici ol."},
                            {"role": "user", "content": content},
                        ],
                        max_tokens=500, temperature=0.8,
                    )
                    st.session_state[result_key] = resp.choices[0].message.content
                except Exception as e:
                    st.session_state[result_key] = f"Hata: {e}"
            st.session_state[gen_key] = False
            st.rerun()

    if result_key in st.session_state:
        result = st.session_state[result_key]
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(34,197,94,0.3);'
            f'border-radius:12px;padding:14px">'
            f'<div style="color:#1e293b;font-size:.9rem;white-space:pre-wrap;line-height:1.6">'
            f'{result}</div></div>',
            unsafe_allow_html=True)
    else:
        def _gen_mnem():
            st.session_state[gen_key] = True
        st.button("\U0001F9E0 Hafıza Teknikleri Üret",
                  key=f"{kp}_mnem_btn", use_container_width=True,
                  type="primary", on_click=_gen_mnem,
                  disabled=not terms)


