# B17 — HAFTALIK RAPOR
# ════════════════════════════════════════════════════════════
def render_weekly_report(ders: str, kp: str):
    """Haftalık ilerleme raporu."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4CA Haftalık Rapor</span></div>',
        unsafe_allow_html=True,
    )

    prog = load_progress()
    gd = prog.get(ders, {})
    topics = gd.get("topics", {})

    if not topics:
        st.info("Henüz veri yok.")
        return

    # Son 7 gün
    today = datetime.now()
    week_data = {}
    for i in range(7):
        day = (today - timedelta(days=6 - i)).strftime("%Y-%m-%d")
        day_label = (today - timedelta(days=6 - i)).strftime("%d/%m")
        week_data[day] = {"label": day_label, "count": 0, "avg_score": 0, "scores": []}

    for topic, data in topics.items():
        d = data.get("date", "")
        if d in week_data:
            week_data[d]["count"] += 1
            if data.get("quiz_score", 0) > 0:
                week_data[d]["scores"].append(data["quiz_score"])

    for d in week_data.values():
        if d["scores"]:
            d["avg_score"] = sum(d["scores"]) / len(d["scores"])

    # Haftalık özet kartları
    total_week = sum(d["count"] for d in week_data.values())
    all_scores = [s for d in week_data.values() for s in d["scores"]]
    avg_week = sum(all_scores) / len(all_scores) if all_scores else 0

    sc1, sc2, sc3 = st.columns(3)
    with sc1:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(59,130,246,0.3);border-radius:10px;'
            f'padding:10px;text-align:center">'
            f'<div style="color:#3b82f6;font-size:1.5rem;font-weight:800">{total_week}</div>'
            f'<div style="color:#64748b;font-size:.75rem">Bu Hafta Ders</div></div>',
            unsafe_allow_html=True)
    with sc2:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(34,197,94,0.3);border-radius:10px;'
            f'padding:10px;text-align:center">'
            f'<div style="color:#22c55e;font-size:1.5rem;font-weight:800">{avg_week:.0f}%</div>'
            f'<div style="color:#64748b;font-size:.75rem">Ortalama Puan</div></div>',
            unsafe_allow_html=True)
    with sc3:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid #93c5fd;border-radius:10px;'
            f'padding:10px;text-align:center">'
            f'<div style="color:#0c4a6e;font-size:1.5rem;font-weight:800">{gd.get("streak",0)}</div>'
            f'<div style="color:#64748b;font-size:.75rem">Gün Serisi</div></div>',
            unsafe_allow_html=True)

    # Günlük bar chart
    import streamlit.components.v1 as components
    bars_js = json.dumps([{"label": d["label"], "count": d["count"],
                           "score": d["avg_score"]} for d in week_data.values()],
                          ensure_ascii=False)
    chart_html = f"""<!DOCTYPE html><html><head><meta charset="utf-8">
    <style>body{{margin:0;background:#f0f9ff}}</style></head><body>
    <canvas id="c" width="560" height="180"></canvas>
    <script>
    var cv=document.getElementById('c'),c=cv.getContext('2d'),W=cv.width,H=cv.height;
    var data={bars_js};
    c.fillStyle='#0B0F19';c.fillRect(0,0,W,H);
    var bw=50,gap=20,sx=(W-data.length*(bw+gap))/2+gap/2;
    var maxC=Math.max(1,...data.map(d=>d.count));
    for(var i=0;i<data.length;i++){{
      var x=sx+i*(bw+gap),bh=data[i].count/maxC*(H-50);
      var y=H-30-bh;
      var grad=c.createLinearGradient(x,y,x,H-30);
      grad.addColorStop(0,'#3b82f6');grad.addColorStop(1,'#1e40af');
      c.fillStyle=grad;c.fillRect(x,y,bw,bh);
      c.fillStyle='#e2e8f0';c.font='bold 11px system-ui';c.textAlign='center';
      if(data[i].count>0)c.fillText(data[i].count,x+bw/2,y-6);
      c.fillStyle='#94a3b8';c.font='10px system-ui';
      c.fillText(data[i].label,x+bw/2,H-14);
    }}
    c.fillStyle='#64748b';c.font='10px system-ui';c.textAlign='left';
    c.fillText('Gunluk ders sayisi',8,14);
    </script></body></html>"""
    components.html(chart_html, height=190, scrolling=False)


