# B18 — TEMA SEÇİMİ (3 Tema)
# ════════════════════════════════════════════════════════════
THEMES = {
    "gold_navy": {
        "name": "Gold & Navy (Varsayılan)",
        "bg": "#0B0F19", "card": "#1e293b", "accent": "#6366F1",
        "text": "#e2e8f0", "sub": "#94a3b8", "border": "rgba(212,175,55,0.3)",
    },
    "neon_dark": {
        "name": "Neon & Dark",
        "bg": "#0a0a0a", "card": "#1a1a1a", "accent": "#00ff88",
        "text": "#f0f0f0", "sub": "#888888", "border": "rgba(0,255,136,0.3)",
    },
    "pastel_light": {
        "name": "Pastel & Light",
        "bg": "#111827", "card": "#ffffff", "accent": "#6366f1",
        "text": "#1e293b", "sub": "#64748b", "border": "rgba(99,102,241,0.3)",
    },
}

def _theme_path():
    return os.path.join(_data_dir(), "theme.json")

def get_current_theme() -> dict:
    p = _theme_path()
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                key = json.load(f).get("theme", "gold_navy")
                return THEMES.get(key, THEMES["gold_navy"])
        except Exception:
            pass
    return THEMES["gold_navy"]

def render_theme_selector(kp: str):
    """Tema seçim UI."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F3A8 Tema Seçimi</span></div>',
        unsafe_allow_html=True,
    )

    current_theme = get_current_theme()
    current = next((k for k, v in THEMES.items() if v == current_theme), "gold_navy")

    cols = st.columns(3)
    for i, (key, theme) in enumerate(THEMES.items()):
        with cols[i]:
            is_active = key == current
            border = f"3px solid {theme['accent']}" if is_active else f"1px solid {theme['border']}"
            st.markdown(
                f'<div style="background:{theme["bg"]};border:{border};border-radius:12px;'
                f'padding:14px;text-align:center;min-height:100px">'
                f'<div style="color:{theme["accent"]};font-weight:700;font-size:.9rem">'
                f'{theme["name"]}</div>'
                f'<div style="display:flex;gap:4px;justify-content:center;margin-top:8px">'
                f'<div style="width:20px;height:20px;border-radius:50%;background:{theme["bg"]};'
                f'border:1px solid {theme["sub"]}"></div>'
                f'<div style="width:20px;height:20px;border-radius:50%;background:{theme["accent"]}"></div>'
                f'<div style="width:20px;height:20px;border-radius:50%;background:{theme["card"]};'
                f'border:1px solid {theme["sub"]}"></div></div>'
                + (f'<div style="color:{theme["accent"]};font-size:.7rem;margin-top:6px">'
                   f'\u2705 Aktif</div>' if is_active else '')
                + '</div>',
                unsafe_allow_html=True)

            def _set_theme(k=key):
                with open(_theme_path(), "w", encoding="utf-8") as f:
                    json.dump({"theme": k}, f)
            st.button(
                "\u2705 Seçili" if is_active else "Seç",
                key=f"{kp}_theme_{key}",
                use_container_width=True,
                disabled=is_active,
                on_click=_set_theme,
            )


# ════════════════════════════════════════════════════════════
# T1 — AI ÖZEL DERS PLANI
# ════════════════════════════════════════════════════════════
def _study_plan_path():
    return os.path.join(_data_dir(), "study_plans.json")

def render_ai_study_plan(ders: str, seviye: str, kp: str):
    """Öğrencinin zayıf/güçlü konularını analiz edip haftalık plan oluştur."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4CB AI Özel Ders Planı</span>'
        '<span style="color:#475569;font-size:.8rem;margin-left:8px">'
        'Sana özel haftalık çalışma planı</span></div>',
        unsafe_allow_html=True,
    )

    prog = load_progress()
    gd = prog.get(ders, {})
    topics = gd.get("topics", {})

    # Zayıf/güçlü analiz
    weak = [t for t, d in topics.items() if d.get("quiz_score", 0) < 60]
    mid = [t for t, d in topics.items() if 60 <= d.get("quiz_score", 0) < 80]
    strong = [t for t, d in topics.items() if d.get("quiz_score", 0) >= 80]

    sc1, sc2, sc3 = st.columns(3)
    with sc1:
        st.markdown(f'<div style="background:#f0f9ff;border:1px solid #ef4444;border-radius:10px;'
                    f'padding:10px;text-align:center"><div style="color:#ef4444;font-size:1.5rem;'
                    f'font-weight:800">{len(weak)}</div><div style="color:#64748b;font-size:.75rem">'
                    f'Zayıf Konu</div></div>', unsafe_allow_html=True)
    with sc2:
        st.markdown(f'<div style="background:#f0f9ff;border:1px solid #f59e0b;border-radius:10px;'
                    f'padding:10px;text-align:center"><div style="color:#f59e0b;font-size:1.5rem;'
                    f'font-weight:800">{len(mid)}</div><div style="color:#64748b;font-size:.75rem">'
                    f'Orta Konu</div></div>', unsafe_allow_html=True)
    with sc3:
        st.markdown(f'<div style="background:#f0f9ff;border:1px solid #22c55e;border-radius:10px;'
                    f'padding:10px;text-align:center"><div style="color:#22c55e;font-size:1.5rem;'
                    f'font-weight:800">{len(strong)}</div><div style="color:#64748b;font-size:.75rem">'
                    f'Güçlü Konu</div></div>', unsafe_allow_html=True)

    gen_key = f"{kp}_plan_gen"
    result_key = f"{kp}_plan_result"

    if st.session_state.get(gen_key):
        with st.spinner("AI ders planı hazırlıyor..."):
            client = _get_client()
            if client:
                try:
                    ctx = (f"Zayıf konular (<60): {', '.join(weak[:5]) or 'Yok'}\n"
                           f"Orta konular (60-79): {', '.join(mid[:5]) or 'Yok'}\n"
                           f"Güçlü konular (80+): {', '.join(strong[:5]) or 'Yok'}")
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"Sen {ders} dersi icin kisisel ders plani hazirlayan bir uzmansin. "
                             f"Seviye: {seviye}. Ogrencinin durumuna gore 7 gunluk plan hazirla. "
                             "Zayif konulara oncelik ver. Her gun icin 1-2 aktivite (ders tekrari, "
                             "quiz, pratik). Turkce yaz. Kisa ve net ol."},
                            {"role": "user", "content": ctx},
                        ],
                        max_tokens=600, temperature=0.7,
                    )
                    plan_text = resp.choices[0].message.content
                    st.session_state[result_key] = plan_text
                    # Persist study plan to disk
                    try:
                        sp_path = _study_plan_path()
                        existing = []
                        if os.path.exists(sp_path):
                            with open(sp_path, "r", encoding="utf-8") as _f:
                                existing = json.load(_f)
                        existing.append({"ders": ders, "seviye": seviye, "plan": plan_text,
                                         "timestamp": time.time()})
                        with open(sp_path, "w", encoding="utf-8") as _f:
                            json.dump(existing, _f, ensure_ascii=False, indent=2)
                    except Exception:
                        pass
                except Exception as e:
                    st.session_state[result_key] = f"Hata: {e}"
            st.session_state[gen_key] = False
            st.rerun()

    if result_key in st.session_state:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(34,197,94,0.3);'
            f'border-radius:12px;padding:14px"><div style="color:#1e293b;font-size:.9rem;'
            f'white-space:pre-wrap;line-height:1.6">{st.session_state[result_key]}</div></div>',
            unsafe_allow_html=True)
        def _new_plan():
            st.session_state.pop(result_key, None)
        st.button("\U0001F504 Yeni Plan Oluştur", key=f"{kp}_plan_new", on_click=_new_plan)
    else:
        def _gen_plan():
            st.session_state[gen_key] = True
        st.button("\U0001F680 Haftalık Plan Oluştur", key=f"{kp}_plan_btn",
                  use_container_width=True, type="primary", on_click=_gen_plan)


# ════════════════════════════════════════════════════════════
# T2 — CANLI WHITEBOARD
# ════════════════════════════════════════════════════════════
def render_whiteboard(kp: str):
    """İnteraktif çizim tahtası — kalem, silgi, renkler, temizle."""
    import streamlit.components.v1 as components
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F58C\uFE0F Canlı Whiteboard</span></div>',
        unsafe_allow_html=True,
    )
    wb_html = """<!DOCTYPE html><html><head><meta charset="utf-8"><style>
    body{margin:0;background:#f0f9ff;font-family:system-ui}
    canvas{display:block;margin:0 auto;border-radius:12px;cursor:crosshair;background:#fff}
    .tb{display:flex;gap:6px;justify-content:center;padding:8px;flex-wrap:wrap}
    .tb button{background:#e2e8f0;color:#1e293b;border:1px solid #93c5fd;
      border-radius:8px;padding:5px 12px;cursor:pointer;font-size:.8rem;font-weight:600}
    .tb button:hover{background:#334155}
    .tb button.active{border-color:#0c4a6e;color:#0c4a6e}
    .cs{width:24px;height:24px;border-radius:50%;border:2px solid transparent;cursor:pointer}
    .cs.sel{border-color:#0c4a6e;transform:scale(1.2)}
    </style></head><body>
    <div class="tb">
      <button onclick="setTool('pen')" id="tPen" class="active">✏️ Kalem</button>
      <button onclick="setTool('eraser')" id="tEraser">🧹 Silgi</button>
      <button onclick="setTool('line')" id="tLine">📏 Çizgi</button>
      <button onclick="setTool('rect')" id="tRect">⬜ Dikdörtgen</button>
      <button onclick="setTool('circle')" id="tCircle">⭕ Daire</button>
      <button onclick="clearBoard()">🗑️ Temizle</button>
      <button onclick="undoLast()">↩️ Geri Al</button>
      <input type="range" min="1" max="20" value="3" oninput="lineW=+this.value"
        style="width:80px;accent-color:#0c4a6e" title="Kalınlık">
    </div>
    <div class="tb">
      <div class="cs sel" style="background:#000" onclick="setColor('#000',this)"></div>
      <div class="cs" style="background:#ef4444" onclick="setColor('#ef4444',this)"></div>
      <div class="cs" style="background:#3b82f6" onclick="setColor('#3b82f6',this)"></div>
      <div class="cs" style="background:#22c55e" onclick="setColor('#22c55e',this)"></div>
      <div class="cs" style="background:#f59e0b" onclick="setColor('#f59e0b',this)"></div>
      <div class="cs" style="background:#a855f7" onclick="setColor('#a855f7',this)"></div>
      <div class="cs" style="background:#ec4899" onclick="setColor('#ec4899',this)"></div>
      <div class="cs" style="background:#fff;border-color:#ccc" onclick="setColor('#ffffff',this)"></div>
    </div>
    <canvas id="wb" width="560" height="380"></canvas>
    <script>
    var cv=document.getElementById('wb'),c=cv.getContext('2d'),drawing=false;
    var tool='pen',color='#000',lineW=3,startX,startY;
    var history=[],snapshot;
    function saveSnap(){history.push(cv.toDataURL());if(history.length>30)history.shift();}
    function undoLast(){if(history.length>0){var img=new Image();img.onload=function(){
      c.clearRect(0,0,cv.width,cv.height);c.drawImage(img,0,0);};img.src=history.pop();}}
    function setTool(t){tool=t;['tPen','tEraser','tLine','tRect','tCircle'].forEach(function(id){
      var el=document.getElementById(id);if(el)el.className=id.replace('t','').toLowerCase()===t?'active':'';});}
    function setColor(col,el){color=col;document.querySelectorAll('.cs').forEach(function(e){e.className='cs';});
      if(el)el.className='cs sel';}
    function clearBoard(){saveSnap();c.fillStyle='#fff';c.fillRect(0,0,cv.width,cv.height);}
    c.fillStyle='#fff';c.fillRect(0,0,cv.width,cv.height);
    cv.addEventListener('mousedown',function(e){
      drawing=true;var r=cv.getBoundingClientRect();
      startX=e.clientX-r.left;startY=e.clientY-r.top;
      if(tool==='pen'||tool==='eraser'){saveSnap();c.beginPath();c.moveTo(startX,startY);}
      else{snapshot=c.getImageData(0,0,cv.width,cv.height);saveSnap();}
    });
    cv.addEventListener('mousemove',function(e){
      if(!drawing)return;var r=cv.getBoundingClientRect();
      var mx=e.clientX-r.left,my=e.clientY-r.top;
      if(tool==='pen'){c.strokeStyle=color;c.lineWidth=lineW;c.lineCap='round';
        c.lineTo(mx,my);c.stroke();}
      else if(tool==='eraser'){c.strokeStyle='#fff';c.lineWidth=lineW*3;c.lineCap='round';
        c.lineTo(mx,my);c.stroke();}
      else if(snapshot){c.putImageData(snapshot,0,0);c.strokeStyle=color;c.lineWidth=lineW;
        if(tool==='line'){c.beginPath();c.moveTo(startX,startY);c.lineTo(mx,my);c.stroke();}
        else if(tool==='rect'){c.strokeRect(startX,startY,mx-startX,my-startY);}
        else if(tool==='circle'){var rx=Math.abs(mx-startX)/2,ry=Math.abs(my-startY)/2;
          c.beginPath();c.ellipse(startX+rx*(mx>startX?1:-1),startY+ry*(my>startY?1:-1),
          rx,ry,0,0,Math.PI*2);c.stroke();}}
    });
    cv.addEventListener('mouseup',function(){drawing=false;c.beginPath();});
    cv.addEventListener('mouseleave',function(){drawing=false;c.beginPath();});
    </script></body></html>"""
    components.html(wb_html, height=480, scrolling=False)


# ════════════════════════════════════════════════════════════
# T3 — ARKADAŞLA YARIŞ (PvP Quiz)
# ════════════════════════════════════════════════════════════
def _pvp_path():
    return os.path.join(_data_dir(), "pvp_sessions.json")

def render_pvp_quiz(ders: str, seviye: str, kp: str):
    """İki öğrenci aynı quiz'i çözer — skor karşılaştırma."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\u2694\uFE0F Arkadaşla Yarış</span></div>',
        unsafe_allow_html=True,
    )

    p1 = st.text_input("Oyuncu 1 Adı:", key=f"{kp}_pvp_p1", placeholder="Senin adın")
    p2 = st.text_input("Oyuncu 2 Adı:", key=f"{kp}_pvp_p2", placeholder="Arkadaşının adı")

    gen_key = f"{kp}_pvp_gen"
    data_key = f"{kp}_pvp_data"
    turn_key = f"{kp}_pvp_turn"  # 1 or 2

    if st.session_state.get(gen_key):
        with st.spinner("Yarış soruları hazırlanıyor..."):
            client = _get_client()
            if client:
                try:
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"{ders} dersi {seviye} seviye 5 coktan secmeli soru uret. "
                             'JSON: {{"questions":[{{"question":"...","options":["A","B","C","D"],'
                             '"correct":0}}]}}'},
                            {"role": "user", "content": f"{ders} yarış soruları"},
                        ],
                        max_tokens=1200, temperature=0.8,
                        response_format={"type": "json_object"},
                    )
                    result = json.loads(resp.choices[0].message.content)
                    st.session_state[data_key] = result.get("questions", [])[:5]
                    st.session_state[turn_key] = 1
                except Exception:
                    pass
            st.session_state[gen_key] = False
            st.rerun()

    if data_key not in st.session_state:
        def _start_pvp():
            st.session_state[gen_key] = True
        st.button("\U0001F3AE Yarışı Başlat!", key=f"{kp}_pvp_start",
                  use_container_width=True, type="primary", on_click=_start_pvp,
                  disabled=not (p1 and p2))
        return

    questions = st.session_state[data_key]
    turn = st.session_state.get(turn_key, 1)
    current_player = p1 if turn == 1 else p2

    if turn <= 2:
        st.markdown(
            f'<div style="background:#f0f9ff;border:2px solid #6366F1;border-radius:12px;'
            f'padding:12px;text-align:center;margin-bottom:8px">'
            f'<div style="color:#0c4a6e;font-size:1.2rem;font-weight:800">'
            f'\U0001F3AE Sıra: {current_player}</div></div>',
            unsafe_allow_html=True)

        answers = {}
        for i, q in enumerate(questions):
            st.markdown(f'<div style="color:#1e293b;font-size:.9rem;margin:4px 0">'
                        f'<b>{i+1}.</b> {q.get("question","")}</div>', unsafe_allow_html=True)
            opts = q.get("options", [])
            sel = st.radio(":", opts, key=f"{kp}_pvp_t{turn}_q{i}",
                           index=None, label_visibility="collapsed")
            if sel is not None:
                answers[i] = opts.index(sel) if sel in opts else -1

        sub_key = f"{kp}_pvp_t{turn}_sub"
        if not st.session_state.get(sub_key):
            def _pvp_submit():
                score = sum(1 for i, q in enumerate(questions)
                            if answers.get(i, -1) == q.get("correct", 0))
                st.session_state[f"{kp}_pvp_score{turn}"] = score
                st.session_state[sub_key] = True
                if turn == 1:
                    st.session_state[turn_key] = 2
                else:
                    st.session_state[turn_key] = 3
            st.button(f"\u2705 {current_player} — Gönder", key=f"{kp}_pvp_sub{turn}",
                      use_container_width=True, type="primary", on_click=_pvp_submit)
    else:
        # Sonuçlar
        s1 = st.session_state.get(f"{kp}_pvp_score1", 0)
        s2 = st.session_state.get(f"{kp}_pvp_score2", 0)
        # Persist PvP session result
        if not st.session_state.get(f"{kp}_pvp_saved"):
            try:
                pp = _pvp_path()
                pvp_hist = []
                if os.path.exists(pp):
                    with open(pp, "r", encoding="utf-8") as _f:
                        pvp_hist = json.load(_f)
                pvp_hist.append({"p1": p1, "p2": p2, "s1": s1, "s2": s2,
                                 "ders": ders, "timestamp": time.time()})
                with open(pp, "w", encoding="utf-8") as _f:
                    json.dump(pvp_hist, _f, ensure_ascii=False, indent=2)
                st.session_state[f"{kp}_pvp_saved"] = True
            except Exception:
                pass
        winner = p1 if s1 > s2 else p2 if s2 > s1 else "Berabere!"
        w_color = "#22c55e" if s1 != s2 else "#f59e0b"

        st.markdown(
            f'<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
            f'border:2px solid {w_color};border-radius:14px;padding:20px;text-align:center">'
            f'<div style="font-size:2rem">\U0001F3C6</div>'
            f'<div style="color:{w_color};font-size:1.5rem;font-weight:900">'
            f'{"Kazanan: " + winner if s1 != s2 else "Berabere!"}</div>'
            f'<div style="display:flex;justify-content:center;gap:30px;margin-top:12px">'
            f'<div style="text-align:center"><div style="color:#3b82f6;font-size:1.3rem;'
            f'font-weight:800">{s1}/5</div><div style="color:#475569">{p1}</div></div>'
            f'<div style="color:#64748b;font-size:1.5rem;align-self:center">VS</div>'
            f'<div style="text-align:center"><div style="color:#ef4444;font-size:1.3rem;'
            f'font-weight:800">{s2}/5</div><div style="color:#475569">{p2}</div></div>'
            f'</div></div>', unsafe_allow_html=True)

        def _pvp_reset():
            for k in [data_key, turn_key, gen_key,
                      f"{kp}_pvp_score1", f"{kp}_pvp_score2",
                      f"{kp}_pvp_t1_sub", f"{kp}_pvp_t2_sub"]:
                st.session_state.pop(k, None)
            for t in range(1, 3):
                for i in range(5):
                    st.session_state.pop(f"{kp}_pvp_t{t}_q{i}", None)
        st.button("\U0001F504 Tekrar Yarış", key=f"{kp}_pvp_again",
                  use_container_width=True, on_click=_pvp_reset)


# ════════════════════════════════════════════════════════════
# T4 — AI SORU AÇIKLAYICI
# ════════════════════════════════════════════════════════════
def render_question_explainer(ders: str, seviye: str, kp: str):
    """Soru yapıştır, AI çözsün + adım adım açıklasın."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F50D AI Soru Açıklayıcı</span></div>',
        unsafe_allow_html=True,
    )

    question = st.text_area("Soruyu yapıştırın:", key=f"{kp}_qexp_input",
                             placeholder="Soruyu buraya yazın veya yapıştırın...", height=100)

    gen_key = f"{kp}_qexp_gen"
    result_key = f"{kp}_qexp_result"

    if st.session_state.get(gen_key):
        with st.spinner("AI soruyu çözüyor..."):
            client = _get_client()
            if client:
                try:
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"Sen {ders} ogretmenisin. Seviye: {seviye}. "
                             "Ogrenci bir soru paylasiyor. Soruyu adim adim coz:\n"
                             "1. Soruyu anla ve ne soruldugunu belirt\n"
                             "2. Gerekli formul/kural/bilgiyi yaz\n"
                             "3. Adim adim cozum goster\n"
                             "4. Dogru cevabi belirt\n"
                             "5. Ipucu ver\nTurkce yaz. Net ve kisa ol."},
                            {"role": "user", "content": question},
                        ],
                        max_tokens=800, temperature=0.5,
                    )
                    st.session_state[result_key] = resp.choices[0].message.content
                except Exception as e:
                    st.session_state[result_key] = f"Hata: {e}"
            st.session_state[gen_key] = False
            st.rerun()

    if result_key in st.session_state:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(34,197,94,0.3);'
            f'border-radius:12px;padding:14px"><div style="color:#1e293b;font-size:.9rem;'
            f'white-space:pre-wrap;line-height:1.6">{st.session_state[result_key]}</div></div>',
            unsafe_allow_html=True)
        def _new_q():
            st.session_state.pop(result_key, None)
            st.session_state.pop(f"{kp}_qexp_input", None)
        st.button("\U0001F504 Yeni Soru", key=f"{kp}_qexp_new", on_click=_new_q)
    else:
        def _solve():
            st.session_state[gen_key] = True
        st.button("\U0001F9E0 Çöz ve Açıkla", key=f"{kp}_qexp_btn",
                  use_container_width=True, type="primary", on_click=_solve,
                  disabled=not question.strip() if isinstance(question, str) else True)


# ════════════════════════════════════════════════════════════
# T5 — POMODORO ÇALIŞMA MODU
# ════════════════════════════════════════════════════════════
def render_pomodoro(kp: str):
    """Pomodoro zamanlayıcı — 25dk çalış, 5dk mola."""
    import streamlit.components.v1 as components
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F345 Pomodoro Çalışma Modu</span></div>',
        unsafe_allow_html=True,
    )
    pomo_html = """<!DOCTYPE html><html><head><meta charset="utf-8"><style>
    body{margin:0;background:#f0f9ff;font-family:system-ui;text-align:center;padding:20px}
    .timer{color:#0c4a6e;font-size:4rem;font-weight:900;font-family:monospace;margin:20px 0}
    .status{color:#475569;font-size:1rem;margin:8px 0}
    .ring{width:200px;height:200px;border-radius:50%;margin:0 auto;position:relative;
      border:6px solid #1e293b}
    .ring svg{position:absolute;top:-6px;left:-6px;transform:rotate(-90deg)}
    .btns{display:flex;gap:8px;justify-content:center;margin-top:16px}
    .btn{background:#e2e8f0;color:#0c4a6e;border:1px solid #93c5fd;
      border-radius:10px;padding:8px 20px;cursor:pointer;font-size:.9rem;font-weight:700}
    .btn:hover{background:#334155}
    .btn.active{background:#6366F1;color:#0B0F19}
    .stats{display:flex;gap:16px;justify-content:center;margin-top:16px}
    .stat{background:#e2e8f0;border-radius:10px;padding:8px 16px}
    .stat-v{color:#0c4a6e;font-size:1.2rem;font-weight:800}
    .stat-l{color:#64748b;font-size:.7rem}
    </style></head><body>
    <div id="statusTxt" class="status">Çalışma Zamanı</div>
    <div class="ring">
      <svg width="212" height="212"><circle cx="106" cy="106" r="97" fill="none"
        stroke="#1e293b" stroke-width="6"/><circle id="prog" cx="106" cy="106" r="97"
        fill="none" stroke="#6366F1" stroke-width="6" stroke-linecap="round"
        stroke-dasharray="609.44" stroke-dashoffset="0"/></svg>
      <div style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%)">
        <div id="timerTxt" class="timer">25:00</div>
      </div>
    </div>
    <div class="btns">
      <button class="btn" id="btnStart" onclick="toggleTimer()">▶ Başlat</button>
      <button class="btn" onclick="resetTimer()">🔄 Sıfırla</button>
      <button class="btn" onclick="setMode('work')">💼 Çalışma</button>
      <button class="btn" onclick="setMode('break')">☕ Mola</button>
    </div>
    <div class="stats">
      <div class="stat"><div class="stat-v" id="sCount">0</div><div class="stat-l">Tamamlanan</div></div>
      <div class="stat"><div class="stat-v" id="sTotal">0dk</div><div class="stat-l">Toplam</div></div>
    </div>
    <script>
    var workMin=25,breakMin=5,timeLeft=workMin*60,running=false,mode='work',interval;
    var completed=0,totalMin=0;
    function updateDisplay(){
      var m=Math.floor(timeLeft/60),s=timeLeft%60;
      document.getElementById('timerTxt').textContent=m+':'+(s<10?'0':'')+s;
      var total=mode==='work'?workMin*60:breakMin*60;
      var pct=(total-timeLeft)/total;
      document.getElementById('prog').style.strokeDashoffset=609.44*(1-pct);
      document.getElementById('prog').style.stroke=mode==='work'?'#6366F1':'#22c55e';
    }
    function toggleTimer(){
      if(running){running=false;clearInterval(interval);
        document.getElementById('btnStart').textContent='▶ Devam';}
      else{running=true;
        document.getElementById('btnStart').textContent='⏸ Duraklat';
        interval=setInterval(function(){
          if(timeLeft<=0){clearInterval(interval);running=false;
            if(mode==='work'){completed++;totalMin+=workMin;
              document.getElementById('sCount').textContent=completed;
              document.getElementById('sTotal').textContent=totalMin+'dk';
              try{var a=new(window.AudioContext||window.webkitAudioContext)();
                var o=a.createOscillator();var g=a.createGain();o.connect(g);g.connect(a.destination);
                o.frequency.value=880;g.gain.value=0.15;o.start();o.stop(a.currentTime+0.3);}catch(e){}
              setMode('break');}
            else{setMode('work');}
            return;}
          timeLeft--;updateDisplay();
        },1000);}
    }
    function resetTimer(){running=false;clearInterval(interval);
      timeLeft=mode==='work'?workMin*60:breakMin*60;
      document.getElementById('btnStart').textContent='▶ Başlat';updateDisplay();}
    function setMode(m){mode=m;running=false;clearInterval(interval);
      timeLeft=m==='work'?workMin*60:breakMin*60;
      document.getElementById('statusTxt').textContent=m==='work'?'Çalışma Zamanı':'Mola Zamanı ☕';
      document.getElementById('btnStart').textContent='▶ Başlat';updateDisplay();}
    updateDisplay();
    </script></body></html>"""
    components.html(pomo_html, height=420, scrolling=False)


# ════════════════════════════════════════════════════════════
# T6 — SESLİ DERS PODCAST
# ════════════════════════════════════════════════════════════
def render_podcast_mode(lesson_data: dict, tts_b64: str | None, ders: str, kp: str):
    """Dersi podcast formatında dinle — MP3 indir."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F3A7 Ders Podcast</span></div>',
        unsafe_allow_html=True,
    )

    title = lesson_data.get("title", "Ders")
    tts_text = lesson_data.get("tts_text", "")

    # Podcast kartı
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
        f'border:2px solid rgba(212,175,55,0.3);border-radius:14px;padding:16px;'
        f'display:flex;gap:16px;align-items:center">'
        f'<div style="background:#6366F1;color:#0B0F19;border-radius:12px;width:80px;height:80px;'
        f'display:flex;align-items:center;justify-content:center;font-size:2rem;flex-shrink:0">'
        f'\U0001F3A7</div>'
        f'<div><div style="color:#0c4a6e;font-weight:700;font-size:1rem">{title}</div>'
        f'<div style="color:#475569;font-size:.85rem">{ders} | SmartCampus Podcast</div>'
        f'<div style="color:#64748b;font-size:.75rem;margin-top:4px">'
        f'{len(tts_text)} karakter</div></div></div>',
        unsafe_allow_html=True)

    if tts_b64:
        # Ses oynatıcı
        st.audio(base64.b64decode(tts_b64), format="audio/mp3")
        # MP3 indir
        st.download_button(
            "\u2B07\uFE0F MP3 İndir",
            data=base64.b64decode(tts_b64),
            file_name=f"podcast_{ders}_{datetime.now().strftime('%Y%m%d')}.mp3",
            mime="audio/mpeg",
            key=f"{kp}_podcast_dl",
        )
    else:
        # TTS yoksa browser ile oku
        st.info("OpenAI TTS mevcut değil. Tarayıcı seslendirmesi kullanılacak.")
        import streamlit.components.v1 as components
        safe_text = tts_text.replace("'", "\\'").replace("\n", " ")[:3000]
        components.html(
            f'<button onclick="var u=new SpeechSynthesisUtterance(\'{safe_text}\');'
            f'u.lang=\'tr-TR\';u.rate=0.9;speechSynthesis.speak(u)" '
            f'style="background:#6366F1;color:#0B0F19;border:none;border-radius:10px;'
            f'padding:10px 24px;cursor:pointer;font-weight:700;font-size:1rem;width:100%">'
            f'\U0001F50A Podcast Dinle</button>', height=50)


# ════════════════════════════════════════════════════════════
# L7 — 3D GÖRSEL LAB (Three.js benzeri CSS3D)
# ════════════════════════════════════════════════════════════
def render_3d_lab(ders: str, kp: str):
    """3D geometrik cisim / molekül gösterimi — CSS3D transform + mouse döndürme."""
    import streamlit.components.v1 as components
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4A0 3D Görsel Lab</span></div>',
        unsafe_allow_html=True,
    )

    models = {
        "Matematik": ["Küp", "Silindir", "Koni", "Küre", "Prizma"],
        "Fizik": ["Vektör Uzayı", "Manyetik Alan"],
        "Kimya": ["Su (H₂O)", "Metan (CH₄)", "CO₂", "Atom Modeli"],
        "Biyoloji": ["DNA Sarmalı", "Hücre"],
        "Fen Bilimleri": ["Küp", "Atom Modeli", "Su (H₂O)"],
    }
    opts = models.get(ders, ["Küp", "Küre", "Silindir"])
    selected = st.selectbox("3D Model:", opts, key=f"{kp}_3d_model")

    lab_html = f"""<!DOCTYPE html><html><head><meta charset="utf-8"><style>
    body{{margin:0;background:#f0f9ff;overflow:hidden}}
    canvas{{display:block;margin:0 auto;cursor:grab}}
    .info{{color:#64748b;font-size:.75rem;text-align:center;padding:4px}}
    </style></head><body>
    <canvas id="c" width="560" height="400"></canvas>
    <div class="info">Mouse ile döndürün | Scroll ile zoom</div>
    <script>
    var cv=document.getElementById('c'),c=cv.getContext('2d'),W=cv.width,H=cv.height;
    var rotX=0.5,rotY=0.4,zoom=200,dragging=false,lastX,lastY;
    var model='{selected}';
    function project(x,y,z){{
      var cosX=Math.cos(rotX),sinX=Math.sin(rotX),cosY=Math.cos(rotY),sinY=Math.sin(rotY);
      var y1=y*cosX-z*sinX,z1=y*sinX+z*cosX;
      var x1=x*cosY+z1*sinY,z2=-x*sinY+z1*cosY;
      var scale=zoom/(z2+400);
      return{{x:W/2+x1*scale,y:H/2-y1*scale,z:z2,s:scale}};
    }}
    function drawLine(x1,y1,z1,x2,y2,z2,color){{
      var p1=project(x1,y1,z1),p2=project(x2,y2,z2);
      c.strokeStyle=color;c.lineWidth=Math.max(1,p1.s*0.8);
      c.beginPath();c.moveTo(p1.x,p1.y);c.lineTo(p2.x,p2.y);c.stroke();
    }}
    function drawPoint(x,y,z,r,color,label){{
      var p=project(x,y,z);var sr=Math.max(2,r*p.s);
      c.fillStyle=color;c.beginPath();c.arc(p.x,p.y,sr,0,Math.PI*2);c.fill();
      if(label){{c.fillStyle='#e2e8f0';c.font='bold '+(10+sr/3)+'px system-ui';
        c.textAlign='center';c.fillText(label,p.x,p.y-sr-4);}}
    }}
    function draw(){{
      c.fillStyle='#0B0F19';c.fillRect(0,0,W,H);
      c.fillStyle='#6366F1';c.font='bold 14px system-ui';c.textAlign='left';
      c.fillText(model,12,24);
      if(model==='Küp'||model==='Prizma'){{
        var s=80,h=model==='Prizma'?120:80;
        var v=[[-s,-h,-s],[s,-h,-s],[s,-h,s],[-s,-h,s],[-s,h,-s],[s,h,-s],[s,h,s],[-s,h,s]];
        var edges=[[0,1],[1,2],[2,3],[3,0],[4,5],[5,6],[6,7],[7,4],[0,4],[1,5],[2,6],[3,7]];
        for(var e of edges)drawLine(v[e[0]][0],v[e[0]][1],v[e[0]][2],v[e[1]][0],v[e[1]][1],v[e[1]][2],'#3b82f6');
        for(var i=0;i<8;i++)drawPoint(v[i][0],v[i][1],v[i][2],4,'#6366F1',String.fromCharCode(65+i));
      }}
      else if(model==='Küre'){{
        for(var lat=-80;lat<=80;lat+=20){{for(var lon=0;lon<360;lon+=10){{
          var la=lat*Math.PI/180,lo=lon*Math.PI/180,lo2=(lon+10)*Math.PI/180;
          var r=80;drawLine(r*Math.cos(la)*Math.cos(lo),r*Math.sin(la),r*Math.cos(la)*Math.sin(lo),
            r*Math.cos(la)*Math.cos(lo2),r*Math.sin(la),r*Math.cos(la)*Math.sin(lo2),'#3b82f680');}}}}
        for(var lon=0;lon<360;lon+=30){{for(var lat=-80;lat<80;lat+=10){{
          var la=lat*Math.PI/180,la2=(lat+10)*Math.PI/180,lo=lon*Math.PI/180;
          var r=80;drawLine(r*Math.cos(la)*Math.cos(lo),r*Math.sin(la),r*Math.cos(la)*Math.sin(lo),
            r*Math.cos(la2)*Math.cos(lo),r*Math.sin(la2),r*Math.cos(la2)*Math.sin(lo),'#3b82f680');}}}}
      }}
      else if(model==='Silindir'){{
        var r=60,h=100;
        for(var a=0;a<360;a+=15){{var a1=a*Math.PI/180,a2=(a+15)*Math.PI/180;
          drawLine(r*Math.cos(a1),h,r*Math.sin(a1),r*Math.cos(a2),h,r*Math.sin(a2),'#22c55e');
          drawLine(r*Math.cos(a1),-h,r*Math.sin(a1),r*Math.cos(a2),-h,r*Math.sin(a2),'#22c55e');
          if(a%30===0)drawLine(r*Math.cos(a1),h,r*Math.sin(a1),r*Math.cos(a1),-h,r*Math.sin(a1),'#22c55e80');}}
      }}
      else if(model==='Koni'){{
        var r=70,h=120;
        for(var a=0;a<360;a+=15){{var a1=a*Math.PI/180,a2=(a+15)*Math.PI/180;
          drawLine(r*Math.cos(a1),-h/2,r*Math.sin(a1),r*Math.cos(a2),-h/2,r*Math.sin(a2),'#f59e0b');
          if(a%30===0)drawLine(r*Math.cos(a1),-h/2,r*Math.sin(a1),0,h/2,0,'#f59e0b80');}}
        drawPoint(0,h/2,0,5,'#6366F1','Tepe');
      }}
      else if(model.includes('H₂O')||model.includes('Su')){{
        drawPoint(0,0,0,12,'#ef4444','O');
        drawPoint(-60,-50,0,8,'#3b82f6','H');drawPoint(60,-50,0,8,'#3b82f6','H');
        drawLine(0,0,0,-60,-50,0,'#94a3b8');drawLine(0,0,0,60,-50,0,'#94a3b8');
        c.fillStyle='#64748b';c.font='11px system-ui';c.textAlign='center';
        var p=project(0,40,0);c.fillText('104.5°',p.x,p.y);
      }}
      else if(model.includes('CH₄')||model.includes('Metan')){{
        drawPoint(0,0,0,12,'#333','C');
        var tet=[[0,80,0],[75,-30,40],[-75,-30,40],[0,-30,-80]];
        for(var t of tet){{drawPoint(t[0],t[1],t[2],8,'#3b82f6','H');drawLine(0,0,0,t[0],t[1],t[2],'#94a3b8');}}
      }}
      else if(model==='CO₂'){{
        drawPoint(0,0,0,12,'#ef4444','C');
        drawPoint(-80,0,0,10,'#3b82f6','O');drawPoint(80,0,0,10,'#3b82f6','O');
        drawLine(0,0,0,-80,0,0,'#94a3b8');drawLine(0,0,0,80,0,0,'#94a3b8');
      }}
      else if(model==='DNA Sarmalı'){{
        for(var i=0;i<60;i++){{var a=i*0.2,y=i*4-120,r2=50;
          var x1=r2*Math.cos(a),z1=r2*Math.sin(a),x2=r2*Math.cos(a+Math.PI),z2=r2*Math.sin(a+Math.PI);
          if(i>0){{var pa=((i-1)*0.2),py=y-4;
            drawLine(r2*Math.cos(pa),py,r2*Math.sin(pa),x1,y,z1,'#3b82f6');
            drawLine(r2*Math.cos(pa+Math.PI),py,r2*Math.sin(pa+Math.PI),x2,y,z2,'#ef4444');}}
          if(i%5===0)drawLine(x1,y,z1,x2,y,z2,'#22c55e40');
          drawPoint(x1,y,z1,2,'#3b82f6','');drawPoint(x2,y,z2,2,'#ef4444','');}}
      }}
      else if(model==='Atom Modeli'){{
        drawPoint(0,0,0,15,'#ef4444','N');
        for(var s=1;s<=3;s++){{for(var a=0;a<360;a+=10){{var a1=a*Math.PI/180,a2=(a+10)*Math.PI/180,r3=s*35;
          drawLine(r3*Math.cos(a1),r3*Math.sin(a1)*0.3,r3*Math.sin(a1),
            r3*Math.cos(a2),r3*Math.sin(a2)*0.3,r3*Math.sin(a2),'rgba(100,116,139,0.2)');}}
          var ea=Date.now()/1000*s;
          drawPoint(s*35*Math.cos(ea),s*35*Math.sin(ea)*0.3,s*35*Math.sin(ea),5,'#3b82f6','e⁻');}}
      }}
      else{{
        var s2=60;var v2=[[-s2,-s2,-s2],[s2,-s2,-s2],[s2,-s2,s2],[-s2,-s2,s2],
          [-s2,s2,-s2],[s2,s2,-s2],[s2,s2,s2],[-s2,s2,s2]];
        var e2=[[0,1],[1,2],[2,3],[3,0],[4,5],[5,6],[6,7],[7,4],[0,4],[1,5],[2,6],[3,7]];
        for(var e of e2)drawLine(v2[e[0]][0],v2[e[0]][1],v2[e[0]][2],v2[e[1]][0],v2[e[1]][1],v2[e[1]][2],'#a855f7');
      }}
      if(model==='Atom Modeli')requestAnimationFrame(draw);
    }}
    cv.addEventListener('mousedown',function(e){{dragging=true;lastX=e.clientX;lastY=e.clientY;}});
    cv.addEventListener('mousemove',function(e){{if(!dragging)return;
      rotY+=(e.clientX-lastX)*0.01;rotX+=(e.clientY-lastY)*0.01;
      lastX=e.clientX;lastY=e.clientY;draw();}});
    cv.addEventListener('mouseup',function(){{dragging=false;}});
    cv.addEventListener('mouseleave',function(){{dragging=false;}});
    cv.addEventListener('wheel',function(e){{zoom+=e.deltaY>0?-20:20;zoom=Math.max(50,Math.min(500,zoom));draw();e.preventDefault();}});
    draw();if(model==='Atom Modeli')requestAnimationFrame(draw);
    </script></body></html>"""
    components.html(lab_html, height=440, scrolling=False)


# ════════════════════════════════════════════════════════════
# L8 — AI ÖĞRETMEN AVATAR KİŞİSELLEŞTİRME
# ════════════════════════════════════════════════════════════
def _avatar_path():
    return os.path.join(_data_dir(), "custom_avatar.json")

def render_avatar_customizer(kp: str):
    """Öğretmen avatarını kişiselleştir — ten, saç, kıyafet rengi."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F9D1\u200D\U0001F3A8 Avatar Kişiselleştirme</span></div>',
        unsafe_allow_html=True,
    )

    # Mevcut ayarları yükle
    custom = {}
    p = _avatar_path()
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                custom = json.load(f)
        except Exception:
            pass

    c1, c2, c3 = st.columns(3)
    with c1:
        skin = st.color_picker("Ten Rengi", value=custom.get("skin", "#DEB887"), key=f"{kp}_av_skin")
    with c2:
        hair = st.color_picker("Saç Rengi", value=custom.get("hair", "#1a1a2e"), key=f"{kp}_av_hair")
    with c3:
        shirt = st.color_picker("Kıyafet Rengi", value=custom.get("shirt", "#2563eb"), key=f"{kp}_av_shirt")

    c4, c5 = st.columns(2)
    with c4:
        name = st.text_input("Öğretmen Adı:", value=custom.get("name", ""), key=f"{kp}_av_name",
                              placeholder="Özel öğretmen adı")
    with c5:
        gender = st.selectbox("Cinsiyet:", ["Erkek", "Kadın"],
                               index=1 if custom.get("is_female") else 0, key=f"{kp}_av_gender")

    # Önizleme
    import streamlit.components.v1 as components
    prev_html = f"""<canvas id="avPrev" width="120" height="200" style="display:block;margin:0 auto;
    border-radius:12px;background:#f0f9ff"></canvas>
    <script>
    var c=document.getElementById('avPrev').getContext('2d');
    c.fillStyle='#0B0F19';c.fillRect(0,0,120,200);
    c.fillStyle='{shirt}';c.fillRect(30,100,60,80);
    c.fillStyle='{skin}';c.beginPath();c.arc(60,60,30,0,Math.PI*2);c.fill();
    c.fillStyle='{hair}';c.beginPath();c.arc(60,48,32,Math.PI,2*Math.PI);c.fill();
    c.fillStyle='#fff';c.beginPath();c.arc(50,58,4,0,Math.PI*2);c.fill();
    c.beginPath();c.arc(70,58,4,0,Math.PI*2);c.fill();
    c.fillStyle='#333';c.beginPath();c.arc(50,58,2,0,Math.PI*2);c.fill();
    c.beginPath();c.arc(70,58,2,0,Math.PI*2);c.fill();
    c.strokeStyle='{skin}';c.lineWidth=2;c.beginPath();c.arc(60,68,6,0.1*Math.PI,0.9*Math.PI);c.stroke();
    </script>"""
    components.html(prev_html, height=210)

    def _save_avatar():
        with open(_avatar_path(), "w", encoding="utf-8") as f:
            json.dump({"skin": skin, "hair": hair, "shirt": shirt,
                       "name": name or "Özel Hoca", "is_female": gender == "Kadın"}, f)
    st.button("\U0001F4BE Avatarı Kaydet", key=f"{kp}_av_save",
              use_container_width=True, type="primary", on_click=_save_avatar)


# ════════════════════════════════════════════════════════════
# L9 — HİKAYE MODU (Story/RPG)
# ════════════════════════════════════════════════════════════
def _story_path():
    return os.path.join(_data_dir(), "story_progress.json")

def _load_story() -> dict:
    p = _story_path()
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            pass
    return {"level": 1, "xp": 0, "chapters": [], "boss_defeated": []}

def _save_story(data: dict):
    with open(_story_path(), "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def render_story_mode(ders: str, kp: str):
    """RPG tarzı hikaye modu — bölümler, boss fight, seviye."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\u2694\uFE0F Hikaye Modu</span>'
        '<span style="color:#475569;font-size:.8rem;margin-left:8px">'
        'Her konu bir macera!</span></div>',
        unsafe_allow_html=True,
    )

    story = _load_story()
    prog = load_progress()
    gd = prog.get(ders, {})
    topics = list(gd.get("topics", {}).keys())

    level = story.get("level", 1)
    xp = story.get("xp", 0)
    chapters_done = story.get("chapters", [])

    # Karakter kartı
    char_class = ["Çırak", "Öğrenci", "Bilgin", "Usta", "Büyücü", "Efsane"][min(level - 1, 5)]
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
        f'border:2px solid #6366F1;border-radius:14px;padding:16px;display:flex;gap:16px;'
        f'align-items:center;margin-bottom:12px">'
        f'<div style="background:linear-gradient(135deg,#7c3aed,#3b82f6);border-radius:12px;'
        f'width:70px;height:70px;display:flex;align-items:center;justify-content:center;'
        f'font-size:2rem;flex-shrink:0">\u2694\uFE0F</div>'
        f'<div><div style="color:#0c4a6e;font-weight:800;font-size:1.1rem">Seviye {level} — {char_class}</div>'
        f'<div style="color:#475569;font-size:.85rem">{xp} XP | {len(chapters_done)} bölüm tamamlandı</div>'
        f'<div style="background:#334155;border-radius:4px;height:6px;margin-top:4px;width:160px">'
        f'<div style="background:#6366F1;height:100%;border-radius:4px;width:{min(100,(xp%300)/3)}%"></div>'
        f'</div></div></div>',
        unsafe_allow_html=True)

    # Bölüm haritası
    if not topics:
        st.info("Henüz tamamlanmış ders yok. Ders tamamladıkça bölümler açılacak.")
        return

    for i, topic in enumerate(topics[:12]):
        done = topic in chapters_done
        is_boss = (i + 1) % 5 == 0
        icon = "\U0001F409" if is_boss else ("\u2705" if done else f"\U0001F512" if i > len(chapters_done) else "\u2B50")
        border = "#22c55e" if done else "#6366F1" if i <= len(chapters_done) else "#334155"
        label = "BOSS!" if is_boss else f"Bölüm {i+1}"

        st.markdown(
            f'<div style="border-left:3px solid {border};background:#f0f9ff;'
            f'border-radius:0 10px 10px 0;padding:8px 12px;margin:3px 0;'
            f'opacity:{"1" if i <= len(chapters_done) else "0.4"}">'
            f'<span style="font-size:1.1rem">{icon}</span> '
            f'<span style="color:{"#22c55e" if done else "#e2e8f0"};font-weight:600;font-size:.9rem">'
            f'{label}: {topic[:35]}</span>'
            f'{"<span style=\\'color:#0c4a6e;font-size:.7rem;margin-left:8px\\'>+50 XP</span>" if done else ""}'
            f'</div>',
            unsafe_allow_html=True)

    # İlerleme kaydet
    for topic in topics:
        if topic not in chapters_done:
            chapters_done.append(topic)
            story["xp"] = story.get("xp", 0) + 50
            story["level"] = story["xp"] // 300 + 1
    story["chapters"] = chapters_done
    _save_story(story)


# ════════════════════════════════════════════════════════════
# L10 — EBEVEYN DASHBOARD
# ════════════════════════════════════════════════════════════
def render_parent_dashboard(kp: str):
    """Veli için ilerleme özeti."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F468\u200D\U0001F469\u200D\U0001F467 Ebeveyn Raporu</span></div>',
        unsafe_allow_html=True,
    )

    prog = load_progress()
    if not prog:
        st.info("Henüz veri yok.")
        return

    total_lessons = sum(gd.get("total_lessons", 0) for gd in prog.values())
    total_xp = sum(gd.get("total_xp", 0) for gd in prog.values())
    all_scores = []
    for gd in prog.values():
        for t in gd.get("topics", {}).values():
            if t.get("quiz_score", 0) > 0:
                all_scores.append(t["quiz_score"])
    avg_score = sum(all_scores) / len(all_scores) if all_scores else 0

    sc1, sc2, sc3, sc4 = st.columns(4)
    stats = [
        (sc1, "\U0001F4DA", str(total_lessons), "Toplam Ders", "#3b82f6"),
        (sc2, "\u2B50", str(total_xp), "Toplam XP", "#6366F1"),
        (sc3, "\U0001F4CA", f"{avg_score:.0f}%", "Ort. Puan", "#22c55e"),
        (sc4, "\U0001F4D6", str(len(prog)), "Ders Sayısı", "#a855f7"),
    ]
    for col, icon, val, lbl, clr in stats:
        with col:
            st.markdown(
                f'<div style="background:#f0f9ff;border:1px solid {clr}40;border-radius:10px;'
                f'padding:10px;text-align:center"><div style="font-size:1.3rem">{icon}</div>'
                f'<div style="color:{clr};font-size:1.2rem;font-weight:800">{val}</div>'
                f'<div style="color:#64748b;font-size:.7rem">{lbl}</div></div>',
                unsafe_allow_html=True)

    # Ders bazlı detay
    for ders_name, gd in prog.items():
        topics = gd.get("topics", {})
        d_score = sum(t.get("quiz_score", 0) for t in topics.values()) / max(len(topics), 1)
        color = "#22c55e" if d_score >= 80 else "#f59e0b" if d_score >= 60 else "#ef4444"
        st.markdown(
            f'<div style="border-left:3px solid {color};background:#f0f9ff;'
            f'border-radius:0 8px 8px 0;padding:8px 12px;margin:4px 0">'
            f'<div style="display:flex;justify-content:space-between;align-items:center">'
            f'<span style="color:#1e293b;font-weight:600">{ders_name}</span>'
            f'<span style="color:{color};font-weight:700">{d_score:.0f}% | '
            f'{len(topics)} konu</span></div></div>',
            unsafe_allow_html=True)


# ════════════════════════════════════════════════════════════
# L11 — ÇOKLU DİL DESTEĞİ
# ════════════════════════════════════════════════════════════
def render_multilang(lesson_data: dict, ders: str, kp: str):
    """Ders içeriğini farklı dile çevir."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F30D Çoklu Dil</span></div>',
        unsafe_allow_html=True,
    )

    lang = st.selectbox("Hedef Dil:", ["İngilizce", "Almanca", "Arapça", "Fransızca", "İspanyolca"],
                         key=f"{kp}_lang_sel")

    gen_key = f"{kp}_lang_gen"
    result_key = f"{kp}_lang_result"

    if st.session_state.get(gen_key):
        with st.spinner(f"{lang} çevirisi yapılıyor..."):
            client = _get_client()
            if client:
                try:
                    summary = lesson_data.get("summary", [])[:5]
                    vocab = lesson_data.get("vocabulary", [])[:6]
                    content = (f"Başlık: {lesson_data.get('title','')}\n"
                              f"Özet: {'; '.join(summary)}\n"
                              f"Kavramlar: {', '.join(v.get('term','') + '=' + v.get('definition','') for v in vocab)}")
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"Asagidaki egitim icerigini {lang} diline cevir. "
                             "Baslik, ozet ve kavramlari cevir. Orijinal Turkce'yi de yanina yaz. "
                             "Format: Her satirda Turkce | Ceviri seklinde."},
                            {"role": "user", "content": content},
                        ],
                        max_tokens=600, temperature=0.3,
                    )
                    st.session_state[result_key] = resp.choices[0].message.content
                except Exception as e:
                    st.session_state[result_key] = f"Hata: {e}"
            st.session_state[gen_key] = False
            st.rerun()

    if result_key in st.session_state:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid rgba(59,130,246,0.3);'
            f'border-radius:12px;padding:14px"><div style="color:#1e293b;font-size:.9rem;'
            f'white-space:pre-wrap;line-height:1.8">{st.session_state[result_key]}</div></div>',
            unsafe_allow_html=True)
    else:
        def _translate():
            st.session_state[gen_key] = True
        st.button(f"\U0001F30D {lang}'ye Çevir", key=f"{kp}_lang_btn",
                  use_container_width=True, type="primary", on_click=_translate)


# ════════════════════════════════════════════════════════════
# L12 — ÖĞRENCİ AI MENTORU
# ════════════════════════════════════════════════════════════
def render_ai_mentor(ders: str, kp: str):
    """Kişiselleştirilmiş AI mentor — öğrenme stiline göre öneriler."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F9D1\u200D\U0001F393 AI Mentor</span></div>',
        unsafe_allow_html=True,
    )

    prog = load_progress()
    gd = prog.get(ders, {})
    topics = gd.get("topics", {})
    weak = [t for t, d in topics.items() if d.get("quiz_score", 0) < 60]
    strong = [t for t, d in topics.items() if d.get("quiz_score", 0) >= 80]

    gen_key = f"{kp}_mentor_gen"
    result_key = f"{kp}_mentor_result"

    if st.session_state.get(gen_key):
        with st.spinner("AI Mentor analiz yapıyor..."):
            client = _get_client()
            if client:
                try:
                    ctx = (f"Ders: {ders}\nToplam ders: {gd.get('total_lessons',0)}\n"
                           f"Streak: {gd.get('streak',0)} gün\n"
                           f"Zayıf: {', '.join(weak[:5]) or 'Yok'}\n"
                           f"Güçlü: {', '.join(strong[:5]) or 'Yok'}")
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             "Sen bir AI ogrenme mentorusun. Ogrencinin ilerleme verisine "
                             "bakarak kisisel geri bildirim ver:\n"
                             "1. Genel degerlendirme (2 cumle)\n"
                             "2. Guclu yonler\n"
                             "3. Gelistirilmesi gereken alanlar\n"
                             "4. Bu hafta icin 3 oneri\n"
                             "5. Motivasyon mesaji\n"
                             "Sicak, destekleyici ton. Turkce."},
                            {"role": "user", "content": ctx},
                        ],
                        max_tokens=500, temperature=0.8,
                    )
                    st.session_state[result_key] = resp.choices[0].message.content
                except Exception as e:
                    st.session_state[result_key] = f"Hata: {e}"
            st.session_state[gen_key] = False
            st.rerun()

    if result_key in st.session_state:
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);'
            f'border:2px solid rgba(34,197,94,0.3);border-radius:12px;padding:16px">'
            f'<div style="color:#22c55e;font-weight:700;font-size:.95rem;margin-bottom:8px">'
            f'\U0001F9D1\u200D\U0001F393 Mentor Değerlendirmesi</div>'
            f'<div style="color:#1e293b;font-size:.9rem;white-space:pre-wrap;line-height:1.6">'
            f'{st.session_state[result_key]}</div></div>',
            unsafe_allow_html=True)
        def _refresh():
            st.session_state.pop(result_key, None)
        st.button("\U0001F504 Yeni Değerlendirme", key=f"{kp}_mentor_new", on_click=_refresh)
    else:
        def _ask_mentor():
            st.session_state[gen_key] = True
        st.button("\U0001F9D1\u200D\U0001F393 Mentor'a Danış", key=f"{kp}_mentor_btn",
                  use_container_width=True, type="primary", on_click=_ask_mentor)


# ════════════════════════════════════════════════════════════
# M13 — HANDWRITING / ÇİZİM TANIMA
# ════════════════════════════════════════════════════════════
def render_handwriting(ders: str, kp: str):
    """Canvas'a el yazısı/formül çiz, AI tanısın."""
    import streamlit.components.v1 as components
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\u270D\uFE0F Çizim & Yazı Tanıma</span></div>',
        unsafe_allow_html=True,
    )
    hw_html = """<!DOCTYPE html><html><head><meta charset="utf-8"><style>
    body{margin:0;background:#f0f9ff;font-family:system-ui;text-align:center;padding:8px}
    canvas{border:2px solid rgba(212,175,55,0.3);border-radius:12px;background:#fff;cursor:crosshair}
    .tb{display:flex;gap:6px;justify-content:center;padding:6px}
    .btn{background:#e2e8f0;color:#0c4a6e;border:1px solid #93c5fd;
      border-radius:8px;padding:5px 14px;cursor:pointer;font-size:.8rem;font-weight:600}
    #result{color:#1e293b;font-size:.9rem;margin:8px;min-height:20px}
    </style></head><body>
    <canvas id="hw" width="500" height="200"></canvas>
    <div class="tb">
      <button class="btn" onclick="clearHW()">🗑️ Temizle</button>
      <button class="btn" onclick="recognizeHW()" style="background:#6366F1;color:#0B0F19">
        🔍 Tanı</button>
      <input type="range" min="1" max="8" value="3" oninput="penW=+this.value"
        style="width:60px;accent-color:#0c4a6e">
    </div>
    <div id="result"></div>
    <script>
    var cv=document.getElementById('hw'),c=cv.getContext('2d'),drawing=false,penW=3;
    c.fillStyle='#fff';c.fillRect(0,0,cv.width,cv.height);
    cv.addEventListener('mousedown',function(e){drawing=true;c.beginPath();
      var r=cv.getBoundingClientRect();c.moveTo(e.clientX-r.left,e.clientY-r.top);});
    cv.addEventListener('mousemove',function(e){if(!drawing)return;
      var r=cv.getBoundingClientRect();c.strokeStyle='#000';c.lineWidth=penW;c.lineCap='round';
      c.lineTo(e.clientX-r.left,e.clientY-r.top);c.stroke();});
    cv.addEventListener('mouseup',function(){drawing=false;});
    cv.addEventListener('mouseleave',function(){drawing=false;});
    function clearHW(){c.fillStyle='#fff';c.fillRect(0,0,cv.width,cv.height);}
    function recognizeHW(){
      var data=cv.toDataURL('image/png');
      document.getElementById('result').innerHTML=
        '<span style="color:#22c55e">✏️ Çiziminiz kaydedildi. AI analiz için "Çöz ve Açıkla" bölümünü kullanın.</span>';
      window.parent.postMessage({type:'handwriting',image:data},'*');
    }
    </script></body></html>"""
    components.html(hw_html, height=320, scrolling=False)
    st.markdown('<div style="color:#475569;font-size:.8rem;text-align:center">'
                'Formül veya çizim yapın, tanıma için "AI Soru Açıklayıcı" ile birlikte kullanın</div>',
                unsafe_allow_html=True)


