# M14 — AR MODU (WebXR / CSS 3D)
# ════════════════════════════════════════════════════════════
def render_ar_mode(ders: str, kp: str):
    """Artırılmış gerçeklik benzeri 3D nesne yerleştirme."""
    import streamlit.components.v1 as components
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4F1 AR Görüntüleyici</span></div>',
        unsafe_allow_html=True,
    )
    ar_html = """<!DOCTYPE html><html><head><meta charset="utf-8"><style>
    body{margin:0;background:#f0f9ff;overflow:hidden;font-family:system-ui}
    .scene{width:560px;height:380px;perspective:800px;margin:0 auto;position:relative;
      background:linear-gradient(135deg,#f0f9ff,#e0f2fe);border-radius:12px;overflow:hidden}
    .grid{position:absolute;width:100%;height:100%;
      background-image:linear-gradient(rgba(148,163,184,0.05) 1px,transparent 1px),
        linear-gradient(90deg,rgba(148,163,184,0.05) 1px,transparent 1px);
      background-size:40px 40px;transform:perspective(400px) rotateX(60deg);
      transform-origin:center bottom}
    .obj{position:absolute;top:50%;left:50%;transform-style:preserve-3d;
      animation:float 3s ease-in-out infinite}
    .face{position:absolute;width:80px;height:80px;border:2px solid rgba(59,130,246,0.5);
      background:rgba(59,130,246,0.1);display:flex;align-items:center;justify-content:center;
      font-size:1.5rem;color:#3b82f6;font-weight:800;backface-visibility:visible}
    @keyframes float{0%,100%{transform:translateY(0) rotateY(0deg) rotateX(0deg)}
      50%{transform:translateY(-15px) rotateY(180deg) rotateX(10deg)}}
    .label{position:absolute;bottom:20px;left:0;right:0;text-align:center;
      color:#0c4a6e;font-weight:700;font-size:1rem}
    .info{color:#64748b;font-size:.75rem;text-align:center;padding:4px}
    </style></head><body>
    <div class="scene">
      <div class="grid"></div>
      <div class="obj" id="arObj" style="transform-style:preserve-3d">
        <div class="face" style="transform:translateZ(40px)">⬡</div>
        <div class="face" style="transform:rotateY(90deg) translateZ(40px)">⬡</div>
        <div class="face" style="transform:rotateY(180deg) translateZ(40px)">⬡</div>
        <div class="face" style="transform:rotateY(-90deg) translateZ(40px)">⬡</div>
        <div class="face" style="transform:rotateX(90deg) translateZ(40px)">⬡</div>
        <div class="face" style="transform:rotateX(-90deg) translateZ(40px)">⬡</div>
      </div>
      <div class="label">AR 3D Nesne — Mouse ile döndürün</div>
    </div>
    <div class="info">WebXR destekli cihazlarda tam AR deneyimi</div>
    <script>
    var obj=document.getElementById('arObj'),rx=0,ry=0,dragging=false,lx,ly;
    var scene=document.querySelector('.scene');
    scene.addEventListener('mousedown',function(e){dragging=true;lx=e.clientX;ly=e.clientY;});
    scene.addEventListener('mousemove',function(e){if(!dragging)return;
      ry+=(e.clientX-lx)*0.5;rx+=(e.clientY-ly)*0.5;lx=e.clientX;ly=e.clientY;
      obj.style.animation='none';
      obj.style.transform='translateY(-10px) rotateX('+rx+'deg) rotateY('+ry+'deg)';});
    scene.addEventListener('mouseup',function(){dragging=false;});
    </script></body></html>"""
    components.html(ar_html, height=430, scrolling=False)


# ════════════════════════════════════════════════════════════
# M15 — CANLI SINIF (Sohbet Odası)
# ════════════════════════════════════════════════════════════
def _chatroom_path():
    return os.path.join(_data_dir(), "chatroom.json")

def render_live_class(ders: str, kp: str):
    """Basit sohbet odası — mesaj gönder/al."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4E1 Canlı Sınıf Sohbeti</span></div>',
        unsafe_allow_html=True,
    )

    p = _chatroom_path()
    messages = []
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                messages = json.load(f)
        except Exception:
            pass

    username = st.text_input("Kullanıcı Adı:", key=f"{kp}_live_user", placeholder="Adınız")
    msg = st.text_input("Mesaj:", key=f"{kp}_live_msg", placeholder="Sınıfa mesaj yazın...")

    if msg and username:
        def _send_msg():
            msgs = []
            if os.path.exists(p):
                try:
                    with open(p, "r", encoding="utf-8") as f:
                        msgs = json.load(f)
                except Exception:
                    pass
            msgs.append({
                "user": username, "text": msg, "ders": ders,
                "time": datetime.now().strftime("%H:%M"),
            })
            with open(p, "w", encoding="utf-8") as f:
                json.dump(msgs[-50:], f, ensure_ascii=False)  # Son 50 mesaj
        st.button("\U0001F4E8 Gönder", key=f"{kp}_live_send",
                  type="primary", on_click=_send_msg)

    # Mesajları göster
    ders_msgs = [m for m in messages if m.get("ders") == ders][-20:]
    if ders_msgs:
        for m in reversed(ders_msgs):
            st.markdown(
                f'<div style="border-left:3px solid #3b82f6;background:#f0f9ff;'
                f'border-radius:0 8px 8px 0;padding:6px 10px;margin:2px 0">'
                f'<span style="color:#0c4a6e;font-weight:600;font-size:.8rem">'
                f'{m.get("user","")} </span>'
                f'<span style="color:#64748b;font-size:.7rem">{m.get("time","")}</span>'
                f'<div style="color:#1e293b;font-size:.85rem">{m.get("text","")}</div></div>',
                unsafe_allow_html=True)
    else:
        st.info("Henüz mesaj yok. İlk mesajı siz yazın!")


# ════════════════════════════════════════════════════════════
# M16 — ADAPTİF ZORLUK MOTORU
# ════════════════════════════════════════════════════════════
def _adaptive_path():
    return os.path.join(_data_dir(), "adaptive_level.json")

def render_adaptive_engine(ders: str, seviye: str, kp: str):
    """Her cevaba göre zorluk ayarlayan adaptif quiz."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4A1 Adaptif Zorluk Motoru</span></div>',
        unsafe_allow_html=True,
    )

    # Seviye bilgisi
    p = _adaptive_path()
    elo = 1200
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                elo = json.load(f).get(ders, 1200)
        except Exception:
            pass

    diff_label = "Kolay" if elo < 1100 else "Orta" if elo < 1300 else "Zor" if elo < 1500 else "Çok Zor"
    diff_color = "#22c55e" if elo < 1100 else "#f59e0b" if elo < 1300 else "#ef4444" if elo < 1500 else "#7c3aed"

    st.markdown(
        f'<div style="background:#f0f9ff;border:2px solid {diff_color};border-radius:12px;'
        f'padding:12px;text-align:center;margin-bottom:8px">'
        f'<div style="color:{diff_color};font-size:1.5rem;font-weight:800">ELO: {elo}</div>'
        f'<div style="color:#475569;font-size:.85rem">Seviye: {diff_label}</div></div>',
        unsafe_allow_html=True)

    gen_key = f"{kp}_adp_gen"
    data_key = f"{kp}_adp_data"
    idx_key = f"{kp}_adp_idx"
    score_key = f"{kp}_adp_score"

    if st.session_state.get(gen_key):
        with st.spinner("Adaptif soru hazırlanıyor..."):
            client = _get_client()
            diff_txt = "kolay" if elo < 1100 else "orta" if elo < 1300 else "zor" if elo < 1500 else "cok zor, analitik"
            if client:
                try:
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"{ders} dersi {seviye} seviye, zorluk: {diff_txt}. "
                             "8 coktan secmeli soru uret. Zorluk kademeli artsin. "
                             'JSON: {{"questions":[{{"question":"...","options":["A","B","C","D"],'
                             '"correct":0,"difficulty":"kolay|orta|zor"}}]}}'},
                            {"role": "user", "content": "Adaptif quiz soruları"},
                        ],
                        max_tokens=1800, temperature=0.7,
                        response_format={"type": "json_object"},
                    )
                    result = json.loads(resp.choices[0].message.content)
                    st.session_state[data_key] = result.get("questions", [])[:8]
                    st.session_state[idx_key] = 0
                    st.session_state[score_key] = 0
                except Exception:
                    pass
            st.session_state[gen_key] = False
            st.rerun()

    if data_key not in st.session_state:
        def _start_adp():
            st.session_state[gen_key] = True
        st.button("\U0001F680 Adaptif Quiz Başlat", key=f"{kp}_adp_start",
                  use_container_width=True, type="primary", on_click=_start_adp)
        return

    questions = st.session_state[data_key]
    qi = st.session_state.get(idx_key, 0)
    score = st.session_state.get(score_key, 0)

    if qi < len(questions):
        q = questions[qi]
        diff_q = q.get("difficulty", "orta")
        dc = "#22c55e" if diff_q == "kolay" else "#f59e0b" if diff_q == "orta" else "#ef4444"
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid {dc};border-radius:10px;'
            f'padding:10px 14px;margin-bottom:6px">'
            f'<div style="display:flex;justify-content:space-between">'
            f'<span style="color:#0c4a6e;font-weight:700">Soru {qi+1}/{len(questions)}</span>'
            f'<span style="color:{dc};font-size:.8rem;font-weight:600">{diff_q.upper()}</span></div>'
            f'<div style="color:#1e293b;font-size:.95rem;margin-top:4px">'
            f'{q.get("question","")}</div></div>',
            unsafe_allow_html=True)

        opts = q.get("options", [])
        sel = st.radio("Cevap:", opts, key=f"{kp}_adp_q{qi}", index=None, label_visibility="collapsed")

        def _adp_answer():
            ans_idx = opts.index(sel) if sel in opts else -1
            correct = ans_idx == q.get("correct", 0)
            s = st.session_state.get(score_key, 0)
            if correct:
                s += 1
            st.session_state[score_key] = s
            st.session_state[idx_key] = qi + 1
            # ELO güncelle
            delta = 30 if correct else -20
            try:
                with open(_adaptive_path(), "r", encoding="utf-8") as f:
                    elo_data = json.load(f)
            except Exception:
                elo_data = {}
            elo_data[ders] = elo_data.get(ders, 1200) + delta
            with open(_adaptive_path(), "w", encoding="utf-8") as f:
                json.dump(elo_data, f)

        st.button("\u2705 Cevapla", key=f"{kp}_adp_ans{qi}",
                  use_container_width=True, type="primary",
                  on_click=_adp_answer, disabled=sel is None)
    else:
        pct = (score / max(len(questions), 1)) * 100
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
            f'border:2px solid #6366F1;border-radius:12px;padding:16px;text-align:center">'
            f'<div style="color:#0c4a6e;font-size:2rem;font-weight:900">{score}/{len(questions)}</div>'
            f'<div style="color:#475569">Adaptif Quiz Tamamlandı!</div></div>',
            unsafe_allow_html=True)
        def _adp_reset():
            for k in [data_key, idx_key, score_key, gen_key]:
                st.session_state.pop(k, None)
            for i in range(10):
                st.session_state.pop(f"{kp}_adp_q{i}", None)
        st.button("\U0001F504 Tekrar", key=f"{kp}_adp_new", on_click=_adp_reset)


# ════════════════════════════════════════════════════════════
# M17 — BİLGİ TURNUVASI
# ════════════════════════════════════════════════════════════
def _tournament_path():
    return os.path.join(_data_dir(), "tournament.json")

def render_tournament(ders: str, seviye: str, kp: str):
    """Haftalık bilgi turnuvası — liderboard."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F3C6 Bilgi Turnuvası</span></div>',
        unsafe_allow_html=True,
    )

    p = _tournament_path()
    data = {"entries": [], "week": ""}
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                data = json.load(f)
        except Exception:
            pass

    current_week = datetime.now().strftime("%Y-W%W")
    if data.get("week") != current_week:
        data = {"entries": [], "week": current_week}

    # Liderboard
    entries = sorted(data.get("entries", []), key=lambda x: x.get("score", 0), reverse=True)
    if entries:
        st.markdown('<div style="color:#475569;font-size:.85rem;font-weight:600;margin-bottom:6px">'
                    'Liderboard:</div>', unsafe_allow_html=True)
        for i, e in enumerate(entries[:10]):
            medal = ["\U0001F947", "\U0001F948", "\U0001F949"][i] if i < 3 else f"{i+1}."
            st.markdown(
                f'<div style="display:flex;justify-content:space-between;background:#f0f9ff;'
                f'border-radius:8px;padding:6px 12px;margin:2px 0">'
                f'<span style="color:#1e293b;font-weight:600">{medal} {e.get("name","")}</span>'
                f'<span style="color:#0c4a6e;font-weight:700">{e.get("score",0)} puan</span></div>',
                unsafe_allow_html=True)

    st.markdown("---")
    player_name = st.text_input("Adınız:", key=f"{kp}_tour_name")

    gen_key = f"{kp}_tour_gen"
    q_key = f"{kp}_tour_q"

    if st.session_state.get(gen_key):
        with st.spinner("Turnuva soruları hazırlanıyor..."):
            client = _get_client()
            if client:
                try:
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"{ders} {seviye} seviye 5 zor soru uret. "
                             'JSON: {{"questions":[{{"question":"...","options":["A","B","C","D"],"correct":0}}]}}'},
                            {"role": "user", "content": "Turnuva soruları"},
                        ],
                        max_tokens=1200, temperature=0.8,
                        response_format={"type": "json_object"},
                    )
                    result = json.loads(resp.choices[0].message.content)
                    st.session_state[q_key] = result.get("questions", [])[:5]
                except Exception:
                    pass
            st.session_state[gen_key] = False
            st.rerun()

    if q_key not in st.session_state:
        def _start_tour():
            st.session_state[gen_key] = True
        st.button("\u2694\uFE0F Turnuvaya Katıl!", key=f"{kp}_tour_start",
                  use_container_width=True, type="primary", on_click=_start_tour,
                  disabled=not player_name)
        return

    questions = st.session_state[q_key]
    answers = {}
    for i, q in enumerate(questions):
        st.markdown(f'<div style="color:#1e293b;font-size:.9rem"><b>{i+1}.</b> '
                    f'{q.get("question","")}</div>', unsafe_allow_html=True)
        opts = q.get("options", [])
        sel = st.radio(":", opts, key=f"{kp}_tour_q{i}", index=None, label_visibility="collapsed")
        if sel is not None:
            answers[i] = opts.index(sel) if sel in opts else -1

    sub_key = f"{kp}_tour_sub"
    if not st.session_state.get(sub_key):
        def _tour_submit():
            score = sum(1 for i, q in enumerate(questions) if answers.get(i, -1) == q.get("correct", 0))
            score_pts = score * 20
            try:
                with open(p, "r", encoding="utf-8") as f:
                    td = json.load(f)
            except Exception:
                td = {"entries": [], "week": current_week}
            td["entries"].append({"name": player_name, "score": score_pts,
                                   "date": datetime.now().strftime("%Y-%m-%d %H:%M")})
            td["week"] = current_week
            with open(p, "w", encoding="utf-8") as f:
                json.dump(td, f, ensure_ascii=False, indent=2)
            st.session_state[sub_key] = True
            st.session_state[f"{kp}_tour_score"] = score_pts
        st.button("\u2705 Gönder", key=f"{kp}_tour_send",
                  use_container_width=True, type="primary", on_click=_tour_submit)
    else:
        pts = st.session_state.get(f"{kp}_tour_score", 0)
        st.success(f"Turnuva puanınız: {pts}! Liderboard güncellendi.")


