# G19 — ÖĞRENME STİLİ TESTİ
# ════════════════════════════════════════════════════════════
def _learning_style_path():
    return os.path.join(_data_dir(), "learning_style.json")

def render_learning_style_test(kp: str):
    """Görsel/İşitsel/Kinestetik öğrenme stili testi."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F9E0 Öğrenme Stili Testi</span></div>',
        unsafe_allow_html=True,
    )

    # Mevcut sonuç varsa göster
    p = _learning_style_path()
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                result = json.load(f)
            style = result.get("style", "")
            scores = result.get("scores", {})
            colors = {"Görsel": "#3b82f6", "İşitsel": "#22c55e", "Kinestetik": "#f59e0b"}
            st.markdown(
                f'<div style="background:#f0f9ff;border:2px solid {colors.get(style,"#6366F1")};'
                f'border-radius:14px;padding:16px;text-align:center">'
                f'<div style="color:{colors.get(style,"#6366F1")};font-size:1.3rem;font-weight:800">'
                f'Senin Stilin: {style}</div></div>', unsafe_allow_html=True)
            for s, v in scores.items():
                bar_w = min(100, v * 10)
                st.markdown(
                    f'<div style="display:flex;align-items:center;gap:8px;margin:4px 0">'
                    f'<span style="color:#1e293b;font-size:.85rem;min-width:80px">{s}</span>'
                    f'<div style="flex:1;background:#e2e8f0;border-radius:4px;height:8px">'
                    f'<div style="background:{colors.get(s,"#6366F1")};width:{bar_w}%;'
                    f'height:100%;border-radius:4px"></div></div>'
                    f'<span style="color:#475569;font-size:.8rem">{v}/10</span></div>',
                    unsafe_allow_html=True)
            def _retest():
                os.remove(p)
            st.button("\U0001F504 Tekrar Test Et", key=f"{kp}_ls_retest", on_click=_retest)
            return
        except Exception:
            pass

    # Test soruları
    questions = [
        ("Yeni bir şey öğrenirken tercih edersin:", "Resim/grafik", "Sesli anlatım", "Yaparak deneme"),
        ("Bir yeri hatırlarken:", "Görüntüsünü hatırlarsın", "Seslerini hatırlarsın", "Orada ne hissettiğini hatırlarsın"),
        ("Sınavda en iyi:", "Grafik/tablo soruları", "Sözel sorular", "Uygulama soruları"),
        ("Boş zamanında:", "Resim/video izlersin", "Müzik/podcast dinlersin", "Spor/el işi yaparsın"),
        ("Ders çalışırken:", "Not + şema çizersin", "Sesli tekrar edersin", "Yürüyerek çalışırsın"),
        ("En iyi öğrendiğin:", "Video izleyerek", "Birisi anlatınca", "Kendin deneyince"),
        ("Bir hikayeyi anlatırken:", "Betimleyici konuşursun", "Diyalogları kullanırsın", "Jestlerle anlatırsın"),
        ("Yönerge alırken:", "Yazılı tercih edersin", "Sözlü tercih edersin", "Gösterilmesini istersin"),
        ("Konsantre olmak için:", "Sessiz ve düzenli ortam", "Hafif müzik", "Hareket edebilmek"),
        ("Hatırlamak için:", "Listeler yaparsın", "Kafanda tekrarlarsın", "Pratik yaparsın"),
    ]

    answers = {}
    for i, (q, a, b, cc) in enumerate(questions):
        st.markdown(f'<div style="color:#1e293b;font-weight:600;font-size:.9rem;margin-top:6px">'
                    f'{i+1}. {q}</div>', unsafe_allow_html=True)
        sel = st.radio(":", [a, b, cc], key=f"{kp}_ls_q{i}", index=None, label_visibility="collapsed")
        if sel == a:
            answers[i] = "Görsel"
        elif sel == b:
            answers[i] = "İşitsel"
        elif sel == cc:
            answers[i] = "Kinestetik"

    if len(answers) == len(questions):
        def _submit_ls():
            scores = {"Görsel": 0, "İşitsel": 0, "Kinestetik": 0}
            for v in answers.values():
                scores[v] += 1
            dominant = max(scores, key=scores.get)
            with open(p, "w", encoding="utf-8") as f:
                json.dump({"style": dominant, "scores": scores,
                           "date": datetime.now().strftime("%Y-%m-%d")}, f, ensure_ascii=False)
        st.button("\u2705 Sonucu Gör", key=f"{kp}_ls_submit",
                  use_container_width=True, type="primary", on_click=_submit_ls)


# ════════════════════════════════════════════════════════════
# G20 — MIND PALACE (Hafıza Sarayı)
# ════════════════════════════════════════════════════════════
def render_mind_palace(lesson_data: dict, kp: str):
    """3D oda konseptinde kavram yerleştirme."""
    import streamlit.components.v1 as components
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F3F0 Hafıza Sarayı</span></div>',
        unsafe_allow_html=True,
    )

    vocab = lesson_data.get("vocabulary", [])[:8]
    vocab_js = json.dumps([{"term": v.get("term", ""), "def": v.get("definition", "")}
                            for v in vocab], ensure_ascii=False)

    palace_html = f"""<!DOCTYPE html><html><head><meta charset="utf-8"><style>
    body{{margin:0;background:#f0f9ff;overflow:hidden}}canvas{{display:block;margin:0 auto;cursor:pointer}}
    </style></head><body><canvas id="c" width="560" height="400"></canvas>
    <script>
    var cv=document.getElementById('c'),c=cv.getContext('2d'),W=cv.width,H=cv.height;
    var vocab={vocab_js},hovered=-1;
    var spots=[
      {{x:80,y:80,label:'Kapı'}},{{x:480,y:80,label:'Pencere'}},
      {{x:80,y:200,label:'Masa'}},{{x:480,y:200,label:'Koltuk'}},
      {{x:200,y:320,label:'Kitaplık'}},{{x:360,y:320,label:'Lamba'}},
      {{x:280,y:140,label:'Tablo'}},{{x:280,y:260,label:'Halı'}}
    ];
    function draw(){{
      c.fillStyle='#0B0F19';c.fillRect(0,0,W,H);
      // Oda
      c.strokeStyle='#334155';c.lineWidth=2;
      c.strokeRect(40,40,W-80,H-80);
      c.beginPath();c.moveTo(0,0);c.lineTo(40,40);c.stroke();
      c.beginPath();c.moveTo(W,0);c.lineTo(W-40,40);c.stroke();
      c.beginPath();c.moveTo(0,H);c.lineTo(40,H-40);c.stroke();
      c.beginPath();c.moveTo(W,H);c.lineTo(W-40,H-40);c.stroke();
      // Spotlar
      for(var i=0;i<Math.min(spots.length,vocab.length);i++){{
        var s=spots[i],v=vocab[i],isH=hovered===i;
        var r=isH?28:20;
        c.fillStyle=isH?'rgba(212,175,55,0.3)':'rgba(59,130,246,0.15)';
        c.beginPath();c.arc(s.x,s.y,r+8,0,Math.PI*2);c.fill();
        c.fillStyle=isH?'#6366F1':'#3b82f6';
        c.beginPath();c.arc(s.x,s.y,r,0,Math.PI*2);c.fill();
        c.fillStyle='#fff';c.font=(isH?'bold 10px':'9px')+' system-ui';
        c.textAlign='center';c.textBaseline='middle';
        c.fillText(v.term.substring(0,10),s.x,s.y);
        c.fillStyle='#64748b';c.font='8px system-ui';
        c.fillText(s.label,s.x,s.y+r+12);
      }}
      // Hover info
      if(hovered>=0&&hovered<vocab.length){{
        var v2=vocab[hovered];
        c.fillStyle='rgba(15,23,42,0.95)';
        c.fillRect(W/2-140,H-60,280,50);
        c.strokeStyle='#6366F1';c.strokeRect(W/2-140,H-60,280,50);
        c.fillStyle='#6366F1';c.font='bold 12px system-ui';c.textAlign='center';
        c.fillText(v2.term,W/2,H-42);
        c.fillStyle='#94a3b8';c.font='10px system-ui';
        c.fillText(v2.def.substring(0,50),W/2,H-24);
      }}
    }}
    cv.addEventListener('mousemove',function(e){{
      var r=cv.getBoundingClientRect();var mx=e.clientX-r.left,my=e.clientY-r.top;
      hovered=-1;
      for(var i=0;i<Math.min(spots.length,vocab.length);i++)
        if(Math.hypot(mx-spots[i].x,my-spots[i].y)<28)hovered=i;
      draw();
    }});
    draw();
    </script></body></html>"""
    components.html(palace_html, height=420, scrolling=False)
    st.markdown('<div style="color:#475569;font-size:.8rem;text-align:center">'
                'Her kavram odadaki bir nesneye bağlı — üzerine gelin</div>',
                unsafe_allow_html=True)


# ════════════════════════════════════════════════════════════
# G21 — AI PROJE ÖDEVİ ÜRETİCİ
# ════════════════════════════════════════════════════════════
def render_project_generator(ders: str, seviye: str, kp: str):
    """Konuya özel araştırma projesi + rubrik üret."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4DD AI Proje Ödevi</span></div>',
        unsafe_allow_html=True,
    )

    topic = st.text_input("Proje Konusu:", key=f"{kp}_proj_topic",
                           placeholder="Örn: Yenilenebilir enerji kaynakları")

    gen_key = f"{kp}_proj_gen"
    result_key = f"{kp}_proj_result"

    if st.session_state.get(gen_key):
        with st.spinner("AI proje ödevi hazırlıyor..."):
            client = _get_client()
            if client:
                try:
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content":
                             f"Sen {ders} ogretmenisin. {seviye} seviyesinde bir arastirma projesi hazirla:\n"
                             "1. Proje Basligi\n2. Amac (2 cumle)\n3. Arastirma Sorulari (3 soru)\n"
                             "4. Yontem (nasil arastirilacak)\n5. Beklenen Ciktilar (sunum/poster/rapor)\n"
                             "6. Degerlendirme Kriterleri (4 kriter, her biri 25 puan)\n"
                             "7. Teslim Suresi onerisi\nTurkce yaz."},
                            {"role": "user", "content": f"Konu: {topic}"},
                        ],
                        max_tokens=600, temperature=0.7,
                    )
                    st.session_state[result_key] = resp.choices[0].message.content
                except Exception as e:
                    st.session_state[result_key] = f"Hata: {e}"
            st.session_state[gen_key] = False
            st.rerun()

    if result_key in st.session_state:
        st.markdown(
            f'<div style="background:#f0f9ff;border:1px solid #93c5fd;'
            f'border-radius:12px;padding:14px"><div style="color:#1e293b;font-size:.9rem;'
            f'white-space:pre-wrap;line-height:1.6">{st.session_state[result_key]}</div></div>',
            unsafe_allow_html=True)
    else:
        def _gen_proj():
            st.session_state[gen_key] = True
        st.button("\U0001F4DD Proje Oluştur", key=f"{kp}_proj_btn",
                  use_container_width=True, type="primary", on_click=_gen_proj,
                  disabled=not topic.strip() if isinstance(topic, str) else True)


