# G22 — SOSYAL ÖĞRENME DUVARI
# ════════════════════════════════════════════════════════════
def _wall_path():
    return os.path.join(_data_dir(), "social_wall.json")

def render_social_wall(ders: str, kp: str):
    """Öğrenciler arası not/soru/ipucu paylaşım duvarı."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F4AC Sosyal Öğrenme Duvarı</span></div>',
        unsafe_allow_html=True,
    )

    p = _wall_path()
    posts = []
    if os.path.exists(p):
        try:
            with open(p, "r", encoding="utf-8") as f:
                posts = json.load(f)
        except Exception:
            pass

    c1, c2 = st.columns([3, 1])
    with c1:
        author = st.text_input("Adın:", key=f"{kp}_wall_author", placeholder="İsim")
    with c2:
        ptype = st.selectbox("Tür:", ["💡 İpucu", "❓ Soru", "📝 Not"], key=f"{kp}_wall_type")

    content = st.text_area("İçerik:", key=f"{kp}_wall_content", height=60,
                            placeholder="Paylaşmak istediğiniz not/soru/ipucu...")

    if content and author:
        def _post():
            all_p = []
            if os.path.exists(p):
                try:
                    with open(p, "r", encoding="utf-8") as f:
                        all_p = json.load(f)
                except Exception:
                    pass
            all_p.append({
                "author": author, "type": ptype, "content": content,
                "ders": ders, "likes": 0,
                "date": datetime.now().strftime("%Y-%m-%d %H:%M"),
            })
            with open(p, "w", encoding="utf-8") as f:
                json.dump(all_p[-100:], f, ensure_ascii=False, indent=2)
        st.button("\U0001F4E8 Paylaş", key=f"{kp}_wall_post",
                  type="primary", on_click=_post)

    # Duvar gönderileri
    ders_posts = [pp for pp in posts if pp.get("ders") == ders][-15:]
    for pp in reversed(ders_posts):
        st.markdown(
            f'<div style="border-left:3px solid #3b82f6;background:#f0f9ff;'
            f'border-radius:0 8px 8px 0;padding:8px 12px;margin:3px 0">'
            f'<div style="display:flex;justify-content:space-between">'
            f'<span style="color:#0c4a6e;font-weight:600;font-size:.85rem">'
            f'{pp.get("author","")} {pp.get("type","")}</span>'
            f'<span style="color:#64748b;font-size:.7rem">{pp.get("date","")}</span></div>'
            f'<div style="color:#1e293b;font-size:.85rem;margin-top:2px">'
            f'{pp.get("content","")}</div></div>',
            unsafe_allow_html=True)


