    mood = st.select_slider("Bugün nasıl hissediyorsun?",
                             options=["Çok Kötü", "Kötü", "Normal", "İyi", "Harika"],
                             value="Normal", key=f"{kp}_mood")

    gen_key = f"{kp}_motiv_gen"
    result_key = f"{kp}_motiv_result"

    if st.session_state.get(gen_key):
        with st.spinner("Koçun sana mesaj hazırlıyor..."):
            client = _get_client()
