# ── O1: AI Ders Asistanı Chat Bot ──
def render_ai_chatbot(topic: str, kp: str = "_prem_"):
    """Sınırsız bağlamsal AI sohbet — geçmiş dersleri hatırlar."""
    st.markdown('<div style="background:linear-gradient(135deg,#f5f3ff,#ede9fe);border:2px solid rgba(139,92,246,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#a78bfa;margin:0">🤖 AI Ders Asistanı</h4></div>',
                unsafe_allow_html=True)
    hist_key = f"{kp}chatbot_hist"
    if hist_key not in st.session_state:
        st.session_state[hist_key] = []
    history = st.session_state[hist_key]
    # Gösterim
    chat_html = ""
    for msg in history[-20:]:
        if msg["role"] == "user":
            chat_html += (f'<div style="text-align:right;margin:6px 0"><span style="background:#3b82f6;color:#fff;'
                          f'padding:8px 14px;border-radius:16px 16px 4px 16px;display:inline-block;max-width:80%;'
                          f'font-size:.9rem">{msg["content"]}</span></div>')
        else:
            chat_html += (f'<div style="text-align:left;margin:6px 0"><span style="background:#e2e8f0;color:#1e293b;'
                          f'border:1px solid rgba(139,92,246,0.3);padding:8px 14px;border-radius:16px 16px 16px 4px;'
                          f'display:inline-block;max-width:80%;font-size:.9rem">{msg["content"]}</span></div>')
    if chat_html:
        st.markdown(f'<div style="max-height:400px;overflow-y:auto;padding:10px;background:#111827;'
                    f'border-radius:12px;margin:10px 0">{chat_html}</div>', unsafe_allow_html=True)
    send_key = f"{kp}chatbot_send"
    gen_key = f"{kp}chatbot_gen"
    inp = st.text_input("Sorunuzu yazın...", key=f"{kp}chatbot_inp",
                        placeholder="Herhangi bir soru sorun...")
    if st.session_state.get(gen_key):
        with st.spinner("AI düşünüyor..."):
            try:
                client = _get_client()
                msgs = [{"role": "system",
                         "content": f"Sen '{topic}' konusunda uzman bir ogretmensin. Turkce cevap ver. "
                                    f"Acik, anlasilir ve ogrenci seviyesinde acikla."}]
                for m in history[-10:]:
                    msgs.append({"role": m["role"], "content": m["content"]})
                resp = client.chat.completions.create(model="gpt-4o-mini", messages=msgs,
                                                     max_tokens=500, temperature=0.7)
                answer = resp.choices[0].message.content
                history.append({"role": "assistant", "content": answer})
            except Exception as e:
                history.append({"role": "assistant", "content": f"Hata: {e}"})
        st.session_state[gen_key] = False
        st.rerun()

    def _send_chat():
        val = st.session_state.get(f"{kp}chatbot_inp", "").strip()
        if val:
            st.session_state[hist_key].append({"role": "user", "content": val})
            st.session_state[gen_key] = True
    st.button("📨 Gönder", key=send_key, on_click=_send_chat, type="primary")
    if history:
        def _clear_chat():
            st.session_state[hist_key] = []
        st.button("🗑️ Sohbeti Temizle", key=f"{kp}chatbot_clear", on_click=_clear_chat)


