# ── O6: Ders Karşılaştırma Matrisi ──
def render_comparison_matrix(topic: str, kp: str = "_prem_"):
    """Birden fazla kavramı matris formatında karşılaştırır."""
    st.markdown('<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);border:2px solid rgba(6,182,212,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#22d3ee;margin:0">📊 Karşılaştırma Matrisi</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}matrix_gen"
    result_key = f"{kp}matrix_result"
    if st.session_state.get(gen_key):
        with st.spinner("Karşılaştırma matrisi oluşturuluyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyla ilgili 3-5 kavram icin karsilastirma matrisi olustur. "
                                                      "JSON: {\"title\":\"baslik\",\"headers\":[\"Ozellik\",\"K1\",\"K2\",\"K3\"],"
                                                      "\"rows\":[[\"ozellik\",\"deger1\",\"deger2\",\"deger3\"]]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=800, temperature=0.5,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        title = data.get("title", "Karşılaştırma")
        headers = data.get("headers", [])
        rows = data.get("rows", [])
        th_html = "".join(f'<th style="background:#1e40af;color:#fff;padding:10px 14px;font-size:.85rem">{h}</th>' for h in headers)
        rows_html = ""
        for i, row in enumerate(rows):
            bg = "rgba(30,41,59,0.5)" if i % 2 == 0 else "rgba(15,23,42,0.5)"
            cells = "".join(f'<td style="padding:8px 12px;color:#1e293b;font-size:.85rem;border-bottom:1px solid rgba(100,116,139,0.2)">{c}</td>' for c in row)
            rows_html += f'<tr style="background:{bg}">{cells}</tr>'
        st.markdown(f'<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;'
                    f'border-radius:12px;overflow:hidden;border:1px solid rgba(6,182,212,0.3)">'
                    f'<thead><tr>{th_html}</tr></thead><tbody>{rows_html}</tbody></table></div>',
                    unsafe_allow_html=True)
        def _new_matrix():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Matris", key=f"{kp}matrix_new", on_click=_new_matrix)
    else:
        def _gen_matrix():
            st.session_state[gen_key] = True
        st.button("📊 Matris Oluştur", key=f"{kp}matrix_btn", type="primary",
                  use_container_width=True, on_click=_gen_matrix)


