# ── S7: AI Sınav Tahmini ──
def render_exam_prediction(topic: str, kp: str = "_prem_"):
    """Geçmiş performanstan sınav notu tahmini."""
    st.markdown('<div style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);border:2px solid rgba(132,204,22,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#a3e635;margin:0">🔮 Sınav Tahmini</h4></div>',
                unsafe_allow_html=True)
    c1, c2, c3 = st.columns(3)
    quiz_scores = c1.number_input("Quiz Ortalaması (0-100)", 0, 100, 70, key=f"{kp}pred_quiz")
    hw_scores = c2.number_input("Ödev Ortalaması (0-100)", 0, 100, 75, key=f"{kp}pred_hw")
    study_hrs = c3.number_input("Haftalık Çalışma (saat)", 0, 40, 10, key=f"{kp}pred_hrs")
    gen_key = f"{kp}pred_gen"
    result_key = f"{kp}pred_result"
    if st.session_state.get(gen_key):
        with st.spinner("Tahmin hesaplanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Egitim analisti olarak sinav notu tahmini yap. "
                                                      "JSON: {\"predicted_score\":85,\"confidence\":\"Yuksek\","
                                                      "\"strengths\":[\"guclu yanlar\"],\"weaknesses\":[\"zayif yanlar\"],"
                                                      "\"tips\":[\"tavsiyeler\"]}"},
                        {"role": "user", "content": f"Konu: {topic}, Quiz ort: {quiz_scores}, "
                                                    f"Odev ort: {hw_scores}, Haftalik calisma: {study_hrs} saat"},
                    ], max_tokens=400, temperature=0.5,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        pred = data.get("predicted_score", 0)
        color = "#22c55e" if pred >= 70 else "#f59e0b" if pred >= 50 else "#ef4444"
        st.markdown(f'<div style="text-align:center;background:#f0f9ff;border-radius:16px;padding:24px;'
                    f'border:2px solid {color}40">'
                    f'<div style="font-size:4rem;color:{color};font-weight:bold">{pred}</div>'
                    f'<div style="color:#475569">Tahmini Sınav Notu</div>'
                    f'<div style="color:{color};font-size:.9rem;margin-top:4px">Güven: {data.get("confidence","")}</div>'
                    f'</div>', unsafe_allow_html=True)
        c1, c2 = st.columns(2)
        with c1:
            st.markdown("**💪 Güçlü Yanlar**")
            for s in data.get("strengths", []):
                st.markdown(f"- ✅ {s}")
        with c2:
            st.markdown("**⚠️ Geliştirilmeli**")
            for w in data.get("weaknesses", []):
                st.markdown(f"- 📌 {w}")
        st.markdown("**💡 Tavsiyeler**")
        for t in data.get("tips", []):
            st.markdown(f"- 🎯 {t}")
        def _reset_pred():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeniden Hesapla", key=f"{kp}pred_new", on_click=_reset_pred)
    else:
        def _gen_pred():
            st.session_state[gen_key] = True
        st.button("🔮 Tahmin Et", key=f"{kp}pred_btn", type="primary",
                  use_container_width=True, on_click=_gen_pred)


# ── S8: Sesli Kitap Modu ──
def render_audiobook(topic: str, kp: str = "_prem_"):
    """Bölüm bölüm sesli kitap."""
    st.markdown('<div style="background:linear-gradient(135deg,#fdf2f8,#fce7f3);border:2px solid rgba(236,72,153,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#f472b6;margin:0">🎧 Sesli Kitap</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}audiobook_gen"
    chapters_key = f"{kp}audiobook_chapters"
    ch_idx_key = f"{kp}audiobook_idx"
    audio_key = f"{kp}audiobook_audio"
    if st.session_state.get(gen_key):
        with st.spinner("Bölümler hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyu 4 bolume ayir. JSON: {\"chapters\":[{\"title\":\"Bolum 1: ...\","
                                                      "\"content\":\"bolum icerigi (3-4 paragraf)\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=1200, temperature=0.6,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                st.session_state[chapters_key] = data.get("chapters", [])
                st.session_state[ch_idx_key] = 0
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    chapters = st.session_state.get(chapters_key, [])
    if not chapters:
        def _gen_ab():
            st.session_state[gen_key] = True
        st.button("🎧 Sesli Kitap Oluştur", key=f"{kp}ab_btn", type="primary",
                  use_container_width=True, on_click=_gen_ab)
        return
    idx = st.session_state.get(ch_idx_key, 0)
    ch = chapters[idx]
    # Bölüm navigasyonu
    cols = st.columns(len(chapters))
    for i, c in enumerate(chapters):
        def _goto_ch(ci=i):
            st.session_state[ch_idx_key] = ci
            st.session_state.pop(audio_key, None)
        style = "primary" if i == idx else "secondary"
        cols[i].button(f"📖 {i+1}", key=f"{kp}ab_ch_{i}", on_click=_goto_ch,
                       type=style, use_container_width=True)
    st.markdown(f'<div style="background:#f0f9ff;border-radius:12px;padding:16px;border:1px solid rgba(236,72,153,0.3)">'
                f'<h5 style="color:#f472b6">{ch.get("title","")}</h5>'
                f'<div style="color:#1e293b;line-height:1.8;font-size:.92rem">{ch.get("content","")}</div></div>',
                unsafe_allow_html=True)
    # TTS
    if audio_key in st.session_state:
        st.audio(st.session_state[audio_key], format="audio/mp3")
    else:
        def _tts_ch():
            try:
                audio_data = ai_generate_tts(ch.get("content", ""), voice="nova")
                st.session_state[audio_key] = audio_data
            except Exception:
                pass
        st.button("🔊 Seslendir", key=f"{kp}ab_tts_{idx}", on_click=_tts_ch)


# ── S9: Kelime Bulutu (Word Cloud) ──
def render_word_cloud(topic: str, kp: str = "_prem_"):
    """Ders içeriğinden interaktif kelime bulutu."""
    st.markdown('<div style="background:linear-gradient(135deg,#f0fdfa,#ccfbf1);border:2px solid rgba(20,184,166,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#2dd4bf;margin:0">☁️ Kelime Bulutu</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}wcloud_gen"
    result_key = f"{kp}wcloud_result"
    if st.session_state.get(gen_key):
        with st.spinner("Kelime bulutu oluşturuluyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyla ilgili 30 anahtar kelime ve onem agirligini ver. "
                                                      "JSON: {\"words\":[{\"text\":\"kelime\",\"weight\":5}]} "
                                                      "weight 1-10 arasi."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=400, temperature=0.6,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        words = data.get("words", [])
        # Canvas word cloud
        words_js = json.dumps(words)
        html = f"""<canvas id="wcCanvas" width="700" height="400" style="background:#f0f9ff;border-radius:12px;
                   border:1px solid rgba(20,184,166,0.3);width:100%"></canvas>
        <script>
        const canvas=document.getElementById('wcCanvas'),ctx=canvas.getContext('2d');
        const words={words_js};
        const colors=['#22d3ee','#a78bfa','#f472b6','#fbbf24','#4ade80','#f87171','#38bdf8','#c084fc'];
        let placed=[];
        words.sort((a,b)=>b.weight-a.weight);
        words.forEach((w,i)=>{{
            const size=Math.max(12,w.weight*5);
            ctx.font=size+'px Arial';
            const tw=ctx.measureText(w.text).width;
            let x,y,ok,tries=0;
            do{{
                x=Math.random()*(700-tw-20)+10;
                y=Math.random()*(400-size-20)+size+10;
                ok=true;
                for(let p of placed){{
                    if(x<p.x+p.w+4&&x+tw+4>p.x&&y-size<p.y&&y>p.y-p.h-4){{ok=false;break;}}
                }}
                tries++;
            }}while(!ok&&tries<50);
            ctx.fillStyle=colors[i%colors.length];
            ctx.globalAlpha=0.85;
            ctx.fillText(w.text,x,y);
            placed.push({{x,y,w:tw,h:size}});
        }});
        </script>"""
        import streamlit.components.v1 as components
        components.html(html, height=420)
        def _new_wc():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Bulut", key=f"{kp}wcloud_new", on_click=_new_wc)
    else:
        def _gen_wc():
            st.session_state[gen_key] = True
        st.button("☁️ Bulut Oluştur", key=f"{kp}wcloud_btn", type="primary",
                  use_container_width=True, on_click=_gen_wc)


# ── S10: Zaman Makinesi ──
def render_time_machine(topic: str, kp: str = "_prem_"):
    """Geçmiş derslere geri dönme arayüzü."""
    st.markdown('<div style="background:linear-gradient(135deg,#fffbeb,#fef3c7);border:2px solid rgba(251,191,36,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#92400e;margin:0">⏰ Zaman Makinesi</h4></div>',
                unsafe_allow_html=True)
    lessons = load_saved_lessons()
    if not lessons:
        st.info("Henüz kaydedilmiş ders yok. Ders işledikten sonra burada görünecek.")
        return
    # Tarihe göre sırala
    sorted_lessons = sorted(lessons, key=lambda x: x.get("timestamp", ""), reverse=True)
    timeline_html = ""
    for i, ls in enumerate(sorted_lessons[:20]):
        ts = ls.get("timestamp", "")[:16].replace("T", " ")
        subj = ls.get("subject", "")
        tp = ls.get("topic", "")
        diff = ls.get("difficulty", "")
        timeline_html += (f'<div style="display:flex;align-items:center;margin:8px 0">'
                          f'<div style="width:12px;height:12px;border-radius:50%;background:#fbbf24;'
                          f'margin-right:12px;flex-shrink:0"></div>'
                          f'<div style="background:#e2e8f0;padding:10px 16px;border-radius:10px;flex:1;'
                          f'border-left:3px solid #fbbf24">'
                          f'<div style="color:#92400e;font-size:.8rem">{ts}</div>'
                          f'<div style="color:#1e293b;font-weight:bold;font-size:.9rem">{tp}</div>'
                          f'<div style="color:#475569;font-size:.8rem">{subj} • {diff}</div>'
                          f'</div></div>')
    st.markdown(f'<div style="border-left:2px solid rgba(251,191,36,0.3);margin-left:6px;padding-left:0;'
                f'max-height:500px;overflow-y:auto">{timeline_html}</div>', unsafe_allow_html=True)
    st.caption(f"Toplam {len(lessons)} ders kaydı")


# ── S11: AI Debate (Tartışma) ──
def render_ai_debate(topic: str, kp: str = "_prem_"):
    """AI ile münazara / tartışma — eleştirel düşünme."""
    st.markdown('<div style="background:linear-gradient(135deg,#fef2f2,#fee2e2);border:2px solid rgba(244,63,94,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#fb7185;margin:0">⚔️ AI Tartışma</h4></div>',
                unsafe_allow_html=True)
    hist_key = f"{kp}debate_hist"
    side_key = f"{kp}debate_side"
    gen_key = f"{kp}debate_gen"
    if hist_key not in st.session_state:
        st.session_state[hist_key] = []
    side = st.radio("Sizin tarafınız:", ["Lehte (Destekliyorum)", "Aleyhte (Karşıyım)"],
                    key=side_key, horizontal=True)
    ai_side = "aleyhte" if "Lehte" in side else "lehte"
    history = st.session_state[hist_key]
    if history:
        for msg in history:
            if msg["role"] == "user":
                st.markdown(f'<div style="text-align:right;margin:8px 0"><span style="background:#3b82f6;'
                            f'color:#fff;padding:8px 14px;border-radius:14px 14px 4px 14px;display:inline-block;'
                            f'max-width:80%;font-size:.9rem">🧑 {msg["content"]}</span></div>',
                            unsafe_allow_html=True)
            else:
                st.markdown(f'<div style="text-align:left;margin:8px 0"><span style="background:#e2e8f0;'
                            f'color:#1e293b;border:1px solid rgba(244,63,94,0.3);padding:8px 14px;'
                            f'border-radius:14px 14px 14px 4px;display:inline-block;max-width:80%;font-size:.9rem">'
                            f'🤖 {msg["content"]}</span></div>', unsafe_allow_html=True)
    if st.session_state.get(gen_key):
        with st.spinner("AI argüman hazırlıyor..."):
            try:
                client = _get_client()
                msgs = [{"role": "system",
                         "content": f"Sen bir munazara yapay zekasisin. '{topic}' konusunda {ai_side} argumanlar "
                                    f"sun. Kisa, etkili, mantikli argumanlar ver. Turkce. 2-3 cumle."}]
                for m in history[-8:]:
                    msgs.append({"role": m["role"], "content": m["content"]})
                resp = client.chat.completions.create(model="gpt-4o-mini", messages=msgs,
                                                     max_tokens=200, temperature=0.7)
                history.append({"role": "assistant", "content": resp.choices[0].message.content})
            except Exception as e:
                history.append({"role": "assistant", "content": f"Hata: {e}"})
        st.session_state[gen_key] = False
        st.rerun()
    arg_input = st.text_input("Argümanınızı yazın...", key=f"{kp}debate_inp",
                              placeholder="Neden böyle düşünüyorsunuz?")
    def _send_debate():
        val = st.session_state.get(f"{kp}debate_inp", "").strip()
        if val:
            st.session_state[hist_key].append({"role": "user", "content": val})
            st.session_state[gen_key] = True
    c1, c2 = st.columns([3, 1])
    c1.button("⚔️ Argüman Gönder", key=f"{kp}debate_send", on_click=_send_debate, type="primary")
    def _clear_debate():
        st.session_state[hist_key] = []
    c2.button("🗑️ Sıfırla", key=f"{kp}debate_clear", on_click=_clear_debate)


