# ── I13: Çoklu Zeka Profili ──
def render_multiple_intelligence(topic: str, kp: str = "_prem_"):
    """Gardner'ın 8 zeka türü testi."""
    st.markdown('<div style="background:linear-gradient(135deg,#f5f3ff,#fce7f3);border:2px solid rgba(217,70,239,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#e879f9;margin:0">🧠 Çoklu Zeka Profili</h4></div>',
                unsafe_allow_html=True)
    result_key = f"{kp}mi_result"
    phase_key = f"{kp}mi_phase"
    ans_key = f"{kp}mi_answers"

    intelligences = [
        ("Sözel-Dilsel", "📝", "#3b82f6"),
        ("Mantıksal-Matematiksel", "🔢", "#8b5cf6"),
        ("Görsel-Uzamsal", "🎨", "#ec4899"),
        ("Müziksel", "🎵", "#f59e0b"),
        ("Bedensel-Kinestetik", "🏃", "#10b981"),
        ("Kişilerarası", "👥", "#06b6d4"),
        ("İçsel", "🧘", "#ef4444"),
        ("Doğacı", "🌿", "#84cc16"),
    ]
    questions = [
        ("Kitap okumak ve yazmak benim için çok keyifli.", 0),
        ("Sayılarla ve mantık bulmacalarıyla uğraşmayı severim.", 1),
        ("Görsel sunumlar ve haritalar bana çok yardımcı olur.", 2),
        ("Müzik dinlerken ya da çalarken çok mutlu olurum.", 3),
        ("Hareket etmek ve spor yapmak benim için önemli.", 4),
        ("Grup çalışmaları ve sosyal etkinlikleri tercih ederim.", 5),
        ("Kendi başıma düşünmek ve plan yapmak benim için kolay.", 6),
        ("Doğada zaman geçirmek beni rahatlatır.", 7),
        ("Kelimeleri ve dilleri hızlı öğrenirim.", 0),
        ("Problemleri adım adım çözmek hoşuma gider.", 1),
        ("Resim çizmek veya tasarım yapmak benim için eğlenceli.", 2),
        ("Ritimleri ve melodileri kolayca hatırlarım.", 3),
        ("El becerileri ve deneyler yapmayı severim.", 4),
        ("İnsanları anlamak ve empati kurmak güçlü yanlarım.", 5),
        ("Günlük tutmak ve kendimi analiz etmek bana iyi gelir.", 6),
        ("Hayvanlar ve bitkilerle ilgilenmeyi severim.", 7),
    ]
    phase = st.session_state.get(phase_key, "test")
    if phase == "test":
        if ans_key not in st.session_state:
            st.session_state[ans_key] = {}
        st.info("Her ifadeyi 1 (Hiç katılmıyorum) - 5 (Kesinlikle katılıyorum) arasında değerlendirin.")
        all_answered = True
        for i, (q, _) in enumerate(questions):
            val = st.slider(q, 1, 5, 3, key=f"{kp}mi_q{i}")
            st.session_state[ans_key][i] = val
        def _calc_mi():
            scores = [0] * 8
            answers = st.session_state[ans_key]
            for i, (_, cat) in enumerate(questions):
                scores[cat] += answers.get(i, 3)
            max_score = max(scores) if scores else 1
            st.session_state[result_key] = [round(s / max_score * 100) for s in scores]
            st.session_state[phase_key] = "result"
        st.button("📊 Profilimi Göster", key=f"{kp}mi_calc", type="primary",
                  use_container_width=True, on_click=_calc_mi)
    elif phase == "result":
        scores = st.session_state.get(result_key, [50]*8)
        bars_html = ""
        for i, (name, emoji, color) in enumerate(intelligences):
            sc = scores[i] if i < len(scores) else 50
            bars_html += (f'<div style="margin:6px 0;display:flex;align-items:center">'
                          f'<div style="width:200px;color:#1e293b;font-size:.85rem">{emoji} {name}</div>'
                          f'<div style="flex:1;background:#e2e8f0;border-radius:8px;height:24px;margin:0 8px">'
                          f'<div style="background:{color};width:{sc}%;height:100%;border-radius:8px;'
                          f'transition:width 1s"></div></div>'
                          f'<div style="color:{color};font-weight:bold;width:40px">{sc}%</div></div>')
        st.markdown(f'<div style="background:#f0f9ff;border-radius:12px;padding:16px;'
                    f'border:1px solid rgba(217,70,239,0.3)">{bars_html}</div>', unsafe_allow_html=True)
        # En güçlü 3
        top3 = sorted(range(8), key=lambda i: scores[i] if i < len(scores) else 0, reverse=True)[:3]
        st.markdown("**🏆 En Güçlü Zeka Alanlarınız:**")
        for rank, idx in enumerate(top3, 1):
            name, emoji, _ = intelligences[idx]
            st.markdown(f"{rank}. {emoji} **{name}** — %{scores[idx]}")
        def _reset_mi():
            for k in [result_key, phase_key, ans_key]:
                st.session_state.pop(k, None)
        st.button("🔄 Tekrar Test Et", key=f"{kp}mi_reset", on_click=_reset_mi)


