# ── I17: AI Soru Bankası Üretici ──
def render_question_bank_generator(topic: str, kp: str = "_prem_"):
    """20-50 soru üret, PDF export."""
    st.markdown('<div style="background:linear-gradient(135deg,#0a2e0a,#1a2e1a);border:2px solid rgba(34,197,94,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#4ade80;margin:0">📝 Soru Bankası Üretici</h4></div>',
                unsafe_allow_html=True)
    count = st.slider("Soru Sayısı", 10, 50, 20, step=5, key=f"{kp}qbank_count")
    diff = st.selectbox("Zorluk", ["Kolay", "Orta", "Zor", "Karışık"], key=f"{kp}qbank_diff")
    gen_key = f"{kp}qbank_gen"
    result_key = f"{kp}qbank_result"
    if st.session_state.get(gen_key):
        with st.spinner(f"{count} soru üretiliyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": f"{count} adet {diff} seviye test sorusu olustur. "
                                                      f"JSON: {{\"questions\":[{{\"q\":\"soru\",\"options\":[\"A\",\"B\",\"C\",\"D\"],"
                                                      f"\"answer\":0,\"explanation\":\"aciklama\"}}]}}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=3000, temperature=0.7,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                st.session_state[result_key] = data.get("questions", [])
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    questions = st.session_state.get(result_key, [])
    if questions:
        st.success(f"{len(questions)} soru üretildi!")
        for i, q in enumerate(questions):
            with st.expander(f"Soru {i+1}: {q.get('q','')}"):
                opts = q.get("options", [])
                ans = q.get("answer", 0)
                for j, opt in enumerate(opts):
                    prefix = "✅" if j == ans else "  "
                    st.markdown(f"{prefix} **{chr(65+j)})** {opt}")
                if q.get("explanation"):
                    st.info(f"💡 {q['explanation']}")
        # PDF export
        def _export_qbank():
            try:
                from reportlab.lib.pagesizes import A4
                from reportlab.pdfgen import canvas as pdf_canvas
                from reportlab.lib.units import mm
                from reportlab.pdfbase import pdfmetrics
                from reportlab.pdfbase.ttfonts import TTFont
                import tempfile
                pdf_path = os.path.join(tempfile.gettempdir(), "soru_bankasi.pdf")
                c = pdf_canvas.Canvas(pdf_path, pagesize=A4)
                w, h = A4
                y = h - 40*mm
                c.setFont("Helvetica-Bold", 16)
                c.drawString(30*mm, y, f"Soru Bankasi - {topic}")
                y -= 15*mm
                c.setFont("Helvetica", 10)
                for i, q in enumerate(questions):
                    if y < 40*mm:
                        c.showPage()
                        y = h - 30*mm
                        c.setFont("Helvetica", 10)
                    c.setFont("Helvetica-Bold", 10)
                    c.drawString(15*mm, y, f"Soru {i+1}:")
                    y -= 5*mm
                    c.setFont("Helvetica", 9)
                    # Wrap text
                    text = q.get("q", "")
                    if len(text) > 90:
                        c.drawString(15*mm, y, text[:90])
                        y -= 4*mm
                        c.drawString(15*mm, y, text[90:180])
                    else:
                        c.drawString(15*mm, y, text)
                    y -= 5*mm
                    for j, opt in enumerate(q.get("options", [])):
                        c.drawString(20*mm, y, f"{chr(65+j)}) {opt}")
                        y -= 4*mm
                    y -= 4*mm
                c.save()
                with open(pdf_path, "rb") as f:
                    st.session_state[f"{kp}qbank_pdf"] = f.read()
            except Exception as e:
                st.error(f"PDF hatası: {e}")
        st.button("📄 PDF İndir", key=f"{kp}qbank_pdf_btn", on_click=_export_qbank)
        if f"{kp}qbank_pdf" in st.session_state:
            st.download_button("⬇️ PDF Kaydet", data=st.session_state[f"{kp}qbank_pdf"],
                               file_name=f"soru_bankasi_{topic}.pdf", mime="application/pdf",
                               key=f"{kp}qbank_dl")
        def _new_qbank():
            st.session_state.pop(result_key, None)
            st.session_state.pop(f"{kp}qbank_pdf", None)
        st.button("🔄 Yeni Sorular", key=f"{kp}qbank_new", on_click=_new_qbank)
    else:
        def _gen_qbank():
            st.session_state[gen_key] = True
        st.button("📝 Soru Üret", key=f"{kp}qbank_btn", type="primary",
                  use_container_width=True, on_click=_gen_qbank)


# ── I18: Etkileşimli Zaman Çizelgesi ──
def render_interactive_timeline(topic: str, kp: str = "_prem_"):
    """Animasyonlu Canvas zaman çizelgesi."""
    st.markdown('<div style="background:linear-gradient(135deg,#1a0a0a,#0a1a2e);border:2px solid rgba(239,68,68,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#f87171;margin:0">📅 Etkileşimli Zaman Çizelgesi</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}timeline_gen"
    result_key = f"{kp}timeline_result"
    if st.session_state.get(gen_key):
        with st.spinner("Zaman çizelgesi oluşturuluyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyla ilgili kronolojik zaman cizelgesi olustur. "
                                                      "JSON: {\"events\":[{\"date\":\"tarih/donem\","
                                                      "\"title\":\"baslik\",\"description\":\"aciklama\"}]} "
                                                      "8-12 olay."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=800, temperature=0.5,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        events = data.get("events", [])
        events_js = json.dumps(events, ensure_ascii=False)
        html = f"""<canvas id="tlCanvas" width="750" height="{max(400, len(events)*70)}"
                   style="background:#f0f9ff;border-radius:12px;border:1px solid rgba(239,68,68,0.3);width:100%"></canvas>
        <script>
        const canvas=document.getElementById('tlCanvas'),ctx=canvas.getContext('2d');
        const events={events_js};
        const colors=['#3b82f6','#8b5cf6','#ec4899','#f59e0b','#10b981','#ef4444','#06b6d4','#84cc16',
                       '#f472b6','#a78bfa','#22d3ee','#fbbf24'];
        // Timeline line
        ctx.strokeStyle='rgba(239,68,68,0.4)';ctx.lineWidth=3;
        ctx.beginPath();ctx.moveTo(120,30);ctx.lineTo(120,canvas.height-20);ctx.stroke();
        events.forEach((e,i)=>{{
            const y=50+i*65;
            const clr=colors[i%colors.length];
            // Dot
            ctx.beginPath();ctx.arc(120,y,8,0,Math.PI*2);ctx.fillStyle=clr;ctx.fill();
            ctx.strokeStyle='#0B0F19';ctx.lineWidth=2;ctx.stroke();
            // Date
            ctx.fillStyle='#94a3b8';ctx.font='bold 11px Arial';ctx.textAlign='right';
            ctx.fillText(e.date||'',105,y+4);
            // Line to content
            ctx.strokeStyle=clr+'60';ctx.lineWidth=1;
            ctx.beginPath();ctx.moveTo(128,y);ctx.lineTo(160,y);ctx.stroke();
            // Title
            ctx.textAlign='left';ctx.fillStyle=clr;ctx.font='bold 13px Arial';
            ctx.fillText(e.title||'',165,y-2);
            // Description
            ctx.fillStyle='#cbd5e1';ctx.font='11px Arial';
            const desc=(e.description||'').substring(0,80);
            ctx.fillText(desc,165,y+14);
        }});
        </script>"""
        import streamlit.components.v1 as components
        components.html(html, height=max(420, len(events)*70+40))
        def _new_tl():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Çizelge", key=f"{kp}tl_new", on_click=_new_tl)
    else:
        def _gen_tl():
            st.session_state[gen_key] = True
        st.button("📅 Çizelge Oluştur", key=f"{kp}tl_btn", type="primary",
                  use_container_width=True, on_click=_gen_tl)


