# ── Q1: AI Terim Sözlüğü ──
def render_glossary(topic: str, kp: str = "_prem_"):
    """Konuya özel terim sözlüğü."""
    st.markdown('<div style="background:linear-gradient(135deg,#0B0F19,#1a2e3e);border:2px solid rgba(56,189,248,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#38bdf8;margin:0">📖 AI Terim Sözlüğü</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}gloss_gen"
    result_key = f"{kp}gloss_result"
    search_key = f"{kp}gloss_search"
    if st.session_state.get(gen_key):
        with st.spinner("Sözlük oluşturuluyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyla ilgili 20 temel terimi acikla. "
                                                      "JSON: {\"terms\":[{\"term\":\"terim\",\"definition\":\"tanim\","
                                                      "\"example\":\"ornek kullanim\"}]} Turkce, ogrenci dostu."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=1000, temperature=0.4,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        terms = data.get("terms", [])
        search = st.text_input("🔍 Terim ara...", key=search_key, placeholder="Anahtar kelime yazın...")
        filtered = [t for t in terms if not search or search.lower() in t.get("term", "").lower()
                    or search.lower() in t.get("definition", "").lower()] if search else terms
        for i, t in enumerate(filtered):
            letter = t.get("term", "?")[0].upper()
            st.markdown(
                f'<div style="background:#f0f9ff;border-left:4px solid #38bdf8;border-radius:0 12px 12px 0;'
                f'padding:12px 16px;margin:6px 0;display:flex;align-items:flex-start;gap:12px">'
                f'<div style="background:#1e40af;color:#fff;width:36px;height:36px;border-radius:50%;'
                f'display:flex;align-items:center;justify-content:center;font-weight:bold;flex-shrink:0">{letter}</div>'
                f'<div><div style="color:#38bdf8;font-weight:bold;font-size:.95rem">{t.get("term","")}</div>'
                f'<div style="color:#1e293b;font-size:.88rem;margin:4px 0">{t.get("definition","")}</div>'
                f'<div style="color:#64748b;font-size:.8rem">📝 {t.get("example","")}</div></div></div>',
                unsafe_allow_html=True)
        st.caption(f"{len(filtered)}/{len(terms)} terim gösteriliyor")
        def _new_gloss():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Sözlük", key=f"{kp}gloss_new", on_click=_new_gloss)
    else:
        def _gen_gloss():
            st.session_state[gen_key] = True
        st.button("📖 Sözlük Oluştur", key=f"{kp}gloss_btn", type="primary",
                  use_container_width=True, on_click=_gen_gloss)


# ── Q2: Düello Modu ──
def render_duel_mode(topic: str, kp: str = "_prem_"):
    """AI ile 1v1 bilgi düellosu."""
    st.markdown('<div style="background:linear-gradient(135deg,#2e0a0a,#2e1a0a);border:2px solid rgba(239,68,68,0.5);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#f87171;margin:0">⚔️ Düello Modu</h4></div>',
                unsafe_allow_html=True)
    phase_key = f"{kp}duel_phase"
    qs_key = f"{kp}duel_qs"
    idx_key = f"{kp}duel_idx"
    p_score = f"{kp}duel_p"
    ai_score = f"{kp}duel_ai"
    gen_key = f"{kp}duel_gen"
    phase = st.session_state.get(phase_key, "idle")

    if phase == "idle":
        if st.session_state.get(gen_key):
            with st.spinner("Düello hazırlanıyor..."):
                try:
                    client = _get_client()
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content": "10 soru olustur. JSON: {\"questions\":[{\"q\":\"soru\","
                                                          "\"options\":[\"A\",\"B\",\"C\",\"D\"],\"answer\":0,"
                                                          "\"ai_wrong_indices\":[2,5,8]}]} ai_wrong_indices: AI'nin "
                                                          "yanlis bilecegi soru indeksleri (3 tane)."},
                            {"role": "user", "content": f"Konu: {topic}"},
                        ], max_tokens=1000, temperature=0.7,
                        response_format={"type": "json_object"})
                    data = json.loads(resp.choices[0].message.content)
                    st.session_state[qs_key] = data.get("questions", [])[:10]
                    st.session_state[idx_key] = 0
                    st.session_state[p_score] = 0
                    st.session_state[ai_score] = 0
                    st.session_state[phase_key] = "playing"
                except Exception as e:
                    st.error(f"Hata: {e}")
            st.session_state[gen_key] = False
            st.rerun()
        st.markdown('<div style="text-align:center;padding:20px">'
                    '<div style="font-size:3rem">⚔️</div>'
                    '<div style="color:#1e293b;font-size:1.1rem">AI\'ye karşı 10 soruluk düello!</div>'
                    '<div style="color:#475569;font-size:.85rem;margin-top:8px">Her doğru cevap 1 puan. AI de cevaplıyor!</div></div>',
                    unsafe_allow_html=True)
        def _start_duel():
            st.session_state[gen_key] = True
        st.button("⚔️ Düelloya Başla!", key=f"{kp}duel_start", type="primary",
                  use_container_width=True, on_click=_start_duel)

    elif phase == "playing":
        qs = st.session_state.get(qs_key, [])
        idx = st.session_state.get(idx_key, 0)
        ps = st.session_state.get(p_score, 0)
        ais = st.session_state.get(ai_score, 0)
        if idx >= len(qs):
            st.session_state[phase_key] = "done"
            st.rerun()
        # Skor gösterimi
        st.markdown(f'<div style="display:flex;justify-content:space-around;background:#f0f9ff;'
                    f'border-radius:12px;padding:12px;margin:8px 0">'
                    f'<div style="text-align:center"><div style="color:#3b82f6;font-size:.8rem">🧑 Sen</div>'
                    f'<div style="color:#3b82f6;font-size:1.8rem;font-weight:bold">{ps}</div></div>'
                    f'<div style="color:#475569;font-size:1.5rem;align-self:center">VS</div>'
                    f'<div style="text-align:center"><div style="color:#ef4444;font-size:.8rem">🤖 AI</div>'
                    f'<div style="color:#ef4444;font-size:1.8rem;font-weight:bold">{ais}</div></div></div>',
                    unsafe_allow_html=True)
        q = qs[idx]
        st.markdown(f"**Soru {idx+1}/10:** {q.get('q','')}")
        opts = q.get("options", [])
        cols = st.columns(2)
        for i, opt in enumerate(opts):
            def _duel_ans(ci=i):
                _qs = st.session_state[qs_key]
                _idx = st.session_state[idx_key]
                correct = _qs[_idx].get("answer", 0)
                ai_wrong = _qs[0].get("ai_wrong_indices", [])
                if ci == correct:
                    st.session_state[p_score] = st.session_state.get(p_score, 0) + 1
                if _idx not in ai_wrong:
                    st.session_state[ai_score] = st.session_state.get(ai_score, 0) + 1
                st.session_state[idx_key] = _idx + 1
            cols[i % 2].button(opt, key=f"{kp}duel_o{idx}_{i}", on_click=_duel_ans,
                               use_container_width=True)

    elif phase == "done":
        ps = st.session_state.get(p_score, 0)
        ais = st.session_state.get(ai_score, 0)
        if ps > ais:
            msg, emoji = "Tebrikler! Kazandın!", "🏆"
        elif ps < ais:
            msg, emoji = "AI kazandı! Tekrar dene!", "🤖"
        else:
            msg, emoji = "Berabere!", "🤝"
        st.markdown(f'<div style="text-align:center;background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
                    f'border:2px solid rgba(251,191,36,0.4);border-radius:16px;padding:24px">'
                    f'<div style="font-size:4rem">{emoji}</div>'
                    f'<div style="color:#92400e;font-size:1.3rem;font-weight:bold">{msg}</div>'
                    f'<div style="color:#1e293b;margin-top:12px;font-size:1.1rem">'
                    f'🧑 Sen: {ps} — 🤖 AI: {ais}</div></div>', unsafe_allow_html=True)
        def _reset_duel():
            for k in [phase_key, qs_key, idx_key, p_score, ai_score]:
                st.session_state.pop(k, None)
        st.button("🔄 Tekrar Düello", key=f"{kp}duel_retry", on_click=_reset_duel)


# ── Q3: Zihin Haritası (Canvas Mind Map) ──
def render_mind_map(topic: str, kp: str = "_prem_"):
    """AI ile otomatik zihin haritası oluştur."""
    st.markdown('<div style="background:linear-gradient(135deg,#1a0a2e,#0a2e1a);border:2px solid rgba(168,85,247,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#c084fc;margin:0">🧠 Zihin Haritası</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}mmap_gen"
    result_key = f"{kp}mmap_result"
    if st.session_state.get(gen_key):
        with st.spinner("Zihin haritası oluşturuluyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyla ilgili zihin haritasi olustur. "
                                                      "JSON: {\"center\":\"ana konu\",\"branches\":["
                                                      "{\"name\":\"dal\",\"children\":[\"alt1\",\"alt2\",\"alt3\"]}]} "
                                                      "5-7 ana dal, her dalda 2-4 alt dal."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=600, temperature=0.6,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        center = data.get("center", topic)
        branches = data.get("branches", [])
        bjs = json.dumps(branches, ensure_ascii=False)
        html = f"""<canvas id="mmCnv" width="800" height="600"
                   style="background:#f0f9ff;border-radius:12px;border:1px solid rgba(168,85,247,0.3);width:100%"></canvas>
        <script>
        const c=document.getElementById('mmCnv'),ctx=c.getContext('2d');
        const cx=400,cy=300;
        const branches={bjs};
        const colors=['#3b82f6','#8b5cf6','#ec4899','#f59e0b','#10b981','#ef4444','#06b6d4','#84cc16'];
        // Center
        ctx.beginPath();ctx.arc(cx,cy,45,0,Math.PI*2);
        const cg=ctx.createRadialGradient(cx,cy,10,cx,cy,45);
        cg.addColorStop(0,'#7c3aed');cg.addColorStop(1,'#3b82f6');
        ctx.fillStyle=cg;ctx.fill();
        ctx.fillStyle='#fff';ctx.font='bold 12px Arial';ctx.textAlign='center';ctx.textBaseline='middle';
        const ct='{center}';
        if(ct.length>14){{ctx.font='bold 10px Arial';}}
        ctx.fillText(ct.substring(0,18),cx,cy);
        // Branches
        branches.forEach((b,i)=>{{
            const angle=(i/branches.length)*Math.PI*2-Math.PI/2;
            const bx=cx+Math.cos(angle)*180;
            const by=cy+Math.sin(angle)*180;
            const clr=colors[i%colors.length];
            // Line
            ctx.strokeStyle=clr+'80';ctx.lineWidth=3;
            ctx.beginPath();ctx.moveTo(cx,cy);ctx.lineTo(bx,by);ctx.stroke();
            // Branch node
            ctx.beginPath();ctx.arc(bx,by,32,0,Math.PI*2);ctx.fillStyle=clr+'30';ctx.fill();
            ctx.strokeStyle=clr;ctx.lineWidth=2;ctx.stroke();
            ctx.fillStyle=clr;ctx.font='bold 10px Arial';
            const bn=(b.name||'').substring(0,16);
            ctx.fillText(bn,bx,by);
            // Children
            const children=b.children||[];
            children.forEach((ch,j)=>{{
                const ca=angle+(j-children.length/2+0.5)*0.35;
                const chx=bx+Math.cos(ca)*100;
                const chy=by+Math.sin(ca)*100;
                ctx.strokeStyle=clr+'40';ctx.lineWidth=1.5;
                ctx.beginPath();ctx.moveTo(bx,by);ctx.lineTo(chx,chy);ctx.stroke();
                ctx.beginPath();ctx.arc(chx,chy,20,0,Math.PI*2);ctx.fillStyle='#1e293b';ctx.fill();
                ctx.strokeStyle=clr+'60';ctx.lineWidth=1;ctx.stroke();
                ctx.fillStyle='#cbd5e1';ctx.font='9px Arial';
                ctx.fillText((ch||'').substring(0,14),chx,chy);
            }});
        }});
        </script>"""
        import streamlit.components.v1 as components
        components.html(html, height=620)
        def _new_mm():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Harita", key=f"{kp}mmap_new", on_click=_new_mm)
    else:
        def _gen_mm():
            st.session_state[gen_key] = True
        st.button("🧠 Harita Oluştur", key=f"{kp}mmap_btn", type="primary",
                  use_container_width=True, on_click=_gen_mm)


# ── Q4: Ders Bingo ──
def render_bingo(topic: str, kp: str = "_prem_"):
    """Kavramlarla bingo kartı oyunu."""
    st.markdown('<div style="background:linear-gradient(135deg,#2e1a0a,#0a1a2e);border:2px solid rgba(251,146,60,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#fb923c;margin:0">🎯 Ders Bingo</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}bingo_gen"
    card_key = f"{kp}bingo_card"
    marked_key = f"{kp}bingo_marked"
    clue_key = f"{kp}bingo_clue"
    clue_idx_key = f"{kp}bingo_cidx"

    if st.session_state.get(gen_key):
        with st.spinner("Bingo kartı hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Bingo oyunu icin 25 kavram ve her biri icin ipucu olustur. "
                                                      "JSON: {\"items\":[{\"word\":\"kavram\",\"clue\":\"ipucu/tanim\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=800, temperature=0.7,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                items = data.get("items", [])[:25]
                while len(items) < 25:
                    items.append({"word": "⭐", "clue": "Bonus!"})
                st.session_state[card_key] = items
                st.session_state[marked_key] = set()
                import random
                order = list(range(25))
                random.shuffle(order)
                st.session_state[clue_key] = order
                st.session_state[clue_idx_key] = 0
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()

    items = st.session_state.get(card_key, [])
    if not items:
        def _gen_bingo():
            st.session_state[gen_key] = True
        st.button("🎯 Bingo Başlat", key=f"{kp}bingo_btn", type="primary",
                  use_container_width=True, on_click=_gen_bingo)
        return

    marked = st.session_state.get(marked_key, set())
    clue_order = st.session_state.get(clue_key, [])
    clue_idx = st.session_state.get(clue_idx_key, 0)

    # İpucu göster
    if clue_idx < len(clue_order):
        ci = clue_order[clue_idx]
        item = items[ci]
        st.info(f"💡 İpucu: **{item.get('clue', '')}**")
    else:
        st.success("Tüm ipuçları verildi!")

    # 5x5 grid
    grid_html = '<div style="display:grid;grid-template-columns:repeat(5,1fr);gap:4px;max-width:500px;margin:0 auto">'
    for i, item in enumerate(items):
        bg = "linear-gradient(135deg,#22c55e,#16a34a)" if i in marked else "#1e293b"
        border = "2px solid #22c55e" if i in marked else "1px solid #334155"
        grid_html += (f'<div style="background:{bg};border:{border};border-radius:8px;padding:8px;'
                      f'text-align:center;min-height:50px;display:flex;align-items:center;justify-content:center">'
                      f'<span style="color:#fff;font-size:.75rem;font-weight:bold">{item.get("word","")}</span></div>')
    grid_html += '</div>'
    st.markdown(grid_html, unsafe_allow_html=True)

    # İşaretleme
    if clue_idx < len(clue_order):
        cols = st.columns(5)
        for i in range(5):
            row_items = list(range(i*5, min(i*5+5, 25)))
            for j in row_items:
                if j not in marked:
                    def _mark(idx=j):
                        st.session_state[marked_key] = st.session_state.get(marked_key, set()) | {idx}
                        st.session_state[clue_idx_key] = st.session_state.get(clue_idx_key, 0) + 1
                    cols[j % 5].button(f"✓{j+1}", key=f"{kp}bingo_m{j}", on_click=_mark)

    # Bingo kontrolü
    lines = [list(range(r*5, r*5+5)) for r in range(5)]  # rows
    lines += [list(range(c, 25, 5)) for c in range(5)]  # cols
    lines += [[0,6,12,18,24], [4,8,12,16,20]]  # diags
    bingo = any(all(c in marked for c in line) for line in lines)
    if bingo:
        st.balloons()
        st.success("🎯 BİNGO! Tebrikler!")

    def _reset_bingo():
        for k in [card_key, marked_key, clue_key, clue_idx_key]:
            st.session_state.pop(k, None)
    st.button("🔄 Yeni Kart", key=f"{kp}bingo_reset", on_click=_reset_bingo)


# ── Q5: Doğru/Yanlış Avı ──
def render_true_false_hunt(topic: str, kp: str = "_prem_"):
    """Paragraftaki hataları bul oyunu."""
    st.markdown('<div style="background:linear-gradient(135deg,#0a2e0a,#1a0a0a);border:2px solid rgba(34,197,94,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#4ade80;margin:0">🔍 Doğru/Yanlış Avı</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}tfhunt_gen"
    result_key = f"{kp}tfhunt_result"
    reveal_key = f"{kp}tfhunt_reveal"
    if st.session_state.get(gen_key):
        with st.spinner("Metin hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyla ilgili 8 cumle yaz. 3 tanesi bilinçli olarak yanlis olsun. "
                                                      "JSON: {\"sentences\":[{\"text\":\"cumle\",\"is_correct\":true,"
                                                      "\"explanation\":\"aciklama\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=600, temperature=0.6,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        sentences = data.get("sentences", [])
        answers_key = f"{kp}tfhunt_answers"
        if answers_key not in st.session_state:
            st.session_state[answers_key] = {}
        user_answers = st.session_state[answers_key]
        total = len(sentences)
        answered = len(user_answers)
        all_done = answered == total

        # İlerleme
        pct = (answered / max(total, 1)) * 100
        st.markdown(
            f'<div style="background:#e2e8f0;border-radius:8px;height:8px;margin:8px 0;overflow:hidden">'
            f'<div style="background:linear-gradient(90deg,#22c55e,#3b82f6);width:{pct}%;'
            f'height:100%;border-radius:8px;transition:width 0.5s"></div></div>'
            f'<div style="color:#64748b;font-size:.8rem;text-align:right">'
            f'{answered}/{total} cevapland\u0131</div>',
            unsafe_allow_html=True,
        )

        for i, s in enumerate(sentences):
            is_correct = s.get("is_correct", True)
            text = s.get("text", "")
            explanation = s.get("explanation", "")

            if i in user_answers:
                # Cevap verilmiş — sonucu göster
                user_said_correct = user_answers[i]
                is_right = (user_said_correct == is_correct)
                if is_right:
                    bg = "rgba(34,197,94,0.1)"
                    border_c = "rgba(34,197,94,0.4)"
                    icon = "\u2705"
                    verdict = "Do\u011fru bildin!"
                else:
                    bg = "rgba(239,68,68,0.1)"
                    border_c = "rgba(239,68,68,0.4)"
                    icon = "\u274C"
                    verdict = "Yanl\u0131\u015F!" if is_correct else "Bu c\u00FCmle zaten yanl\u0131\u015Ft\u0131!"
                actual = "\u2705 Do\u011fru c\u00FCmle" if is_correct else "\u274C Yanl\u0131\u015F c\u00FCmle"
                st.markdown(
                    f'<div style="background:{bg};border:1px solid {border_c};'
                    f'border-radius:10px;padding:12px;margin:6px 0">'
                    f'<div style="color:#1e293b;font-size:.9rem">{icon} {text}</div>'
                    f'<div style="color:#475569;font-size:.8rem;margin-top:4px">'
                    f'<b>{verdict}</b> ({actual})</div>'
                    f'<div style="color:#64748b;font-size:.78rem;margin-top:2px">'
                    f'\U0001F4A1 {explanation}</div></div>',
                    unsafe_allow_html=True,
                )
            else:
                # Henüz cevaplanmamış — butonlar göster
                st.markdown(
                    f'<div style="background:#f0f9ff;border:1px solid #93c5fd;'
                    f'border-radius:10px;padding:12px;margin:6px 0">'
                    f'<div style="color:#1e293b;font-size:.9rem;font-weight:600">'
                    f'{i + 1}. {text}</div></div>',
                    unsafe_allow_html=True,
                )
                bc1, bc2 = st.columns(2)
                with bc1:
                    def _mark_true(idx=i):
                        st.session_state[answers_key][idx] = True
                    st.button("\u2705 Do\u011Fru", key=f"{kp}tfh_t_{i}",
                              use_container_width=True, on_click=_mark_true)
                with bc2:
                    def _mark_false(idx=i):
                        st.session_state[answers_key][idx] = False
                    st.button("\u274C Yanl\u0131\u015F", key=f"{kp}tfh_f_{i}",
                              use_container_width=True, type="primary", on_click=_mark_false)
                # İlk cevaplanmamış sorudan sonra dur
                break

        # Tümü bitti — skor göster
        if all_done:
            score = sum(
                1 for i, s in enumerate(sentences)
                if user_answers.get(i) == s.get("is_correct", True)
            )
            pct_score = int(score / max(total, 1) * 100)
            color = "#22c55e" if pct_score >= 70 else "#f59e0b" if pct_score >= 50 else "#ef4444"
            st.markdown(
                f'<div style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);'
                f'border:2px solid {color};border-radius:12px;padding:16px;'
                f'margin:12px 0;text-align:center">'
                f'<div style="color:{color};font-weight:800;font-size:1.3rem">'
                f'\U0001F3AF {score}/{total} Do\u011Fru (%{pct_score})</div></div>',
                unsafe_allow_html=True,
            )

        def _new_tf():
            st.session_state.pop(result_key, None)
            st.session_state.pop(answers_key, None)
        st.button("\U0001F504 Yeni Metin", key=f"{kp}tfhunt_new", on_click=_new_tf)
    else:
        def _gen_tf():
            st.session_state[gen_key] = True
        st.button("🔍 Avı Başlat", key=f"{kp}tfhunt_btn", type="primary",
                  use_container_width=True, on_click=_gen_tf)


# ── Q6: AI Deney Tasarlayıcı ──
def render_experiment_designer(topic: str, kp: str = "_prem_"):
    """Sanal deney tasarımı ve simülasyonu."""
    st.markdown('<div style="background:linear-gradient(135deg,#0a2e2e,#1a2e0a);border:2px solid rgba(20,184,166,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#2dd4bf;margin:0">🔬 AI Deney Tasarlayıcı</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}exp_gen"
    result_key = f"{kp}exp_result"
    if st.session_state.get(gen_key):
        with st.spinner("Deney tasarlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyla ilgili bir deney tasarla. "
                                                      "JSON: {\"title\":\"deney adi\",\"hypothesis\":\"hipotez\","
                                                      "\"materials\":[\"malzeme listesi\"],\"steps\":[\"adim adim\"],"
                                                      "\"expected_result\":\"beklenen sonuc\","
                                                      "\"variables\":{\"independent\":\"bagimsiz\","
                                                      "\"dependent\":\"bagimli\",\"controlled\":\"kontrol\"}} Turkce."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=600, temperature=0.6,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        st.markdown(f'<div style="background:#f0f9ff;border:1px solid rgba(20,184,166,0.3);border-radius:12px;padding:16px">'
                    f'<h5 style="color:#2dd4bf">🔬 {data.get("title","")}</h5></div>', unsafe_allow_html=True)
        st.markdown(f"**📝 Hipotez:** {data.get('hypothesis','')}")
        # Malzemeler
        st.markdown("**🧪 Malzemeler:**")
        for m in data.get("materials", []):
            st.markdown(f"- {m}")
        # Adımlar
        st.markdown("**📋 Deney Adımları:**")
        for i, step in enumerate(data.get("steps", []), 1):
            st.markdown(f'{i}. {step}')
        # Değişkenler
        variables = data.get("variables", {})
        c1, c2, c3 = st.columns(3)
        c1.markdown(f'<div style="background:rgba(59,130,246,0.1);border:1px solid rgba(59,130,246,0.3);'
                    f'border-radius:10px;padding:10px;text-align:center">'
                    f'<div style="color:#3b82f6;font-size:.8rem;font-weight:bold">Bağımsız</div>'
                    f'<div style="color:#1e293b;font-size:.85rem">{variables.get("independent","")}</div></div>',
                    unsafe_allow_html=True)
        c2.markdown(f'<div style="background:rgba(34,197,94,0.1);border:1px solid rgba(34,197,94,0.3);'
                    f'border-radius:10px;padding:10px;text-align:center">'
                    f'<div style="color:#22c55e;font-size:.8rem;font-weight:bold">Bağımlı</div>'
                    f'<div style="color:#1e293b;font-size:.85rem">{variables.get("dependent","")}</div></div>',
                    unsafe_allow_html=True)
        c3.markdown(f'<div style="background:rgba(251,191,36,0.1);border:1px solid rgba(251,191,36,0.3);'
                    f'border-radius:10px;padding:10px;text-align:center">'
                    f'<div style="color:#92400e;font-size:.8rem;font-weight:bold">Kontrol</div>'
                    f'<div style="color:#1e293b;font-size:.85rem">{variables.get("controlled","")}</div></div>',
                    unsafe_allow_html=True)
        st.success(f"**Beklenen Sonuç:** {data.get('expected_result','')}")
        def _new_exp():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Deney", key=f"{kp}exp_new", on_click=_new_exp)
    else:
        def _gen_exp():
            st.session_state[gen_key] = True
        st.button("🔬 Deney Tasarla", key=f"{kp}exp_btn", type="primary",
                  use_container_width=True, on_click=_gen_exp)


