# ── E7: Kavram Çarkı (Wheel of Fortune) ──
def render_concept_wheel(topic: str, kp: str = "_prem_"):
    """Çark çevir, kavram açıkla."""
    st.markdown('<div style="background:linear-gradient(135deg,#2e0a2e,#1a0a3e);border:2px solid rgba(236,72,153,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#f472b6;margin:0">🎡 Kavram Çarkı</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}wheel_gen"
    result_key = f"{kp}wheel_result"
    spin_key = f"{kp}wheel_spin"
    if st.session_state.get(gen_key):
        with st.spinner("Kavramlar hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "8 kavram ve aciklamalari olustur. JSON: "
                                                      "{\"concepts\":[{\"name\":\"kavram\",\"explanation\":\"aciklama\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=500, temperature=0.6,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        concepts = data.get("concepts", [])[:8]
        cjs = json.dumps([c["name"] for c in concepts], ensure_ascii=False)
        spin_result = st.session_state.get(spin_key)
        html = f"""<canvas id="wheelCnv" width="400" height="400"
                   style="background:#f0f9ff;border-radius:50%;border:4px solid rgba(236,72,153,0.4);
                   display:block;margin:0 auto;cursor:pointer"></canvas>
        <script>
        const c=document.getElementById('wheelCnv'),ctx=c.getContext('2d');
        const names={cjs};
        const colors=['#3b82f6','#8b5cf6','#ec4899','#f59e0b','#10b981','#ef4444','#06b6d4','#84cc16'];
        const n=names.length,slice=Math.PI*2/n;
        let angle=0;
        function draw(){{
            ctx.clearRect(0,0,400,400);
            for(let i=0;i<n;i++){{
                ctx.beginPath();ctx.moveTo(200,200);
                ctx.arc(200,200,190,angle+i*slice,angle+(i+1)*slice);
                ctx.fillStyle=colors[i%colors.length];ctx.fill();
                ctx.strokeStyle='#0B0F19';ctx.lineWidth=2;ctx.stroke();
                // Text
                const mid=angle+i*slice+slice/2;
                ctx.save();ctx.translate(200,200);ctx.rotate(mid);
                ctx.fillStyle='#fff';ctx.font='bold 11px Arial';ctx.textAlign='center';
                ctx.fillText(names[i].substring(0,12),100,4);
                ctx.restore();
            }}
            // Arrow
            ctx.beginPath();ctx.moveTo(200,5);ctx.lineTo(190,25);ctx.lineTo(210,25);ctx.closePath();
            ctx.fillStyle='#fbbf24';ctx.fill();
            // Center
            ctx.beginPath();ctx.arc(200,200,25,0,Math.PI*2);ctx.fillStyle='#1e293b';ctx.fill();
            ctx.strokeStyle='#fbbf24';ctx.lineWidth=3;ctx.stroke();
            ctx.fillStyle='#fbbf24';ctx.font='bold 14px Arial';ctx.textAlign='center';ctx.textBaseline='middle';
            ctx.fillText('🎡',200,200);
        }}
        draw();
        </script>"""
        import streamlit.components.v1 as components
        components.html(html, height=420)
        # Çark çevir
        import random
        def _spin():
            idx = random.randint(0, len(concepts) - 1)
            st.session_state[spin_key] = idx
        st.button("🎡 Çarkı Çevir!", key=f"{kp}wheel_spin_btn", type="primary",
                  use_container_width=True, on_click=_spin)
        if spin_result is not None and spin_result < len(concepts):
            c = concepts[spin_result]
            st.markdown(f'<div style="background:linear-gradient(135deg,#fdf2f8,#fce7f3);border:2px solid #f472b6;'
                        f'border-radius:14px;padding:16px;margin-top:12px;text-align:center">'
                        f'<div style="color:#be185d;font-size:1.2rem;font-weight:bold">🎯 {c.get("name","")}</div>'
                        f'<div style="color:#1e293b;margin-top:8px;font-size:.92rem">{c.get("explanation","")}</div>'
                        f'</div>', unsafe_allow_html=True)
        def _new_wheel():
            st.session_state.pop(result_key, None)
            st.session_state.pop(spin_key, None)
        st.button("🔄 Yeni Kavramlar", key=f"{kp}wheel_new", on_click=_new_wheel)
    else:
        def _gen_wheel():
            st.session_state[gen_key] = True
        st.button("🎡 Çark Oluştur", key=f"{kp}wheel_btn", type="primary",
                  use_container_width=True, on_click=_gen_wheel)


# ── E8: Flash Swipe Kartları ──
def render_swipe_cards(topic: str, kp: str = "_prem_"):
    """Tinder tarzı sağ/sol swipe ile öğren."""
    st.markdown('<div style="background:linear-gradient(135deg,#1a2e0a,#2e0a1a);border:2px solid rgba(132,204,22,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#a3e635;margin:0">👆 Flash Swipe</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}swipe_gen"
    cards_key = f"{kp}swipe_cards"
    idx_key = f"{kp}swipe_idx"
    know_key = f"{kp}swipe_know"
    learn_key = f"{kp}swipe_learn"
    flip_key = f"{kp}swipe_flip"
    if st.session_state.get(gen_key):
        with st.spinner("Kartlar hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "15 flash kart olustur. JSON: "
                                                      "{\"cards\":[{\"front\":\"kavram/soru\",\"back\":\"cevap/aciklama\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=600, temperature=0.6,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                st.session_state[cards_key] = data.get("cards", [])
                st.session_state[idx_key] = 0
                st.session_state[know_key] = 0
                st.session_state[learn_key] = 0
                st.session_state[flip_key] = False
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    cards = st.session_state.get(cards_key, [])
    if not cards:
        def _gen_swipe():
            st.session_state[gen_key] = True
        st.button("👆 Kartları Oluştur", key=f"{kp}swipe_btn", type="primary",
                  use_container_width=True, on_click=_gen_swipe)
        return
    idx = st.session_state.get(idx_key, 0)
    know = st.session_state.get(know_key, 0)
    learn = st.session_state.get(learn_key, 0)
    flipped = st.session_state.get(flip_key, False)
    if idx >= len(cards):
        total = know + learn
        st.markdown(f'<div style="text-align:center;background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
                    f'border:2px solid rgba(132,204,22,0.4);border-radius:16px;padding:24px">'
                    f'<div style="font-size:3rem">🎉</div>'
                    f'<div style="color:#a3e635;font-size:1.3rem;font-weight:bold">Kartlar Tamamlandı!</div>'
                    f'<div style="color:#1e293b;margin:12px 0">'
                    f'✅ Biliyorum: {know} | 📚 Öğrenmeliyim: {learn}</div></div>', unsafe_allow_html=True)
        def _reset_swipe():
            for k in [cards_key, idx_key, know_key, learn_key, flip_key]:
                st.session_state.pop(k, None)
        st.button("🔄 Tekrar", key=f"{kp}swipe_reset", on_click=_reset_swipe)
        return
    card = cards[idx]
    # Progress
    st.progress(idx / len(cards))
    st.caption(f"Kart {idx+1}/{len(cards)}  •  ✅ {know}  📚 {learn}")
    # Kart
    content = card.get("back", "") if flipped else card.get("front", "")
    bg = "linear-gradient(135deg,#1e40af,#7c3aed)" if not flipped else "linear-gradient(135deg,#065f46,#047857)"
    label = "CEVAP" if flipped else "SORU"
    st.markdown(f'<div style="background:{bg};border-radius:16px;padding:30px;text-align:center;'
                f'min-height:160px;display:flex;flex-direction:column;align-items:center;justify-content:center;'
                f'margin:12px 0;cursor:pointer">'
                f'<div style="color:rgba(255,255,255,0.5);font-size:.7rem;margin-bottom:8px">{label}</div>'
                f'<div style="color:#fff;font-size:1.1rem;font-weight:bold;line-height:1.6">{content}</div></div>',
                unsafe_allow_html=True)
    if not flipped:
        def _flip():
            st.session_state[flip_key] = True
        st.button("🔄 Kartı Çevir", key=f"{kp}swipe_flip_btn", on_click=_flip,
                  use_container_width=True)
    else:
        c1, c2 = st.columns(2)
        def _know():
            st.session_state[know_key] = st.session_state.get(know_key, 0) + 1
            st.session_state[idx_key] = st.session_state.get(idx_key, 0) + 1
            st.session_state[flip_key] = False
        def _learn():
            st.session_state[learn_key] = st.session_state.get(learn_key, 0) + 1
            st.session_state[idx_key] = st.session_state.get(idx_key, 0) + 1
            st.session_state[flip_key] = False
        c1.button("✅ Biliyorum", key=f"{kp}swipe_know_{idx}", on_click=_know,
                  type="primary", use_container_width=True)
        c2.button("📚 Öğrenmeliyim", key=f"{kp}swipe_learn_{idx}", on_click=_learn,
                  use_container_width=True)


# ── E9: Eşleştirme Oyunu (Memory Card) ──
def render_matching_game(topic: str, kp: str = "_prem_"):
    """Kavram-tanım eşleştirme oyunu."""
    st.markdown('<div style="background:linear-gradient(135deg,#0a1a2e,#2e0a2e);border:2px solid rgba(99,102,241,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#818cf8;margin:0">🃏 Eşleştirme Oyunu</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}match_gen"
    pairs_key = f"{kp}match_pairs"
    sel_key = f"{kp}match_sel"
    found_key = f"{kp}match_found"
    moves_key = f"{kp}match_moves"
    if st.session_state.get(gen_key):
        with st.spinner("Eşleştirme kartları hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "6 kavram-tanim cifti olustur. JSON: "
                                                      "{\"pairs\":[{\"concept\":\"kavram\",\"definition\":\"kisa tanim\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=400, temperature=0.6,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                pairs = data.get("pairs", [])[:6]
                # Kart listesi oluştur: kavramlar ve tanımlar karışık
                import random
                card_list = []
                for i, p in enumerate(pairs):
                    card_list.append({"id": i, "type": "concept", "text": p["concept"], "pair_id": i})
                    card_list.append({"id": i, "type": "definition", "text": p["definition"], "pair_id": i})
                random.shuffle(card_list)
                st.session_state[pairs_key] = card_list
                st.session_state[sel_key] = None
                st.session_state[found_key] = set()
                st.session_state[moves_key] = 0
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    cards = st.session_state.get(pairs_key, [])
    if not cards:
        def _gen_match():
            st.session_state[gen_key] = True
        st.button("🃏 Oyunu Başlat", key=f"{kp}match_btn", type="primary",
                  use_container_width=True, on_click=_gen_match)
        return
    found = st.session_state.get(found_key, set())
    selected = st.session_state.get(sel_key)
    moves = st.session_state.get(moves_key, 0)
    st.caption(f"Hamle: {moves}  |  Bulunan: {len(found)}/6")
    # Grid
    cols = st.columns(4)
    for ci, card in enumerate(cards):
        col = cols[ci % 4]
        is_found = card["pair_id"] in found
        is_sel = selected is not None and ci == selected
        if is_found:
            col.markdown(f'<div style="background:rgba(34,197,94,0.2);border:2px solid #22c55e;border-radius:10px;'
                         f'padding:10px;margin:4px 0;text-align:center;min-height:60px;display:flex;'
                         f'align-items:center;justify-content:center">'
                         f'<span style="color:#4ade80;font-size:.8rem">{card["text"]}</span></div>',
                         unsafe_allow_html=True)
        elif is_sel:
            col.markdown(f'<div style="background:rgba(59,130,246,0.2);border:2px solid #3b82f6;border-radius:10px;'
                         f'padding:10px;margin:4px 0;text-align:center;min-height:60px;display:flex;'
                         f'align-items:center;justify-content:center">'
                         f'<span style="color:#60a5fa;font-size:.8rem">{card["text"]}</span></div>',
                         unsafe_allow_html=True)
        else:
            def _sel_card(idx=ci):
                prev = st.session_state.get(sel_key)
                if prev is None:
                    st.session_state[sel_key] = idx
                else:
                    st.session_state[moves_key] = st.session_state.get(moves_key, 0) + 1
                    prev_card = st.session_state[pairs_key][prev]
                    cur_card = st.session_state[pairs_key][idx]
                    if prev_card["pair_id"] == cur_card["pair_id"] and prev_card["type"] != cur_card["type"]:
                        st.session_state[found_key] = st.session_state.get(found_key, set()) | {prev_card["pair_id"]}
                    st.session_state[sel_key] = None
            col.button(f"❓ Kart {ci+1}", key=f"{kp}match_c{ci}", on_click=_sel_card,
                       use_container_width=True)
    if len(found) >= 6:
        st.success(f"🎉 Tüm eşleştirmeler tamamlandı! {moves} hamlede!")
        def _reset_match():
            for k in [pairs_key, sel_key, found_key, moves_key]:
                st.session_state.pop(k, None)
        st.button("🔄 Yeni Oyun", key=f"{kp}match_reset", on_click=_reset_match)


# ── E10: AI Sunum Oluşturucu ──
def render_presentation_maker(topic: str, kp: str = "_prem_"):
    """Konudan otomatik sunum slaytları oluştur."""
    st.markdown('<div style="background:linear-gradient(135deg,#1a0a2e,#0a2e2e);border:2px solid rgba(139,92,246,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#a78bfa;margin:0">📽️ AI Sunum Oluşturucu</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}pres_gen"
    result_key = f"{kp}pres_result"
    slide_key = f"{kp}pres_slide"
    if st.session_state.get(gen_key):
        with st.spinner("Sunum oluşturuluyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "8 slaytlik sunum olustur. JSON: {\"slides\":["
                                                      "{\"title\":\"slayt basligi\",\"bullets\":[\"madde1\",\"madde2\",\"madde3\"],"
                                                      "\"note\":\"konusmaci notu\"}]} Ilk slayt kapak, son slayt ozet olsun."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=800, temperature=0.6,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                st.session_state[result_key] = data.get("slides", [])
                st.session_state[slide_key] = 0
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    slides = st.session_state.get(result_key, [])
    if not slides:
        def _gen_pres():
            st.session_state[gen_key] = True
        st.button("📽️ Sunum Oluştur", key=f"{kp}pres_btn", type="primary",
                  use_container_width=True, on_click=_gen_pres)
        return
    idx = st.session_state.get(slide_key, 0)
    slide = slides[idx]
    colors_list = ["#3b82f6", "#8b5cf6", "#ec4899", "#f59e0b", "#10b981", "#ef4444", "#06b6d4", "#84cc16"]
    clr = colors_list[idx % len(colors_list)]
    # Slayt navigasyonu
    c1, c2, c3 = st.columns([1, 3, 1])
    def _prev_slide():
        st.session_state[slide_key] = max(0, st.session_state.get(slide_key, 0) - 1)
    def _next_slide():
        st.session_state[slide_key] = min(len(slides)-1, st.session_state.get(slide_key, 0) + 1)
    c1.button("◀️", key=f"{kp}pres_prev", on_click=_prev_slide, disabled=idx==0)
    c2.markdown(f'<div style="text-align:center;color:#475569">Slayt {idx+1}/{len(slides)}</div>',
                unsafe_allow_html=True)
    c3.button("▶️", key=f"{kp}pres_next", on_click=_next_slide, disabled=idx>=len(slides)-1)
    # Slayt içeriği
    bullets_html = "".join(f'<div style="color:#1e293b;font-size:.95rem;margin:8px 0;padding-left:16px;'
                           f'border-left:3px solid {clr}40">{b}</div>' for b in slide.get("bullets", []))
    st.markdown(f'<div style="background:linear-gradient(135deg,#f0f9ff,#e0f2fe);border:2px solid {clr}40;'
                f'border-radius:16px;padding:24px;min-height:250px">'
                f'<div style="color:{clr};font-size:1.3rem;font-weight:bold;margin-bottom:16px;'
                f'padding-bottom:12px;border-bottom:2px solid {clr}30">{slide.get("title","")}</div>'
                f'{bullets_html}</div>', unsafe_allow_html=True)
    # Konuşmacı notu
    if slide.get("note"):
        with st.expander("🗣️ Konuşmacı Notu"):
            st.markdown(slide["note"])
    def _new_pres():
        st.session_state.pop(result_key, None)
        st.session_state.pop(slide_key, None)
    st.button("🔄 Yeni Sunum", key=f"{kp}pres_new", on_click=_new_pres)


# ── E11: Boşluk Doldurma ──
def render_fill_blanks(topic: str, kp: str = "_prem_"):
    """Metinde boşlukları doldur oyunu."""
    st.markdown('<div style="background:linear-gradient(135deg,#0a2e1a,#1a0a2e);border:2px solid rgba(34,197,94,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#4ade80;margin:0">📝 Boşluk Doldurma</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}fill_gen"
    result_key = f"{kp}fill_result"
    check_key = f"{kp}fill_check"
    if st.session_state.get(gen_key):
        with st.spinner("Metin hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyla ilgili 6 cumle olustur. Her cumlede 1 anahtar kelime ___ "
                                                      "ile bos birakilmis olsun. JSON: {\"sentences\":["
                                                      "{\"text\":\"cumle ___ ile\",\"answer\":\"dogru kelime\","
                                                      "\"hint\":\"ipucu\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=500, temperature=0.6,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        sentences = data.get("sentences", [])
        checked = st.session_state.get(check_key, False)
        score = 0
        for i, s in enumerate(sentences):
            st.markdown(f'<div style="color:#1e293b;font-size:.9rem;margin:4px 0">{i+1}. {s.get("text","")}</div>',
                        unsafe_allow_html=True)
            user_ans = st.text_input(f"Cevap {i+1}:", key=f"{kp}fill_a{i}",
                                     placeholder=f"İpucu: {s.get('hint','')}")
            if checked:
                correct = s.get("answer", "").strip().lower()
                given = user_ans.strip().lower()
                if given and (given in correct or correct in given):
                    st.success(f"✅ Doğru: {s.get('answer','')}")
                    score += 1
                else:
                    st.error(f"❌ Doğru cevap: {s.get('answer','')}")
        if not checked:
            def _check_fill():
                st.session_state[check_key] = True
            st.button("✅ Kontrol Et", key=f"{kp}fill_check_btn", type="primary",
                      on_click=_check_fill)
        else:
            st.markdown(f"**Sonuç: {score}/{len(sentences)}**")
        def _new_fill():
            st.session_state.pop(result_key, None)
            st.session_state.pop(check_key, None)
        st.button("🔄 Yeni Metin", key=f"{kp}fill_new", on_click=_new_fill)
    else:
        def _gen_fill():
            st.session_state[gen_key] = True
        st.button("📝 Başlat", key=f"{kp}fill_btn", type="primary",
                  use_container_width=True, on_click=_gen_fill)


