# ── N13: Sıralama Oyunu ──
def render_ordering_game(topic: str, kp: str = "_prem_"):
    """Kavramları doğru sıraya koy."""
    st.markdown('<div style="background:linear-gradient(135deg,#0B0F19,#2e0a1a);border:2px solid rgba(96,165,250,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#60a5fa;margin:0">📑 Sıralama Oyunu</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}order_gen"
    result_key = f"{kp}order_result"
    check_key = f"{kp}order_check"
    if st.session_state.get(gen_key):
        with st.spinner("Sıralama sorusu hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Siralama oyunu icin 3 soru olustur. Her birinde 5 oge dogru "
                                                      "siraya konulmali. JSON: {\"questions\":["
                                                      "{\"instruction\":\"sirala talimat\","
                                                      "\"correct_order\":[\"1.\",\"2.\",\"3.\",\"4.\",\"5.\"],"
                                                      "\"shuffled\":[\"3.\",\"1.\",\"5.\",\"2.\",\"4.\"]}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=500, temperature=0.6,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        questions = data.get("questions", [])
        checked = st.session_state.get(check_key, False)
        total_score = 0
        for qi, q in enumerate(questions):
            st.markdown(f"**{qi+1}. {q.get('instruction','')}**")
            shuffled = q.get("shuffled", [])
            correct = q.get("correct_order", [])
            for si, item in enumerate(shuffled):
                user_pos = st.number_input(f"{item}", min_value=1, max_value=len(shuffled),
                                           value=si+1, key=f"{kp}order_q{qi}_s{si}")
            if checked:
                # Basit kontrol
                user_order = []
                for si, item in enumerate(shuffled):
                    pos = st.session_state.get(f"{kp}order_q{qi}_s{si}", si+1)
                    user_order.append((pos, item))
                user_order.sort()
                user_sorted = [x[1] for x in user_order]
                if user_sorted == correct:
                    st.success("✅ Doğru sıralama!")
                    total_score += 1
                else:
                    st.error(f"❌ Doğru sıra: {' → '.join(correct)}")
        if not checked:
            def _check_order():
                st.session_state[check_key] = True
            st.button("✅ Kontrol Et", key=f"{kp}order_check_btn", type="primary",
                      on_click=_check_order)
        else:
            st.markdown(f"**Toplam: {total_score}/{len(questions)}**")
        def _new_order():
            st.session_state.pop(result_key, None)
            st.session_state.pop(check_key, None)
        st.button("🔄 Yeni Sorular", key=f"{kp}order_new", on_click=_new_order)
    else:
        def _gen_order():
            st.session_state[gen_key] = True
        st.button("📑 Oyunu Başlat", key=f"{kp}order_btn", type="primary",
                  use_container_width=True, on_click=_gen_order)


