# ── N15: Konu Haritası (Coğrafi/Kavramsal) ──
def render_topic_map(topic: str, kp: str = "_prem_"):
    """İnteraktif kavramsal bölge haritası."""
    st.markdown('<div style="background:linear-gradient(135deg,#0a2e1a,#0a1a2e);border:2px solid rgba(34,197,94,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#4ade80;margin:0">🗺️ Konu Haritası</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}tmap_gen"
    result_key = f"{kp}tmap_result"
    if st.session_state.get(gen_key):
        with st.spinner("Harita oluşturuluyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konuyla ilgili 8 alt konu ve aralarindaki iliskileri listele. "
                                                      "JSON: {\"regions\":[{\"name\":\"alt konu\",\"size\":3,"
                                                      "\"connections\":[0,2],\"summary\":\"kisa aciklama\"}]} "
                                                      "size: 1-5 onem, connections: bagli bolge indeksleri."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=500, temperature=0.6,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        regions = data.get("regions", [])
        rjs = json.dumps(regions, ensure_ascii=False)
        html = f"""<canvas id="tmapCnv" width="750" height="500"
                   style="background:#f0f9ff;border-radius:12px;border:1px solid rgba(34,197,94,0.3);width:100%"></canvas>
        <script>
        const c=document.getElementById('tmapCnv'),ctx=c.getContext('2d');
        const regions={rjs};
        const colors=['#3b82f6','#8b5cf6','#ec4899','#f59e0b','#10b981','#ef4444','#06b6d4','#84cc16'];
        // Position regions in a circle
        const cx=375,cy=250,radius=170;
        const positions=regions.map((r,i)=>{{
            const angle=(i/regions.length)*Math.PI*2-Math.PI/2;
            return {{x:cx+Math.cos(angle)*radius,y:cy+Math.sin(angle)*radius}};
        }});
        // Draw connections
        regions.forEach((r,i)=>{{
            (r.connections||[]).forEach(j=>{{
                if(j<positions.length){{
                    ctx.strokeStyle='rgba(100,116,139,0.3)';ctx.lineWidth=1.5;
                    ctx.beginPath();ctx.moveTo(positions[i].x,positions[i].y);
                    ctx.lineTo(positions[j].x,positions[j].y);ctx.stroke();
                }}
            }});
        }});
        // Draw regions
        regions.forEach((r,i)=>{{
            const p=positions[i];
            const size=20+(r.size||3)*8;
            const clr=colors[i%colors.length];
            ctx.beginPath();ctx.arc(p.x,p.y,size,0,Math.PI*2);
            ctx.fillStyle=clr+'30';ctx.fill();
            ctx.strokeStyle=clr;ctx.lineWidth=2;ctx.stroke();
            ctx.fillStyle='#fff';ctx.font='bold 11px Arial';ctx.textAlign='center';ctx.textBaseline='middle';
            ctx.fillText((r.name||'').substring(0,14),p.x,p.y);
        }});
        // Center label
        ctx.fillStyle='#94a3b8';ctx.font='bold 14px Arial';
        ctx.fillText('{topic[:20]}',cx,cy);
        </script>"""
        import streamlit.components.v1 as components
        components.html(html, height=520)
        # Alt konu detayları
        for i, r in enumerate(regions):
            clr = ["#3b82f6","#8b5cf6","#ec4899","#f59e0b","#10b981","#ef4444","#06b6d4","#84cc16"][i%8]
            st.markdown(f'<span style="color:{clr};font-weight:bold">●</span> '
                        f'**{r.get("name","")}**: {r.get("summary","")}')
        def _new_tmap():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Harita", key=f"{kp}tmap_new", on_click=_new_tmap)
    else:
        def _gen_tmap():
            st.session_state[gen_key] = True
        st.button("🗺️ Harita Oluştur", key=f"{kp}tmap_btn", type="primary",
                  use_container_width=True, on_click=_gen_tmap)


