# ── S1: AI Konu Özetçisi ──
def render_topic_summarizer(topic: str, kp: str = "_prem_"):
    """Bullet / Paragraf / Tablo formatında konu özeti."""
    st.markdown('<div style="background:linear-gradient(135deg,#0B0F19,#0a2e2e);border:2px solid rgba(56,189,248,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#38bdf8;margin:0">📌 AI Konu Özetçisi</h4></div>',
                unsafe_allow_html=True)
    fmt = st.selectbox("Özet Formatı", ["Madde İmli (Bullet)", "Paragraf", "Tablo Formatı"],
                       key=f"{kp}summ_fmt")
    gen_key = f"{kp}summ_gen"
    result_key = f"{kp}summ_result"
    if st.session_state.get(gen_key):
        with st.spinner("Özet hazırlanıyor..."):
            try:
                client = _get_client()
                fmt_map = {"Madde İmli (Bullet)": "Madde imleriyle kisa ozetler, ana fikirler",
                           "Paragraf": "Akici paragraflar halinde ozet",
                           "Tablo Formatı": "Markdown tablo formatinda (Konu | Aciklama | Ornek)"}
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": f"Konu ozetleyici. {fmt_map.get(fmt,'')} formatinda yaz. Turkce, "
                                                      f"ogrenci seviyesi. Kapsamli ama okunakli."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=700, temperature=0.5)
                st.session_state[result_key] = resp.choices[0].message.content
            except Exception as e:
                st.session_state[result_key] = f"Hata: {e}"
        st.session_state[gen_key] = False
        st.rerun()
