# ── S2: Hızlı Eşleştir ──
def render_quick_match(topic: str, kp: str = "_prem_"):
    """Kavram-tanım hızlı eşleştirme — dropdown bazlı."""
    st.markdown('<div style="background:linear-gradient(135deg,#1a2e0a,#0a1a2e);border:2px solid rgba(132,204,22,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#a3e635;margin:0">⚡ Hızlı Eşleştir</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}qmatch_gen"
    result_key = f"{kp}qmatch_result"
    check_key = f"{kp}qmatch_check"
    if st.session_state.get(gen_key):
        with st.spinner("Eşleştirme hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "8 kavram-tanim cifti olustur. JSON: "
                                                      "{\"pairs\":[{\"concept\":\"kavram\",\"definition\":\"tanim\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=500, temperature=0.6,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                pairs = data.get("pairs", [])[:8]
                import random
                defs_shuffled = [p["definition"] for p in pairs]
                random.shuffle(defs_shuffled)
                st.session_state[result_key] = {"pairs": pairs, "defs": defs_shuffled}
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        pairs = data["pairs"]
        defs = data["defs"]
        checked = st.session_state.get(check_key, False)
        options = ["Seçiniz..."] + defs
        score = 0
        for i, p in enumerate(pairs):
            c1, c2 = st.columns([1, 2])
            c1.markdown(f'<div style="background:#e2e8f0;border-radius:8px;padding:10px;color:#a3e635;'
                        f'font-weight:bold;font-size:.9rem;margin-top:8px">{p["concept"]}</div>',
                        unsafe_allow_html=True)
            sel = c2.selectbox("→", options, key=f"{kp}qmatch_s{i}", label_visibility="collapsed")
            if checked:
                if sel == p["definition"]:
                    c2.success("✅")
                    score += 1
                elif sel != "Seçiniz...":
                    c2.error(f"❌ → {p['definition']}")
        if not checked:
            def _check_qm():
                st.session_state[check_key] = True
            st.button("✅ Kontrol Et", key=f"{kp}qmatch_chk", type="primary", on_click=_check_qm)
        else:
            st.markdown(f"**Sonuç: {score}/{len(pairs)}**")
        def _new_qm():
            st.session_state.pop(result_key, None)
            st.session_state.pop(check_key, None)
        st.button("🔄 Yeni Set", key=f"{kp}qmatch_new", on_click=_new_qm)
    else:
        def _gen_qm():
            st.session_state[gen_key] = True
        st.button("⚡ Başlat", key=f"{kp}qmatch_btn", type="primary",
                  use_container_width=True, on_click=_gen_qm)


# ── S3: Çoktan Seçmeli Üretici ──
def render_mcq_generator(topic: str, kp: str = "_prem_"):
    """Anında çoktan seçmeli soru üret ve çöz."""
    st.markdown('<div style="background:linear-gradient(135deg,#2e0a1a,#0a2e1a);border:2px solid rgba(244,63,94,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#fb7185;margin:0">❓ Çoktan Seçmeli Üretici</h4></div>',
                unsafe_allow_html=True)
    diff = st.radio("Zorluk:", ["Kolay", "Orta", "Zor"], key=f"{kp}mcqg_diff", horizontal=True)
    gen_key = f"{kp}mcqg_gen"
    result_key = f"{kp}mcqg_result"
    check_key = f"{kp}mcqg_check"
    if st.session_state.get(gen_key):
        with st.spinner("Soru üretiliyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": f"1 adet {diff} seviye coktan secmeli soru olustur. "
                                                      f"JSON: {{\"question\":\"soru\",\"options\":[\"A\",\"B\",\"C\",\"D\"],"
                                                      f"\"answer\":0,\"explanation\":\"aciklama\"}}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=300, temperature=0.7,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        st.markdown(f"**{data.get('question','')}**")
        opts = data.get("options", [])
        checked = st.session_state.get(check_key)
        if checked is not None:
            correct = data.get("answer", 0)
            for i, opt in enumerate(opts):
                if i == correct:
                    st.success(f"✅ {chr(65+i)}) {opt}")
                elif i == checked:
                    st.error(f"❌ {chr(65+i)}) {opt}")
                else:
                    st.markdown(f"   {chr(65+i)}) {opt}")
            st.info(f"💡 {data.get('explanation','')}")
        else:
            for i, opt in enumerate(opts):
                def _sel_mcq(ci=i):
                    st.session_state[check_key] = ci
                st.button(f"{chr(65+i)}) {opt}", key=f"{kp}mcqg_o{i}", on_click=_sel_mcq,
                          use_container_width=True)
        def _new_mcq():
            st.session_state.pop(result_key, None)
            st.session_state.pop(check_key, None)
        st.button("🔄 Yeni Soru", key=f"{kp}mcqg_new", on_click=_new_mcq)
    else:
        def _gen_mcq():
            st.session_state[gen_key] = True
        st.button("❓ Soru Üret", key=f"{kp}mcqg_btn", type="primary",
                  use_container_width=True, on_click=_gen_mcq)


