# ── S5: Konu Ağacı (Hiyerarşik Tree) ──
def render_topic_tree(topic: str, kp: str = "_prem_"):
    """Hiyerarşik ağaç görünümünde konu yapısı."""
    st.markdown('<div style="background:linear-gradient(135deg,#0a2e0a,#1a2e1a);border:2px solid rgba(34,197,94,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#4ade80;margin:0">🌳 Konu Ağacı</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}tree_gen"
    result_key = f"{kp}tree_result"
    if st.session_state.get(gen_key):
        with st.spinner("Konu ağacı oluşturuluyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Konunun hiyerarsik agac yapisini olustur. "
                                                      "JSON: {\"root\":\"ana konu\",\"children\":["
                                                      "{\"name\":\"alt konu\",\"children\":["
                                                      "{\"name\":\"detay\",\"children\":[]}]}]} "
                                                      "3 seviye derinlik, 4-5 ana dal."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=600, temperature=0.5,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        def _render_tree_node(node, level=0):
            indent = level * 24
            colors = ["#4ade80", "#38bdf8", "#a78bfa", "#fb923c", "#f472b6"]
            clr = colors[level % len(colors)]
            icons = ["🌳", "🌿", "🍃", "🍂"]
            icon = icons[min(level, len(icons)-1)]
            name = node.get("name", node.get("root", ""))
            st.markdown(f'<div style="margin-left:{indent}px;padding:4px 0">'
                        f'<span style="color:{clr};font-size:.9rem">{icon}</span> '
                        f'<span style="color:{clr};font-weight:{"bold" if level<2 else "normal"};'
                        f'font-size:{1.0-level*0.08:.2f}rem">{name}</span></div>',
                        unsafe_allow_html=True)
            for child in node.get("children", []):
                _render_tree_node(child, level + 1)
        st.markdown('<div style="background:#f0f9ff;border-radius:12px;padding:16px;'
                    'border:1px solid rgba(34,197,94,0.3)">', unsafe_allow_html=True)
        _render_tree_node(data)
        st.markdown('</div>', unsafe_allow_html=True)
        def _new_tree():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Ağaç", key=f"{kp}tree_new", on_click=_new_tree)
    else:
        def _gen_tree():
            st.session_state[gen_key] = True
        st.button("🌳 Ağaç Oluştur", key=f"{kp}tree_btn", type="primary",
                  use_container_width=True, on_click=_gen_tree)


