# ── C8: Kavram Sıcak-Soğuk Oyunu ──
def render_hot_cold_game(topic: str, kp: str = "_prem_"):
    """Gizli kavramı tahmin et — ipuçlarıyla sıcak/soğuk."""
    st.markdown('<div style="background:linear-gradient(135deg,#2e0a0a,#0B0F19);border:2px solid rgba(239,68,68,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#f87171;margin:0">🌡️ Sıcak-Soğuk</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}hc_gen"
    word_key = f"{kp}hc_word"
    hints_key = f"{kp}hc_hints"
    hint_idx_key = f"{kp}hc_hidx"
    solved_key = f"{kp}hc_solved"
    if st.session_state.get(gen_key):
        with st.spinner("Oyun hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Bir gizli kavram sec ve 6 ipucu olustur. "
                                                      "Ilk ipucu en uzak (soguk), son ipucu en yakin (sicak). "
                                                      "JSON: {\"word\":\"gizli kavram\","
                                                      "\"hints\":[\"cok uzak ipucu\",...,\"cok yakin ipucu\"]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=300, temperature=0.7,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                st.session_state[word_key] = data.get("word", "")
                st.session_state[hints_key] = data.get("hints", [])
                st.session_state[hint_idx_key] = 0
                st.session_state[solved_key] = False
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    word = st.session_state.get(word_key, "")
    if not word:
        def _gen_hc():
            st.session_state[gen_key] = True
        st.button("🌡️ Oyunu Başlat", key=f"{kp}hc_btn", type="primary",
                  use_container_width=True, on_click=_gen_hc)
        return
    hints = st.session_state.get(hints_key, [])
    idx = st.session_state.get(hint_idx_key, 0)
    solved = st.session_state.get(solved_key, False)
    # Sıcaklık göstergesi
    if hints:
        temp_pct = (idx / max(len(hints)-1, 1)) * 100
        temp_color = f"hsl({max(0, 240 - temp_pct * 2.4)}, 80%, 50%)"
        temp_label = ["🥶 Buz", "❄️ Soğuk", "🌊 Serin", "☀️ Ilık", "🔥 Sıcak", "🌋 Çok Sıcak"][min(idx, 5)]
        st.markdown(f'<div style="background:#e2e8f0;border-radius:8px;height:30px;margin:8px 0">'
                    f'<div style="background:{temp_color};width:{temp_pct}%;height:100%;border-radius:8px;'
                    f'display:flex;align-items:center;justify-content:center;color:#fff;font-weight:bold;'
                    f'font-size:.8rem;min-width:80px;transition:width 0.5s">{temp_label}</div></div>',
                    unsafe_allow_html=True)
    # Gösterilen ipuçları
    for i in range(min(idx + 1, len(hints))):
        st.markdown(f'<div style="color:#1e293b;font-size:.9rem;margin:4px 0;padding:6px 12px;'
                    f'background:#f0f9ff;border-radius:8px;border-left:3px solid '
                    f'{"#3b82f6" if i<2 else "#f59e0b" if i<4 else "#ef4444"}">'
                    f'💡 İpucu {i+1}: {hints[i]}</div>', unsafe_allow_html=True)
    if not solved:
        guess = st.text_input("Tahminiz:", key=f"{kp}hc_guess_{idx}")
        c1, c2 = st.columns(2)
        def _check_hc():
            val = st.session_state.get(f"{kp}hc_guess_{idx}", "").strip().lower()
            target = st.session_state.get(word_key, "").strip().lower()
            if val and (val in target or target in val):
                st.session_state[solved_key] = True
            else:
                st.session_state[hint_idx_key] = min(st.session_state.get(hint_idx_key, 0) + 1, len(hints) - 1)
        c1.button("🔍 Tahmin Et", key=f"{kp}hc_check_{idx}", on_click=_check_hc, type="primary")
        if idx < len(hints) - 1:
            def _next_hint():
                st.session_state[hint_idx_key] = min(st.session_state.get(hint_idx_key, 0) + 1, len(hints) - 1)
            c2.button("💡 Sonraki İpucu", key=f"{kp}hc_next_{idx}", on_click=_next_hint)
    else:
        st.success(f"🎉 Tebrikler! Cevap: **{word}** — {idx+1} ipucunda buldunuz!")
    def _reset_hc():
        for k in [word_key, hints_key, hint_idx_key, solved_key]:
            st.session_state.pop(k, None)
    st.button("🔄 Yeni Oyun", key=f"{kp}hc_reset", on_click=_reset_hc)


# ── C9: AI Ders Haritası (Roadmap) ──
def render_learning_roadmap(topic: str, kp: str = "_prem_"):
    """Öğrenme yol haritası — sıralı adımlar."""
    st.markdown('<div style="background:linear-gradient(135deg,#0a2e1a,#1a0a2e);border:2px solid rgba(34,197,94,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#4ade80;margin:0">🛤️ Öğrenme Yol Haritası</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}roadmap_gen"
    result_key = f"{kp}roadmap_result"
    if st.session_state.get(gen_key):
        with st.spinner("Yol haritası çiziliyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Ogrenme yol haritasi olustur. JSON: "
                                                      "{\"roadmap\":[{\"step\":1,\"title\":\"adim\","
                                                      "\"description\":\"aciklama\",\"duration\":\"sure\","
                                                      "\"milestone\":\"hedef\"}]} 8 adim."},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=600, temperature=0.5,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        steps = data.get("roadmap", [])
        colors_list = ["#3b82f6", "#8b5cf6", "#ec4899", "#f59e0b", "#10b981", "#ef4444", "#06b6d4", "#84cc16"]
        for i, step in enumerate(steps):
            clr = colors_list[i % len(colors_list)]
            num = step.get("step", i+1)
            st.markdown(
                f'<div style="display:flex;gap:14px;margin:8px 0">'
                f'<div style="flex-shrink:0;width:44px;height:44px;border-radius:50%;'
                f'background:{clr};display:flex;align-items:center;justify-content:center;'
                f'color:#fff;font-weight:bold;font-size:1rem">{num}</div>'
                f'<div style="flex:1;background:#f0f9ff;border:1px solid {clr}30;border-radius:12px;padding:12px">'
                f'<div style="color:{clr};font-weight:bold;font-size:.92rem">{step.get("title","")}</div>'
                f'<div style="color:#1e293b;font-size:.85rem;margin:4px 0">{step.get("description","")}</div>'
                f'<div style="display:flex;gap:12px">'
                f'<span style="color:#64748b;font-size:.78rem">⏱️ {step.get("duration","")}</span>'
                f'<span style="color:#92400e;font-size:.78rem">🎯 {step.get("milestone","")}</span></div>'
                f'</div></div>', unsafe_allow_html=True)
            if i < len(steps) - 1:
                st.markdown(f'<div style="margin-left:20px;border-left:2px dashed {clr}40;height:16px"></div>',
                            unsafe_allow_html=True)
        def _new_road():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Harita", key=f"{kp}roadmap_new", on_click=_new_road)
    else:
        def _gen_road():
            st.session_state[gen_key] = True
        st.button("🛤️ Harita Oluştur", key=f"{kp}roadmap_btn", type="primary",
                  use_container_width=True, on_click=_gen_road)


