# ── C11: AI Sınav Simülatörü (Zamanlı) ──
def render_exam_simulator(topic: str, kp: str = "_prem_"):
    """Zamanlı mini sınav simülasyonu."""
    st.markdown('<div style="background:linear-gradient(135deg,#0B0F19,#2e1a0a);border:2px solid rgba(251,191,36,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#92400e;margin:0">📝 Sınav Simülatörü</h4></div>',
                unsafe_allow_html=True)
    phase_key = f"{kp}esim_phase"
    qs_key = f"{kp}esim_qs"
    ans_key = f"{kp}esim_ans"
    gen_key = f"{kp}esim_gen"
    phase = st.session_state.get(phase_key, "idle")
    if phase == "idle":
        if st.session_state.get(gen_key):
            with st.spinner("Sınav hazırlanıyor..."):
                try:
                    client = _get_client()
                    resp = client.chat.completions.create(
                        model="gpt-4o-mini",
                        messages=[
                            {"role": "system", "content": "10 soruluk sinav olustur. JSON: {\"exam_title\":\"baslik\","
                                                          "\"questions\":[{\"q\":\"soru\",\"options\":[\"A\",\"B\",\"C\",\"D\"],"
                                                          "\"answer\":0,\"points\":10}]}"},
                            {"role": "user", "content": f"Konu: {topic}"},
                        ], max_tokens=1000, temperature=0.6,
                        response_format={"type": "json_object"})
                    data = json.loads(resp.choices[0].message.content)
                    st.session_state[qs_key] = data
                    st.session_state[ans_key] = {}
                    st.session_state[phase_key] = "taking"
                except Exception as e:
                    st.error(f"Hata: {e}")
            st.session_state[gen_key] = False
            st.rerun()
        st.info("10 soruluk mini sınav simülasyonu. Hazır olduğunuzda başlayın!")
        def _start_esim():
            st.session_state[gen_key] = True
        st.button("📝 Sınavı Başlat", key=f"{kp}esim_start", type="primary",
                  use_container_width=True, on_click=_start_esim)
    elif phase == "taking":
        data = st.session_state.get(qs_key, {})
        questions = data.get("questions", [])
        st.markdown(f'<div style="color:#92400e;font-weight:bold;text-align:center;font-size:1.1rem">'
                    f'{data.get("exam_title","Sınav")}</div>', unsafe_allow_html=True)
        for i, q in enumerate(questions):
            st.markdown(f"**{i+1}.** {q.get('q','')}")
            ans = st.radio("Cevap:", [f"{chr(65+j)}) {o}" for j, o in enumerate(q.get("options", []))],
                           key=f"{kp}esim_q{i}", index=None)
            if ans:
                st.session_state[ans_key][i] = ord(ans[0]) - 65
        def _submit_esim():
            st.session_state[phase_key] = "result"
        st.button("✅ Sınavı Bitir", key=f"{kp}esim_submit", type="primary",
                  use_container_width=True, on_click=_submit_esim)
    elif phase == "result":
        data = st.session_state.get(qs_key, {})
        questions = data.get("questions", [])
        answers = st.session_state.get(ans_key, {})
        score = 0
        total = len(questions) * 10
        for i, q in enumerate(questions):
            correct = q.get("answer", 0)
            given = answers.get(i, -1)
            is_right = given == correct
            if is_right:
                score += q.get("points", 10)
            icon = "✅" if is_right else "❌"
            st.markdown(f"{icon} **{i+1}.** {q.get('q','')} → **{chr(65+correct)}**")
        pct = round(score / total * 100) if total else 0
        color = "#22c55e" if pct >= 70 else "#f59e0b" if pct >= 50 else "#ef4444"
        st.markdown(f'<div style="text-align:center;background:#f0f9ff;border:2px solid {color}40;'
                    f'border-radius:16px;padding:20px;margin:12px 0">'
                    f'<div style="color:{color};font-size:2.5rem;font-weight:bold">{score}/{total}</div>'
                    f'<div style="color:#475569">Başarı: %{pct}</div></div>', unsafe_allow_html=True)
        def _reset_esim():
            for k in [phase_key, qs_key, ans_key]:
                st.session_state.pop(k, None)
        st.button("🔄 Yeni Sınav", key=f"{kp}esim_reset", on_click=_reset_esim)


# ── C12: Hata Düzeltme Oyunu ──
def render_error_fix_game(topic: str, kp: str = "_prem_"):
    """Hatalı cümleleri düzelt oyunu."""
    st.markdown('<div style="background:linear-gradient(135deg,#fffbeb,#fef3c7);border:2px solid rgba(239,68,68,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#f87171;margin:0">🔧 Hata Düzeltme</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}errfix_gen"
    result_key = f"{kp}errfix_result"
    check_key = f"{kp}errfix_check"
    if st.session_state.get(gen_key):
        with st.spinner("Hatalı cümleler hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "6 hatali cumle olustur. JSON: {\"sentences\":["
                                                      "{\"wrong\":\"hatali cumle\",\"correct\":\"dogru hali\","
                                                      "\"error_type\":\"hata turu\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=500, temperature=0.6,
                    response_format={"type": "json_object"})
                st.session_state[result_key] = json.loads(resp.choices[0].message.content)
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    data = st.session_state.get(result_key)
    if data:
        sentences = data.get("sentences", [])
        checked = st.session_state.get(check_key, False)
        st.info("Aşağıdaki cümlelerdeki hataları bulup doğrusunu yazın!")
        score = 0
        for i, s in enumerate(sentences):
            st.markdown(f'<div style="background:#e2e8f0;border:1px solid rgba(239,68,68,0.3);border-radius:8px;'
                        f'padding:10px;margin:6px 0;color:#f87171;font-size:.9rem">'
                        f'❌ {s.get("wrong","")}</div>', unsafe_allow_html=True)
            user_fix = st.text_input(f"Doğrusu:", key=f"{kp}errfix_a{i}",
                                     placeholder="Düzeltilmiş cümleyi yazın...")
            if checked:
                correct = s.get("correct", "")
                if user_fix.strip().lower() and (user_fix.strip().lower() in correct.lower()
                                                  or correct.lower() in user_fix.strip().lower()):
                    st.success(f"✅ Doğru! ({s.get('error_type','')})")
                    score += 1
                else:
                    st.error(f"❌ Doğrusu: {correct} ({s.get('error_type','')})")
        if not checked:
            def _check_err():
                st.session_state[check_key] = True
            st.button("✅ Kontrol Et", key=f"{kp}errfix_chk", type="primary", on_click=_check_err)
        else:
            st.markdown(f"**Sonuç: {score}/{len(sentences)}**")
        def _new_err():
            st.session_state.pop(result_key, None)
            st.session_state.pop(check_key, None)
        st.button("🔄 Yeni Sorular", key=f"{kp}errfix_new", on_click=_new_err)
    else:
        def _gen_err():
            st.session_state[gen_key] = True
        st.button("🔧 Başlat", key=f"{kp}errfix_btn", type="primary",
                  use_container_width=True, on_click=_gen_err)


