# ── G13: AI Akrostiş Şiir ──
def render_acrostic_poem(topic: str, kp: str = "_prem_"):
    """Konuyla ilgili akrostiş şiir üret."""
    st.markdown('<div style="background:linear-gradient(135deg,#f5f3ff,#fce7f3);border:2px solid rgba(168,85,247,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#c084fc;margin:0">📝 Akrostiş Şiir</h4></div>',
                unsafe_allow_html=True)
    keyword = st.text_input("Anahtar kelime:", value=topic.split()[0] if topic else "BİLGİ",
                            key=f"{kp}acro_word")
    gen_key = f"{kp}acro_gen"
    result_key = f"{kp}acro_result"
    if st.session_state.get(gen_key):
        with st.spinner("Şiir yazılıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": f"'{keyword}' kelimesiyle akrostis siir yaz. "
                                                      f"Her satir kelimenin bir harfiyle baslar. "
                                                      f"Konu: {topic}. Turkce, ogretici, eglenceli."},
                        {"role": "user", "content": f"Akrostis siir yaz: {keyword}"},
                    ], max_tokens=300, temperature=0.9)
                st.session_state[result_key] = resp.choices[0].message.content
            except Exception as e:
                st.session_state[result_key] = f"Hata: {e}"
        st.session_state[gen_key] = False
        st.rerun()
    if result_key in st.session_state:
        lines = st.session_state[result_key].strip().split("\n")
        poem_html = ""
        for line in lines:
            if line.strip():
                first = line.strip()[0] if line.strip() else ""
                rest = line.strip()[1:] if len(line.strip()) > 1 else ""
                poem_html += (f'<div style="margin:6px 0;font-size:1rem;line-height:1.8">'
                              f'<span style="color:#c084fc;font-size:1.4rem;font-weight:bold">{first}</span>'
                              f'<span style="color:#1e293b">{rest}</span></div>')
        st.markdown(f'<div style="background:#f0f9ff;border:1px solid rgba(168,85,247,0.3);border-radius:12px;'
                    f'padding:20px;text-align:center;font-family:Georgia,serif">{poem_html}</div>',
                    unsafe_allow_html=True)
        def _new_acro():
            st.session_state.pop(result_key, None)
        st.button("🔄 Yeni Şiir", key=f"{kp}acro_new", on_click=_new_acro)
    else:
        def _gen_acro():
            st.session_state[gen_key] = True
        st.button("📝 Şiir Yaz", key=f"{kp}acro_btn", type="primary",
                  use_container_width=True, on_click=_gen_acro)


# ── G14: Kavram Taboo Oyunu ──
def render_taboo_game(topic: str, kp: str = "_prem_"):
    """Yasak kelimeleri kullanmadan kavramı anlat."""
    st.markdown('<div style="background:linear-gradient(135deg,#2e0a0a,#1a0a2e);border:2px solid rgba(239,68,68,0.5);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#f87171;margin:0">🚫 Taboo Oyunu</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}taboo_gen"
    result_key = f"{kp}taboo_result"
    idx_key = f"{kp}taboo_idx"
    score_key = f"{kp}taboo_score"
    if st.session_state.get(gen_key):
        with st.spinner("Taboo kartları hazırlanıyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Taboo oyunu icin 8 kart olustur. JSON: "
                                                      "{\"cards\":[{\"word\":\"anlatilacak kelime\","
                                                      "\"taboo\":[\"yasak1\",\"yasak2\",\"yasak3\",\"yasak4\"]}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=400, temperature=0.7,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                st.session_state[result_key] = data.get("cards", [])
                st.session_state[idx_key] = 0
                st.session_state[score_key] = 0
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    cards = st.session_state.get(result_key, [])
    if not cards:
        def _gen_taboo():
            st.session_state[gen_key] = True
        st.button("🚫 Oyunu Başlat", key=f"{kp}taboo_btn", type="primary",
                  use_container_width=True, on_click=_gen_taboo)
        return
    idx = st.session_state.get(idx_key, 0)
    score = st.session_state.get(score_key, 0)
    if idx >= len(cards):
        st.markdown(f'<div style="text-align:center;background:#f0f9ff;border:2px solid rgba(34,197,94,0.4);'
                    f'border-radius:16px;padding:24px">'
                    f'<div style="font-size:3rem">🎉</div>'
                    f'<div style="color:#4ade80;font-size:1.3rem;font-weight:bold">Oyun Bitti!</div>'
                    f'<div style="color:#1e293b;margin-top:8px">Skor: {score}/{len(cards)}</div></div>',
                    unsafe_allow_html=True)
        def _reset_taboo():
            for k in [result_key, idx_key, score_key]:
                st.session_state.pop(k, None)
        st.button("🔄 Yeni Oyun", key=f"{kp}taboo_reset", on_click=_reset_taboo)
        return
    card = cards[idx]
    st.markdown(f'<div style="background:linear-gradient(135deg,#fef2f2,#fee2e2);border:3px solid #ef4444;'
                f'border-radius:16px;padding:24px;text-align:center;max-width:300px;margin:0 auto">'
                f'<div style="color:#15803d;font-size:1.5rem;font-weight:bold;margin-bottom:16px">'
                f'{card.get("word","")}</div>'
                f'<div style="border-top:2px solid #ef4444;padding-top:12px">'
                + "".join(f'<div style="color:#f87171;font-size:.9rem;margin:4px 0">🚫 {t}</div>'
                          for t in card.get("taboo", []))
                + '</div></div>', unsafe_allow_html=True)
    st.caption(f"Kart {idx+1}/{len(cards)}  •  Skor: {score}")
    c1, c2 = st.columns(2)
    def _taboo_pass():
        st.session_state[idx_key] = st.session_state.get(idx_key, 0) + 1
    def _taboo_correct():
        st.session_state[score_key] = st.session_state.get(score_key, 0) + 1
        st.session_state[idx_key] = st.session_state.get(idx_key, 0) + 1
    c1.button("✅ Bildim!", key=f"{kp}taboo_ok_{idx}", on_click=_taboo_correct, type="primary",
              use_container_width=True)
    c2.button("⏭️ Pas", key=f"{kp}taboo_skip_{idx}", on_click=_taboo_pass,
              use_container_width=True)


