# ── G17: Kavram Labirenti ──
def render_concept_maze(topic: str, kp: str = "_prem_"):
    """Kavramları doğru sırayla takip ederek labirentten çık."""
    st.markdown('<div style="background:linear-gradient(135deg,#fffbeb,#fef3c7);border:2px solid rgba(251,146,60,0.4);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#fb923c;margin:0">🔀 Kavram Labirenti</h4></div>',
                unsafe_allow_html=True)
    gen_key = f"{kp}maze_gen"
    result_key = f"{kp}maze_result"
    pos_key = f"{kp}maze_pos"
    if st.session_state.get(gen_key):
        with st.spinner("Labirent oluşturuluyor..."):
            try:
                client = _get_client()
                resp = client.chat.completions.create(
                    model="gpt-4o-mini",
                    messages=[
                        {"role": "system", "content": "Kavram labirenti icin 8 kavram olustur. "
                                                      "Her birinde bir soru ve 2 yol secenegi (dogru/yanlis). "
                                                      "JSON: {\"maze\":[{\"question\":\"soru\","
                                                      "\"correct\":\"dogru yol\",\"wrong\":\"yanlis yol\","
                                                      "\"concept\":\"kavram\"}]}"},
                        {"role": "user", "content": f"Konu: {topic}"},
                    ], max_tokens=600, temperature=0.6,
                    response_format={"type": "json_object"})
                data = json.loads(resp.choices[0].message.content)
                st.session_state[result_key] = data.get("maze", [])
                st.session_state[pos_key] = 0
            except Exception as e:
                st.error(f"Hata: {e}")
        st.session_state[gen_key] = False
        st.rerun()
    maze = st.session_state.get(result_key, [])
    if not maze:
        def _gen_maze():
            st.session_state[gen_key] = True
        st.button("🔀 Labirente Gir", key=f"{kp}maze_btn", type="primary",
                  use_container_width=True, on_click=_gen_maze)
        return
    pos = st.session_state.get(pos_key, 0)
    # Progress
    st.progress(pos / len(maze))
    if pos >= len(maze):
        st.markdown(f'<div style="text-align:center;background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
                    f'border:2px solid rgba(34,197,94,0.5);border-radius:16px;padding:24px">'
                    f'<div style="font-size:3rem">🏆</div>'
                    f'<div style="color:#4ade80;font-size:1.3rem;font-weight:bold">Labirentten Çıktınız!</div>'
                    f'<div style="color:#475569;margin-top:8px">Tüm kavramları doğru geçtiniz!</div></div>',
                    unsafe_allow_html=True)
        def _reset_maze():
            for k in [result_key, pos_key]:
                st.session_state.pop(k, None)
        st.button("🔄 Yeni Labirent", key=f"{kp}maze_reset", on_click=_reset_maze)
        return
    node = maze[pos]
    st.markdown(f'<div style="background:#f0f9ff;border:2px solid #fb923c40;border-radius:12px;'
                f'padding:16px;text-align:center">'
                f'<div style="color:#fb923c;font-size:.8rem">Kavşak {pos+1}/{len(maze)}</div>'
                f'<div style="color:#1e293b;font-size:1rem;font-weight:bold;margin:8px 0">'
                f'{node.get("question","")}</div></div>', unsafe_allow_html=True)
    import random
    options = [("correct", node.get("correct", "")), ("wrong", node.get("wrong", ""))]
    random.seed(hash(node.get("question", "")) + pos)
    random.shuffle(options)
    c1, c2 = st.columns(2)
    for i, (otype, text) in enumerate(options):
        def _choose(t=otype):
            if t == "correct":
                st.session_state[pos_key] = st.session_state.get(pos_key, 0) + 1
            else:
                st.session_state[pos_key] = max(0, st.session_state.get(pos_key, 0) - 1)
        col = c1 if i == 0 else c2
        col.button(f"{'🔵' if i==0 else '🔴'} {text}", key=f"{kp}maze_c{pos}_{i}",
                   on_click=_choose, use_container_width=True)


# ── G18: AI Çalışma Asistanı (Focus Mode) ──
def render_focus_mode(topic: str, kp: str = "_prem_"):
    """Odaklanma modu — zamanlayıcı + hedef + motivasyon."""
    st.markdown('<div style="background:linear-gradient(135deg,#0a2e0a,#0B0F19);border:2px solid rgba(34,197,94,0.5);'
                'border-radius:16px;padding:20px;margin:10px 0">'
                '<h4 style="color:#4ade80;margin:0">🎯 Focus Mode</h4></div>',
                unsafe_allow_html=True)
    phase_key = f"{kp}focus_phase"
    goal_key = f"{kp}focus_goal"
    dur_key = f"{kp}focus_dur"
    start_key = f"{kp}focus_start"
    phase = st.session_state.get(phase_key, "setup")
    if phase == "setup":
        goal = st.text_input("Çalışma hedefin:", key=goal_key,
                             placeholder="Örn: Bu konunun formüllerini öğrenmek")
        dur = st.select_slider("Süre (dakika):", options=[5, 10, 15, 20, 25, 30, 45, 60],
                               value=25, key=dur_key)
        def _start_focus():
            st.session_state[start_key] = time.time()
            st.session_state[phase_key] = "active"
        st.button("🎯 Odaklanmaya Başla!", key=f"{kp}focus_start_btn", type="primary",
                  use_container_width=True, on_click=_start_focus)
        # Motivasyon
        import random
        quotes = [
            "Başarı, hazırlık fırsatla buluştuğunda ortaya çıkar.",
            "Her uzman bir zamanlar acemiydi.",
            "Küçük adımlar büyük yolculukları başlatır.",
            "Bugünkü çaban, yarının başarısıdır.",
            "Öğrenmekten asla vazgeçme!",
        ]
        st.markdown(f'<div style="text-align:center;color:#475569;font-style:italic;margin-top:12px;font-size:.85rem">'
                    f'💭 "{random.choice(quotes)}"</div>', unsafe_allow_html=True)
    elif phase == "active":
        dur = st.session_state.get(dur_key, 25)
        elapsed = time.time() - st.session_state.get(start_key, time.time())
        remaining = max(0, dur * 60 - elapsed)
        mins = int(remaining // 60)
        secs = int(remaining % 60)
        pct = (1 - remaining / (dur * 60)) * 100
        color = "#22c55e" if remaining > dur * 20 else "#f59e0b" if remaining > dur * 5 else "#ef4444"
        st.markdown(f'<div style="text-align:center;background:#f0f9ff;border:2px solid {color}40;'
                    f'border-radius:16px;padding:24px">'
                    f'<div style="color:{color};font-size:3rem;font-weight:bold;font-family:monospace">'
                    f'{mins:02d}:{secs:02d}</div>'
                    f'<div style="background:#e2e8f0;border-radius:8px;height:8px;margin:16px 0">'
                    f'<div style="background:{color};width:{pct}%;height:100%;border-radius:8px;'
                    f'transition:width 1s"></div></div>'
                    f'<div style="color:#475569;font-size:.85rem">🎯 {st.session_state.get(goal_key,"")}</div></div>',
                    unsafe_allow_html=True)
        if remaining <= 0:
            st.session_state[phase_key] = "done"
            st.rerun()
        def _stop_focus():
            st.session_state[phase_key] = "done"
        st.button("⏹️ Bitir", key=f"{kp}focus_stop", on_click=_stop_focus)
    elif phase == "done":
        dur = st.session_state.get(dur_key, 25)
        elapsed = time.time() - st.session_state.get(start_key, time.time())
        actual = min(elapsed / 60, dur)
        st.markdown(f'<div style="text-align:center;background:linear-gradient(135deg,#f0f9ff,#e0f2fe);'
                    f'border:2px solid rgba(34,197,94,0.5);border-radius:16px;padding:24px">'
                    f'<div style="font-size:3rem">🎉</div>'
                    f'<div style="color:#4ade80;font-size:1.2rem;font-weight:bold">Odaklanma Tamamlandı!</div>'
                    f'<div style="color:#1e293b;margin-top:8px">{int(actual)} dakika çalıştınız</div>'
                    f'<div style="color:#475569;font-size:.85rem;margin-top:4px">'
                    f'🎯 {st.session_state.get(goal_key,"")}</div></div>', unsafe_allow_html=True)
        def _reset_focus():
            for k in [phase_key, start_key]:
                st.session_state.pop(k, None)
        st.button("🔄 Yeni Oturum", key=f"{kp}focus_reset", on_click=_reset_focus)


