# ════════════════════════════════════════════════════════════
# LEARNING STYLE DETECTION
# ════════════════════════════════════════════════════════════
def detect_learning_style(ders: str) -> dict:
    """Ogrencinin ogrenme stilini davranis verisinden tespit et."""
    prog = load_progress()
    gd = prog.get(ders, {})
    topics = gd.get("topics", {})
    style_data = gd.get("_learning_style", {})

    # Aggregate behavior indicators
    visual_score = style_data.get("visual_interactions", 0)
    audio_score = style_data.get("audio_completions", 0)
    practice_score = style_data.get("quiz_attempts", 0)
    reading_score = style_data.get("flashcard_views", 0)

    total = max(visual_score + audio_score + practice_score + reading_score, 1)

    styles = {
        "visual": {"name": "Gorsel", "icon": "\U0001F441", "pct": visual_score / total * 100,
                   "tip": "Gorseller ve diyagramlarla daha iyi ogreniyorsun. Ders sirasinda gorsellere odaklan."},
        "auditory": {"name": "Isitsel", "icon": "\U0001F442", "pct": audio_score / total * 100,
                     "tip": "Dinleyerek ogreniyorsun. TTS ogretmen anlatimini dinlemeye devam et."},
        "kinesthetic": {"name": "Uygulayici", "icon": "\u270D\uFE0F", "pct": practice_score / total * 100,
                        "tip": "Yaparak ogreniyorsun. Quiz ve alistirmalara agirlik ver."},
        "reading": {"name": "Okuyucu", "icon": "\U0001F4D6", "pct": reading_score / total * 100,
                    "tip": "Okuyarak ogreniyorsun. Kavram kartlari ve ozetleri kullan."},
    }

    dominant = max(styles.items(), key=lambda x: x[1]["pct"])
    return {"styles": styles, "dominant": dominant[0], "dominant_data": dominant[1]}


def update_learning_style(ders: str, action: str):
    """Ogrenme stili verisini guncelle."""
    prog = load_progress()
    if ders not in prog:
        return
    gd = prog[ders]
    if "_learning_style" not in gd:
        gd["_learning_style"] = {"visual_interactions": 0, "audio_completions": 0,
                                  "quiz_attempts": 0, "flashcard_views": 0}
    ls = gd["_learning_style"]
    action_map = {
        "visual_view": "visual_interactions",
        "audio_complete": "audio_completions",
        "quiz_attempt": "quiz_attempts",
        "flashcard_view": "flashcard_views",
    }
    field = action_map.get(action)
    if field:
        ls[field] = ls.get(field, 0) + 1
    with open(_progress_path(), "w", encoding="utf-8") as f:
        json.dump(prog, f, ensure_ascii=False, indent=2)


def render_learning_style(ders: str):
    """Ogrenme stili analizi goster."""
    style_info = detect_learning_style(ders)
    styles = style_info["styles"]
    dominant = style_info["dominant_data"]

    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F9E0 Ogrenme Stilin</span></div>',
        unsafe_allow_html=True,
    )

    # Style bars
    html_out = '<div style="padding:8px">'
    for key, s in styles.items():
        bar_color = "#6366F1" if key == style_info["dominant"] else "#475569"
        html_out += (
            f'<div style="margin:6px 0">'
            f'<div style="display:flex;justify-content:space-between;color:#1e293b;font-size:.8rem;margin-bottom:2px">'
            f'<span>{s["icon"]} {s["name"]}</span><span>{s["pct"]:.0f}%</span></div>'
            f'<div style="background:#e2e8f0;border-radius:4px;height:6px;overflow:hidden">'
            f'<div style="background:{bar_color};height:100%;width:{max(s["pct"],2):.0f}%;border-radius:4px"></div>'
            f'</div></div>'
        )

    # Dominant style recommendation
    html_out += (
        f'<div style="background:rgba(212,175,55,0.08);border:1px solid #bae6fd;'
        f'border-radius:8px;padding:10px;margin-top:10px">'
        f'<div style="color:#0c4a6e;font-weight:700;font-size:.85rem">'
        f'{dominant["icon"]} Baskin Stil: {dominant["name"]}</div>'
        f'<div style="color:#1e293b;font-size:.8rem;margin-top:4px">{dominant["tip"]}</div></div>'
    )
    html_out += '</div>'
    st.markdown(html_out, unsafe_allow_html=True)


# ════════════════════════════════════════════════════════════
# CONCEPT MAP BUILDER
# ════════════════════════════════════════════════════════════
def render_concept_map(ders: str, lesson_data: dict):
    """Kavram haritasi olusturucu — dersten otomatik kavram grafi."""
    import streamlit.components.v1 as components

    sections = lesson_data.get("sections", [])
    vocab = lesson_data.get("vocabulary", [])
    title = lesson_data.get("title", "Ders")

    # Extract concepts from sections
    concepts = []
    for v in vocab[:8]:
        concepts.append({"id": v.get("term", ""), "label": v.get("term", ""),
                        "def": v.get("definition", "")})

    if not concepts:
        # Fallback: extract from headers
        for s in sections:
            if s.get("type") == "header" and s.get("text"):
                concepts.append({"id": s["text"][:30], "label": s["text"][:30], "def": ""})

    if len(concepts) < 2:
        st.info("Kavram haritasi icin yeterli kavram bulunamadi.")
        return

    st.markdown(
        '<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);'
        'border:1px solid #93c5fd;border-radius:12px;padding:12px 16px;margin-bottom:12px">'
        '<span style="color:#0c4a6e;font-weight:800;font-size:1.1rem">'
        '\U0001F5FA Kavram Haritasi</span></div>',
        unsafe_allow_html=True,
    )

    nodes_js = json.dumps(concepts, ensure_ascii=False)
    title_short = title[:20]
    map_html = f"""
    <canvas id="cmcv" width="600" height="350" style="width:100%;background:#f0f9ff;border-radius:10px;
      border:1px solid #bae6fd"></canvas>
    <script>
    var cv=document.getElementById('cmcv');var c=cv.getContext('2d');var W=cv.width,H=cv.height;
    var nodes={nodes_js};var cx=W/2,cy=H/2;
    // Central topic
    c.fillStyle='#6366F1';c.beginPath();c.arc(cx,cy,30,0,Math.PI*2);c.fill();
    c.fillStyle='#0B0F19';c.font='bold 10px system-ui';c.textAlign='center';
    c.fillText('{title_short}',cx,cy+4);
    // Concept nodes
    var colors=['#3b82f6','#22c55e','#a855f7','#ef4444','#f59e0b','#06b6d4','#ec4899','#84cc16'];
    for(var i=0;i<nodes.length;i++){{
      var angle=(i/nodes.length)*Math.PI*2-Math.PI/2;
      var r=120+Math.random()*30;
      var nx=cx+Math.cos(angle)*r;var ny=cy+Math.sin(angle)*r;
      // Connection line
      c.strokeStyle=colors[i%colors.length]+'66';c.lineWidth=2;
      c.beginPath();c.moveTo(cx,cy);c.lineTo(nx,ny);c.stroke();
      // Node
      c.fillStyle=colors[i%colors.length]+'33';c.beginPath();c.arc(nx,ny,22,0,Math.PI*2);c.fill();
      c.strokeStyle=colors[i%colors.length];c.lineWidth=1.5;c.beginPath();c.arc(nx,ny,22,0,Math.PI*2);c.stroke();
      c.fillStyle='#e2e8f0';c.font='9px system-ui';
      var label=nodes[i].label||'';
      if(label.length>12)label=label.substring(0,12)+'..';
      c.fillText(label,nx,ny+4);
    }}
    </script>
    """
    components.html(map_html, height=370)


# ════════════════════════════════════════════════════════════
# IRT CONNECTION FOR ADAPTIVE DIFFICULTY
# ════════════════════════════════════════════════════════════
def get_irt_difficulty_recommendation(ders: str, student_id: str = "") -> str:
    """IRT modeline gore zorluk onerisi."""
    prog = load_progress()
    gd = prog.get(ders, {})
    topics = gd.get("topics", {})
    if len(topics) < 3:
        return "normal"

    scores = [t.get("quiz_score", 50) for t in topics.values()]
    avg = sum(scores) / len(scores)
    recent = sorted(topics.values(), key=lambda x: x.get("date", ""), reverse=True)[:5]
    recent_avg = sum(t.get("quiz_score", 50) for t in recent) / len(recent)
    trend = recent_avg - avg

    # Simple ability estimation (theta approximation)
    theta = (recent_avg - 50) / 25  # Normalize to roughly -2 to +2

    if theta > 1.0 or (recent_avg >= 85 and trend >= 0):
        return "hard"
    elif theta < -0.5 or (recent_avg < 45 and trend <= 0):
        return "easy"
    return "normal"


