# 106. AI ÖĞRENCİ PERFORMANS RAPORU (Kurumsal)
# ════════════════════════════════════════════════════════════
def render_student_performance_report(topic: str, kp: str = "_prem_"):
    """Tüm modül verilerini toplayan kurumsal AI öğrenci performans raporu."""
    import streamlit.components.v1 as components

    # ── Başlık ──
    st.markdown(
        '<div style="background:linear-gradient(135deg,#0c1220,#1a1040);'
        'border:2px solid rgba(212,175,55,0.6);border-radius:16px;padding:24px;margin:10px 0;'
        'box-shadow:0 8px 32px rgba(0,0,0,0.4)">'
        '<div style="display:flex;align-items:center;gap:14px">'
        '<span style="font-size:2.2rem">📊</span>'
        '<div><h3 style="color:#6366F1;margin:0;letter-spacing:1px">AI Öğrenci Performans Raporu</h3>'
        '<p style="color:#94a3b8;margin:0;font-size:.85rem">Kapsamlı analiz &bull; Tüm modül verileri &bull; AI değerlendirme</p>'
        '</div></div></div>', unsafe_allow_html=True)

    # ── Veri toplama ──
    progress = load_progress()
    all_lessons = load_saved_lessons()
    mistakes = _load_mistakes()
    sr_data = _load_sr()
    daily_data = _load_daily()
    bookmarks = _load_bookmarks()
    notes = _load_notes()

    # Ders adını topic'ten çıkar
    ders_name = topic.split("—")[0].strip() if "—" in topic else topic.strip()
    # Emoji temizle
    import re as _re
    ders_clean = _re.sub(r'^[\U0001F000-\U0001FFFF\u2600-\u27FF\uFE00-\uFE0F\u200D]+\s*', '', ders_name).strip()

    # Ders verisini bul (esnek eşleştirme)
    ders_data = {}
    matched_key = ""
    for k, v in progress.items():
        k_clean = _re.sub(r'^[\U0001F000-\U0001FFFF\u2600-\u27FF\uFE00-\uFE0F\u200D]+\s*', '', k).strip()
        if k_clean.lower() == ders_clean.lower() or ders_clean.lower() in k_clean.lower() or k_clean.lower() in ders_clean.lower():
            ders_data = v
            matched_key = k
            break

    topics_data = ders_data.get("topics", {})
    total_lessons = ders_data.get("total_lessons", 0)
    total_xp = ders_data.get("total_xp", 0)
    streak = ders_data.get("streak", 0)
    best_streak = ders_data.get("best_streak", 0)
    level = total_xp // 200 + 1

    # Quiz skorları
    scores = [t.get("quiz_score", 0) for t in topics_data.values()]
    avg_score = sum(scores) / len(scores) if scores else 0
    max_score = max(scores) if scores else 0
    min_score = min(scores) if scores else 0

    # Lig
    league = {"name": "Bronz Lig", "icon": "🥉", "color": "#cd7f32"}
    for lg in LEAGUE_DEFS:
        if total_xp >= lg["min_xp"]:
            league = lg

    # Rozetler
    badges = get_earned_badges(matched_key) if matched_key else []

    # Konu bazlı hatalar
    ders_mistakes = [m for m in mistakes if ders_clean.lower() in m.get("ders", "").lower()]
    reviewed_mistakes = [m for m in ders_mistakes if m.get("reviewed")]

    # Akıllı tekrar
    all_cards = sr_data.get("cards", [])
    ders_cards = [c for c in all_cards if ders_clean.lower() in c.get("ders", "").lower()]
    mastered_cards = [c for c in ders_cards if c.get("interval", 0) >= 21]
    today_str = datetime.now().strftime("%Y-%m-%d")
    due_cards = [c for c in ders_cards if c.get("next_review", "9999") <= today_str]

    # Günlük meydan okuma
    daily_challenges = daily_data.get("challenges", [])
    daily_streak = daily_data.get("streak", 0)

    # Son 7 gün aktivite
    last_7_days = {}
    for t_name, t_data in topics_data.items():
        d = t_data.get("date", "")
        if d:
            last_7_days[d] = last_7_days.get(d, 0) + 1

    # Skor dağılımı
    score_ranges = {"0-39": 0, "40-59": 0, "60-79": 0, "80-100": 0}
    for s in scores:
        if s < 40:
            score_ranges["0-39"] += 1
        elif s < 60:
            score_ranges["40-59"] += 1
        elif s < 80:
            score_ranges["60-79"] += 1
        else:
            score_ranges["80-100"] += 1

    # Güçlü / Zayıf konular
    strong_topics = sorted(topics_data.items(), key=lambda x: x[1].get("quiz_score", 0), reverse=True)[:5]
    weak_topics = sorted(topics_data.items(), key=lambda x: x[1].get("quiz_score", 0))[:5]

